ext-white hover:bg-white/20 hover:text-white\\"\\n                  : \\"bg-purple-100 border-purple-300 text-purple-700 hover:bg-purple-200 hover:text-purple-800\\"\\n              }`}\\n            >\\n              <Minus className=\\"h-5 w-5\\" />\\n              Decrement\\n            </Button>\\n\\n            <Button\\n              variant=\\"default\\"\\n              size=\\"lg\\"\\n              onClick={increment}\\n              className=\\"bg-purple-600 hover:bg-purple-700 text-white\\"\\n            >\\n              <Plus className=\\"h-5 w-5\\" />\\n              Increment\\n            </Button>\\n          </div>\\n\\n          {/* Reset Button */}\\n          <Button\\n            variant=\\"ghost\\"\\n            size=\\"sm\\"\\n            onClick={reset}\\n            className={`transition-all duration-300 ${\\n              isDark\\n                ? \\"text-white/70 hover:text-white hover:bg-white/10\\"\\n                : \\"text-slate-600 hover:text-slate-800 hover:bg-purple-100\\"\\n            }`}\\n          >\\n            <RotateCcw className=\\"h-4 w-4\\" />\\n            Reset\\n          </Button>\\n        </div>\\n\\n        {/* Stats */}\\n        <div\\n          className={`mt-8 pt-6 border-t transition-colors duration-300 ${\\n            isDark ? \\"border-white/20\\" : \\"border-purple-200/50\\"\\n          }`}\\n        >\\n          <div\\n            className={`flex justify-center gap-8 text-sm transition-colors duration-300 ${\\n              isDark ? \\"text-white/60\\" : \\"text-slate-500\\"\\n            }`}\\n          >\\n            <div className=\\"text-center\\">\\n              <div\\n                className={`font-semibold ${\\n                  isDark ? \\"text-white\\" : \\"text-slate-800\\"\\n                }`}\\n              >\\n                {count > 0 ? count : 0}\\n              </div>\\n              <div>Positive</div>\\n            </div>\\n            <div className=\\"text-center\\">\\n 