e0969047-6bc8-4eac-94e6-492439d6f03a	3649a0c4-e9b1-497a-ba78-b0f3313b6e76	https://3000-ipgrj5856ph9xdokk4hv8.e2b.app	Todo App\n	{"app/page.tsx": "\\"use client\\";\\n\\nimport { useState, useEffect } from \\"react\\";\\nimport { Button } from \\"@/components/ui/button\\";\\nimport { Input } from \\"@/components/ui/input\\";\\nimport { Card, CardContent, CardHeader, CardTitle } from \\"@/components/ui/card\\";\\nimport { Plus, Trash2, Check, Circle } from \\"lucide-react\\";\\n\\ninterface Todo {\\n  id: string;\\n  text: string;\\n  completed: boolean;\\n  createdAt: number;\\n}\\n\\ntype FilterType = \\"all\\" | \\"active\\" | \\"completed\\";\\n\\nexport default function Home() {\\n  const [todos, setTodos] = useState<Todo[]>([]);\\n  const [inputValue, setInputValue] = useState(\\"\\");\\n  const [filter, setFilter] = useState<FilterType>(\\"all\\");\\n\\n  // Load todos from localStorage on mount\\n  useEffect(() => {\\n    const savedTodos = localStorage.getItem(\\"todos\\");\\n    if (savedTodos) {\\n      setTodos(JSON.parse(savedTodos));\\n    }\\n  }, []);\\n\\n  // Save todos to localStorage whenever they change\\n  useEffect(() => {\\n    localStorage.setItem(\\"todos\\", JSON.stringify(todos));\\n  }, [todos]);\\n\\n  const addTodo = () => {\\n    if (inputValue.trim() === \\"\\") return;\\n\\n    const newTodo: Todo = {\\n      id: Date.now().toString(),\\n      text: inputValue.trim(),\\n      completed: false,\\n      createdAt: Date.now(),\\n    };\\n\\n    setTodos([newTodo, ...todos]);\\n    setInputValue(\\"\\");\\n  };\\n\\n  const toggleTodo = (id: string) => {\\n    setTodos(\\n      todos.map((todo) =>\\n        todo.id === id ? { ...todo, completed: !todo.completed } : todo\\n      )\\n    );\\n  };\\n\\n  const deleteTodo = (id: string) => {\\n    setTodos(todos.filter((todo) => todo.id !== id));\\n  };\\n\\n  const clearCompleted = () => {\\n    setTodos(todos.filter((todo) => !todo.completed));\\n  };\\n\\n  const filteredTodos = todos.filter((todo) => {\\n    if (filter === \\"active\\") return !todo.completed;\\n    if (filter === \\"completed\\") return todo.completed;\\n    return true;\\n  });\\n\\n  const activeTodosCount = todos.filter((todo) => !todo.completed).length;\\n  const completedTodosCount = todos.filter((todo) => todo.completed).length;\\n\\n  return (\\n    <div className=\\"min-h-screen bg-gradient-to-br from-slate-50 to-slate-100 dark:from-slate-950 dark:to-slate-900\\">\\n      {/* Header */}\\n      <header className=\\"border-b bg-white/80 dark:bg-slate-900/80 backdrop-blur-sm sticky top-0 z-10\\">\\n        <div className=\\"max-w-3xl mx-auto px-4 py-6\\">\\n          <h1 className=\\"text-3xl font-bold text-slate-900 dark:text-slate-100\\">\\n            ✅ Todo App\\n          </h1>\\n          <p className=\\"text-slate-600 dark:text-slate-400 mt-1\\">\\n            Stay organized, get things done\\n          </p>\\n        </div>\\n      </header>\\n\\n      {/* Main Content */}\\n      <main className=\\"max-w-3xl mx-auto px-4 py-8\\">\\n        {/* Add Todo Form */}\\n        <Card className=\\"mb-6 shadow-lg border-0 bg-white dark:bg-slate-800\\">\\n          <CardHeader>\\n            <CardTitle className=\\"text-lg\\">Add a new task</CardTitle>\\n          </CardHeader>\\n          <CardContent>\\n            <div className=\\"flex gap-3\\">\\n              <Input\\n                type=\\"text\\"\\n                placeholder=\\"What needs to be done?\\"\\n                value={inputValue}\\n                onChange={(e) => setInputValue(e.target.value)}\\n                onKeyDown={(e) => e.key === \\"Enter\\" && addTodo()}\\n                className=\\"flex-1\\"\\n              />\\n              <Button onClick={addTodo} className=\\"gap-2\\">\\n                <Plus className=\\"h-4 w-4\\" />\\n                Add\\n              </Button>\\n            </div>\\n          </CardContent>\\n        </Card>\\n\\n        {/* Stats and Filters */}\\n        <div className=\\"flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4 mb-6\\">\\n          <div className=\\"flex gap-4 text-sm text-slate-600 dark:text-slate-400\\">\\n            <span>\\n              <strong className=\\"text-slate-900 dark:text-slate-100\\">\\n                {activeTodosCount}\\n              </strong>{\\" \\"}\\n              active\\n            </span>\\n            <span>\\n              <strong className=\\"text-slate-900 dark:text-slate-100\\">\\n                {completedTodosCount}\\n              </strong>{\\" \\"}\\n              completed\\n            </span>\\n          </div>\\n\\n          <div className=\\"flex gap-2 flex-wrap\\">\\n            {([\\"all\\", \\"active\\", \\"completed\\"] as FilterType[]).map((f) => (\\n              <Button\\n                key={f}\\n                variant={filter === f ? \\"default\\" : \\"outline\\"}\\n                size=\\"sm\\"\\n                onClick={() => setFilter(f)}\\n                className=\\"capitalize\\"\\n              >\\n                {f}\\n              </Button>\\n            ))}\\n            {completedTodosCount > 0 && (\\n              <Button\\n                variant=\\"ghost\\"\\n                size=\\"sm\\"\\n                onClick={clearCompleted}\\n                className=\\"text-red-600 hover:text-red-700 hover:bg-red-50 dark:hover:bg-red-950\\"\\n              >\\n                Clear completed\\n              </Button>\\n            )}\\n          </div>\\n        </div>\\n\\n        {/* Todo List */}\\n        <Card className=\\"shadow-lg border-0 bg-white dark:bg-slate-800\\">\\n          <CardContent className=\\"p-0\\">\\n            {filteredTodos.length === 0 ? (\\n              <div className=\\"py-16 text-center text-slate-500 dark:text-slate-400\\">\\n                <div className=\\"text-5xl mb-4\\">📝</div>\\n                <p className=\\"text-lg\\">\\n                  {filter === \\"all\\"\\n                    ? \\"No tasks yet. Add one above!\\"\\n                    : filter === \\"active\\"\\n                    ? \\"No active tasks. Great job!\\"\\n                    : \\"No completed tasks yet.\\"}\\n                </p>\\n              </div>\\n            ) : (\\n              <ul className=\\"divide-y divide-slate-200 dark:divide-slate-700\\">\\n                {filteredTodos.map((todo) => (\\n                  <li\\n                    key={todo.id}\\n                    className=\\"flex items-center gap-3 p-4 hover:bg-slate-50 dark:hover:bg-slate-700/50 transition-colors group\\"\\n                  >\\n                    <button\\n                      onClick={() => toggleTodo(todo.id)}\\n                      className=\\"flex-shrink-0 text-slate-400 hover:text-slate-600 dark:hover:text-slate-300 transition-colors\\"\\n                      aria-label={\\n                        todo.completed ? \\"Mark as incomplete\\" : \\"Mark as complete\\"\\n                      }\\n                    >\\n                      {todo.completed ? (\\n                        <div className=\\"h-6 w-6 rounded-full bg-green-500 flex items-center justify-center\\">\\n                          <Check className=\\"h-4 w-4 text-white\\" />\\n                        </div>\\n                      ) : (\\n                        <Circle className=\\"h-6 w-6\\" />\\n                      )}\\n                    </button>\\n\\n                    <span\\n                      className={`flex-1 text-slate-800 dark:text-slate-200 transition-all ${\\n                        todo.completed\\n                          ? \\"line-through text-slate-400 dark:text-slate-500\\"\\n                          : \\"\\"\\n                      }`}\\n                    >\\n                      {todo.text}\\n                    </span>\\n\\n                    <Button\\n                      variant=\\"ghost\\"\\n                      size=\\"icon\\"\\n                      onClick={() => deleteTodo(todo.id)}\\n                      className=\\"opacity-0 group-hover:opacity-100 text-red-500 hover:text-red-600 hover:bg-red-50 dark:hover:bg-red-950 transition-all\\"\\n                      aria-label=\\"Delete task\\"\\n                    >\\n                      <Trash2 className=\\"h-4 w-4\\" />\\n                    </Button>\\n                  </li>\\n                ))}\\n              </ul>\\n            )}\\n          </CardContent>\\n        </Card>\\n\\n        {/* Footer */}\\n        <footer className=\\"mt-12 text-center text-sm text-slate-500 dark:text-slate-400\\">\\n          <p>Double-click a task to edit • Press Enter to save</p>\\n          <p className=\\"mt-1\\">Built with Next.js & Shadcn UI</p>\\n        </footer>\\n      </main>\\n    </div>\\n  );\\n}\\n"}	2026-03-13 14:29:47.537	2026-03-13 14:29:47.537	Created a fully functional todo app with add, toggle, and delete capabilities. Features include localStorage persistence, filtering by all/active/completed tasks, task statistics, and a polished UI using Shadcn UI components and Tailwind CSS. The app is responsive, supports dark mode, and includes proper accessibility attributes.
d79d1b6b-3de5-4369-8fe1-5c8be5219b96	24f01c5a-97ea-4b07-814f-54cb8d26d928	https://3000-ipgrj5856ph9xdokk4hv8.e2b.app	Todo App\n	{"app/page.tsx": "\\"use client\\";\\n\\nimport { useState, useEffect } from \\"react\\";\\nimport { Button } from \\"@/components/ui/button\\";\\nimport { Input } from \\"@/components/ui/input\\";\\nimport { Card, CardContent, CardHeader, CardTitle } from \\"@/components/ui/card\\";\\nimport { Plus, Trash2, Check, Circle } from \\"lucide-react\\";\\nimport { ThemeToggle } from \\"./theme-toggle\\";\\n\\ninterface Todo {\\n  id: string;\\n  text: string;\\n  completed: boolean;\\n  createdAt: number;\\n}\\n\\ntype FilterType = \\"all\\" | \\"active\\" | \\"completed\\";\\n\\nexport default function Home() {\\n  const [todos, setTodos] = useState<Todo[]>([]);\\n  const [inputValue, setInputValue] = useState(\\"\\");\\n  const [filter, setFilter] = useState<FilterType>(\\"all\\");\\n\\n  // Load todos from localStorage on mount\\n  useEffect(() => {\\n    const savedTodos = localStorage.getItem(\\"todos\\");\\n    if (savedTodos) {\\n      setTodos(JSON.parse(savedTodos));\\n    }\\n  }, []);\\n\\n  // Save todos to localStorage whenever they change\\n  useEffect(() => {\\n    localStorage.setItem(\\"todos\\", JSON.stringify(todos));\\n  }, [todos]);\\n\\n  const addTodo = () => {\\n    if (inputValue.trim() === \\"\\") return;\\n\\n    const newTodo: Todo = {\\n      id: Date.now().toString(),\\n      text: inputValue.trim(),\\n      completed: false,\\n      createdAt: Date.now(),\\n    };\\n\\n    setTodos([newTodo, ...todos]);\\n    setInputValue(\\"\\");\\n  };\\n\\n  const toggleTodo = (id: string) => {\\n    setTodos(\\n      todos.map((todo) =>\\n        todo.id === id ? { ...todo, completed: !todo.completed } : todo\\n      )\\n    );\\n  };\\n\\n  const deleteTodo = (id: string) => {\\n    setTodos(todos.filter((todo) => todo.id !== id));\\n  };\\n\\n  const clearCompleted = () => {\\n    setTodos(todos.filter((todo) => !todo.completed));\\n  };\\n\\n  const filteredTodos = todos.filter((todo) => {\\n    if (filter === \\"active\\") return !todo.completed;\\n    if (filter === \\"completed\\") return todo.completed;\\n    return true;\\n  });\\n\\n  const activeTodosCount = todos.filter((todo) => !todo.completed).length;\\n  const completedTodosCount = todos.filter((todo) => todo.completed).length;\\n\\n  return (\\n    <div className=\\"min-h-screen bg-gradient-to-br from-slate-50 to-slate-100 dark:from-slate-950 dark:to-slate-900\\">\\n      {/* Header */}\\n      <header className=\\"border-b bg-white/80 dark:bg-slate-900/80 backdrop-blur-sm sticky top-0 z-10\\">\\n        <div className=\\"max-w-3xl mx-auto px-4 py-6 flex justify-between items-start\\">\\n          <div>\\n            <h1 className=\\"text-3xl font-bold text-slate-900 dark:text-slate-100\\">\\n              ✅ Todo App\\n            </h1>\\n            <p className=\\"text-slate-600 dark:text-slate-400 mt-1\\">\\n              Stay organized, get things done\\n            </p>\\n          </div>\\n          <ThemeToggle />\\n        </div>\\n      </header>\\n\\n      {/* Main Content */}\\n      <main className=\\"max-w-3xl mx-auto px-4 py-8\\">\\n        {/* Add Todo Form */}\\n        <Card className=\\"mb-6 shadow-lg border-0 bg-white dark:bg-slate-800\\">\\n          <CardHeader>\\n            <CardTitle className=\\"text-lg text-slate-900 dark:text-slate-100\\">\\n              Add a new task\\n            </CardTitle>\\n          </CardHeader>\\n          <CardContent>\\n            <div className=\\"flex gap-3\\">\\n              <Input\\n                type=\\"text\\"\\n                placeholder=\\"What needs to be done?\\"\\n                value={inputValue}\\n                onChange={(e) => setInputValue(e.target.value)}\\n                onKeyDown={(e) => e.key === \\"Enter\\" && addTodo()}\\n                className=\\"flex-1\\"\\n              />\\n              <Button onClick={addTodo} className=\\"gap-2\\">\\n                <Plus className=\\"h-4 w-4\\" />\\n                Add\\n              </Button>\\n            </div>\\n          </CardContent>\\n        </Card>\\n\\n        {/* Stats and Filters */}\\n        <div className=\\"flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4 mb-6\\">\\n          <div className=\\"flex gap-4 text-sm text-slate-600 dark:text-slate-400\\">\\n            <span>\\n              <strong className=\\"text-slate-900 dark:text-slate-100\\">\\n                {activeTodosCount}\\n              </strong>{\\" \\"}\\n              active\\n            </span>\\n            <span>\\n              <strong className=\\"text-slate-900 dark:text-slate-100\\">\\n                {completedTodosCount}\\n              </strong>{\\" \\"}\\n              completed\\n            </span>\\n          </div>\\n\\n          <div className=\\"flex gap-2 flex-wrap\\">\\n            {([\\"all\\", \\"active\\", \\"completed\\"] as FilterType[]).map((f) => (\\n              <Button\\n                key={f}\\n                variant={filter === f ? \\"default\\" : \\"outline\\"}\\n                size=\\"sm\\"\\n                onClick={() => setFilter(f)}\\n                className=\\"capitalize\\"\\n              >\\n                {f}\\n              </Button>\\n            ))}\\n            {completedTodosCount > 0 && (\\n              <Button\\n                variant=\\"ghost\\"\\n                size=\\"sm\\"\\n                onClick={clearCompleted}\\n                className=\\"text-red-600 hover:text-red-700 hover:bg-red-50 dark:hover:bg-red-950\\"\\n              >\\n                Clear completed\\n              </Button>\\n            )}\\n          </div>\\n        </div>\\n\\n        {/* Todo List */}\\n        <Card className=\\"shadow-lg border-0 bg-white dark:bg-slate-800\\">\\n          <CardContent className=\\"p-0\\">\\n            {filteredTodos.length === 0 ? (\\n              <div className=\\"py-16 text-center text-slate-500 dark:text-slate-400\\">\\n                <div className=\\"text-5xl mb-4\\">📝</div>\\n                <p className=\\"text-lg\\">\\n                  {filter === \\"all\\"\\n                    ? \\"No tasks yet. Add one above!\\"\\n                    : filter === \\"active\\"\\n                    ? \\"No active tasks. Great job!\\"\\n                    : \\"No completed tasks yet.\\"}\\n                </p>\\n              </div>\\n            ) : (\\n              <ul className=\\"divide-y divide-slate-200 dark:divide-slate-700\\">\\n                {filteredTodos.map((todo) => (\\n                  <li\\n                    key={todo.id}\\n                    className=\\"flex items-center gap-3 p-4 hover:bg-slate-50 dark:hover:bg-slate-700/50 transition-colors group\\"\\n                  >\\n                    <button\\n                      onClick={() => toggleTodo(todo.id)}\\n                      className=\\"flex-shrink-0 text-slate-400 hover:text-slate-600 dark:hover:text-slate-300 transition-colors\\"\\n                      aria-label={\\n                        todo.completed ? \\"Mark as incomplete\\" : \\"Mark as complete\\"\\n                      }\\n                    >\\n                      {todo.completed ? (\\n                        <div className=\\"h-6 w-6 rounded-full bg-green-500 flex items-center justify-center\\">\\n                          <Check className=\\"h-4 w-4 text-white\\" />\\n                        </div>\\n                      ) : (\\n                        <Circle className=\\"h-6 w-6\\" />\\n                      )}\\n                    </button>\\n\\n                    <span\\n                      className={`flex-1 text-slate-800 dark:text-slate-200 transition-all ${\\n                        todo.completed\\n                          ? \\"line-through text-slate-400 dark:text-slate-500\\"\\n                          : \\"\\"\\n                      }`}\\n                    >\\n                      {todo.text}\\n                    </span>\\n\\n                    <Button\\n                      variant=\\"ghost\\"\\n                      size=\\"icon\\"\\n                      onClick={() => deleteTodo(todo.id)}\\n                      className=\\"opacity-0 group-hover:opacity-100 text-red-500 hover:text-red-600 hover:bg-red-50 dark:hover:bg-red-950 transition-all\\"\\n                      aria-label=\\"Delete task\\"\\n                    >\\n                      <Trash2 className=\\"h-4 w-4\\" />\\n                    </Button>\\n                  </li>\\n                ))}\\n              </ul>\\n            )}\\n          </CardContent>\\n        </Card>\\n\\n        {/* Footer */}\\n        <footer className=\\"mt-12 text-center text-sm text-slate-500 dark:text-slate-400\\">\\n          <p>Double-click a task to edit • Press Enter to save</p>\\n          <p className=\\"mt-1\\">Built with Next.js & Shadcn UI</p>\\n        </footer>\\n      </main>\\n    </div>\\n  );\\n}\\n", "app/layout.tsx": "import type { Metadata } from \\"next\\";\\nimport { Geist, Geist_Mono } from \\"next/font/google\\";\\nimport \\"./globals.css\\";\\nimport { ThemeProvider } from \\"./providers\\";\\n\\nconst geistSans = Geist({\\n  variable: \\"--font-geist-sans\\",\\n  subsets: [\\"latin\\"],\\n});\\n\\nconst geistMono = Geist_Mono({\\n  variable: \\"--font-geist-mono\\",\\n  subsets: [\\"latin\\"],\\n});\\n\\nexport const metadata: Metadata = {\\n  title: \\"Todo App\\",\\n  description: \\"A simple todo app with light/dark mode\\",\\n};\\n\\nexport default function RootLayout({\\n  children,\\n}: Readonly<{\\n  children: React.ReactNode;\\n}>) {\\n  return (\\n    <html lang=\\"en\\" suppressHydrationWarning>\\n      <body\\n        className={`${geistSans.variable} ${geistMono.variable} antialiased`}\\n      >\\n        <ThemeProvider\\n          attribute=\\"class\\"\\n          defaultTheme=\\"system\\"\\n          enableSystem\\n          disableTransitionOnChange\\n        >\\n          {children}\\n        </ThemeProvider>\\n      </body>\\n    </html>\\n  );\\n}\\n", "app/providers.tsx": "\\"use client\\";\\n\\nimport { ThemeProvider as NextThemesProvider } from \\"next-themes\\";\\nimport { type ThemeProviderProps } from \\"next-themes\\";\\n\\nexport function ThemeProvider({ children, ...props }: ThemeProviderProps) {\\n  return <NextThemesProvider {...props}>{children}</NextThemesProvider>;\\n}\\n", "app/theme-toggle.tsx": "\\"use client\\";\\n\\nimport * as React from \\"react\\";\\nimport { Moon, Sun } from \\"lucide-react\\";\\nimport { useTheme } from \\"next-themes\\";\\nimport { Button } from \\"@/components/ui/button\\";\\n\\nexport function ThemeToggle() {\\n  const { theme, setTheme } = useTheme();\\n  const [mounted, setMounted] = React.useState(false);\\n\\n  React.useEffect(() => {\\n    setMounted(true);\\n  }, []);\\n\\n  if (!mounted) {\\n    return (\\n      <Button variant=\\"ghost\\" size=\\"icon\\" className=\\"h-9 w-9\\">\\n        <Sun className=\\"h-5 w-5\\" />\\n      </Button>\\n    );\\n  }\\n\\n  return (\\n    <Button\\n      variant=\\"ghost\\"\\n      size=\\"icon\\"\\n      onClick={() => setTheme(theme === \\"dark\\" ? \\"light\\" : \\"dark\\")}\\n      className=\\"h-9 w-9\\"\\n      aria-label=\\"Toggle theme\\"\\n    >\\n      {theme === \\"dark\\" ? (\\n        <Sun className=\\"h-5 w-5 text-yellow-500\\" />\\n      ) : (\\n        <Moon className=\\"h-5 w-5 text-slate-700\\" />\\n      )}\\n    </Button>\\n  );\\n}\\n"}	2026-03-13 14:44:50.529	2026-03-13 14:44:50.529	Added light/dark mode to the todo app using next-themes. Created a ThemeProvider component, a ThemeToggle button with sun/moon icons, and updated the layout to wrap the app with the theme provider. The toggle button is now in the header, allowing users to switch between light and dark themes or follow their system preference.
