lch(1 0 0);\\n  --foreground: oklch(0.145 0 0);\\n  --card: oklch(1 0 0);\\n  --card-foreground: oklch(0.145 0 0);\\n  --popover: oklch(1 0 0);\\n  --popover-foreground: oklch(0.145 0 0);\\n  --primary: oklch(0.205 0 0);\\n  --primary-foreground: oklch(0.985 0 0);\\n  --secondary: oklch(0.97 0 0);\\n  --secondary-foreground: oklch(0.205 0 0);\\n  --muted: oklch(0.97 0 0);\\n  --muted-foreground: oklch(0.556 0 0);\\n  --accent: oklch(0.97 0 0);\\n  --accent-foreground: oklch(0.205 0 0);\\n  --destructive: oklch(0.577 0.245 27.325);\\n  --border: oklch(0.922 0 0);\\n  --input: oklch(0.922 0 0);\\n  --ring: oklch(0.708 0 0);\\n  --chart-1: oklch(0.646 0.222 41.116);\\n  --chart-2: oklch(0.6 0.118 184.704);\\n  --chart-3: oklch(0.398 0.07 227.392);\\n  --chart-4: oklch(0.828 0.189 84.429);\\n  --chart-5: oklch(0.769 0.188 70.08);\\n  --sidebar: oklch(0.985 0 0);\\n  --sidebar-foreground: oklch(0.145 0 0);\\n  --sidebar-primary: oklch(0.205 0 0);\\n  --sidebar-primary-foreground: oklch(0.985 0 0);\\n  --sidebar-accent: oklch(0.97 0 0);\\n  --sidebar-accent-foreground: oklch(0.205 0 0);\\n  --sidebar-border: oklch(0.922 0 0);\\n  --sidebar-ring: oklch(0.708 0 0);\\n}\\n\\n.dark {\\n  --background: oklch(0 0 0);\\n  --foreground: oklch(0.985 0 0);\\n  --card: oklch(0.08 0 0);\\n  --card-foreground: oklch(0.985 0 0);\\n  --popover: oklch(0.08 0 0);\\n  --popover-foreground: oklch(0.985 0 0);\\n  --primary: oklch(0.922 0 0);\\n  --primary-foreground: oklch(0.205 0 0);\\n  --secondary: oklch(0.15 0 0);\\n  --secondary-foreground: oklch(0.985 0 0);\\n  --muted: oklch(0.15 0 0);\\n  --muted-foreground: oklch(0.708 0 0);\\n  --accent: oklch(0.15 0 0);\\n  --accent-foreground: oklch(0.985 0 0);\\n  --destructive: oklch(0.704 0.191 22.216);\\n  --border: oklch(1 0 0 / 10%);\\n  --input: oklch(1 0 0 / 15%);\\n  --ring: oklch(0.556 0 0);\\n  --chart-1: oklch(0.488 0.243 264.376);\\n  --chart-2: oklch(0.696 0.17 162.48);\\n  --chart-3: oklch(0.769 0.188 70.08);\\n  --chart-4: oklch(0.627 0.265 303.9);\\n  --chart-5: oklch(0.645 0.246 16.439);\\n  --sidebar: oklch(0.05 0 0);\\n  --sidebar-foreground: oklch(0.985 0 0);\\n  --sidebar-primary: oklch(0.488 0.243 264.376);\\n  --sidebar-primary-foreground: oklch(0.985 0 0);\\n  --sidebar-accent: oklch(0.15 0 0);\\n  --sidebar-accent-foreground: oklch(0.985 0 0);\\n  --sidebar-border: oklch(1 0 0 / 10%);\\n  --sidebar-ring: oklch(0.556 0 0);\\n}\\n\\n@layer base {\\n  * {\\n    @apply border-border outline-ring/50;\\n  }\\n  body {\\n    @apply bg-background text-foreground;\\n  }\\n}\\n"}	2026-03-13 15:02:18.038	2026-03-13 15:02:18.038	Updated the dark mode theme in globals.css to use a pure black background (oklch(0 0 0)) instead of the navy/dark gray. Adjusted card, popover, and sidebar colors to maintain visual contrast while keeping the black theme throughout the UI.
a6bb1535-413b-427b-90a7-2d2447920b0e	497b71eb-7329-45b8-86ad-58b2e7be665e	https://3000-ipgrj5856ph9xdokk4hv8.e2b.app	Todo App\n	{"app/page.tsx": "\\"use client\\";\\n\\nimport { useState, useEffect } from \\"react\\";\\nimport { Button } from \\"@/components/ui/button\\";\\nimport { Input } from \\"@/components/ui/input\\";\\nimport { Card, CardContent, CardHeader, CardTitle } from \\"@/components/ui/card\\";\\nimport { Plus, Trash2, Check, Circle } from \\"lucide-react\\";\\nimport { ThemeToggle } from \\"./theme-toggle\\";\\n\\ninterface Todo {\\n  id: string;\\n  text: string;\\n  completed: boolean;\\n  createdAt: number;\\n}\\n\\ntype FilterType = \\"all\\" | \\"active\\" | \\"completed\\";\\n\\nexport default function Home() {\\n  const [todos, setTodos] = useState<Todo[]>([]);\\n  const [inputValue, setInputValue] = useState(\\"\\");\\n  const [filter, setFilter] = useState<FilterType>(\\"all\\");\\n\\n  // Load todos from localStorage on mount\\n  useEffect(() => {\\n    const savedTodos = localStorage.getItem(\\"todos\\");\\n    if (savedTodos) {\\n      setTodos(JSON.parse(savedTodos));\\n    }\\n  }, []);\\n\\n  // Save todos to localStorage whenever they change\\n  useEffect(() => {\\n    localStorage.setItem(\\"todos\\", JSON.stringify(todos));\\n  }, [todos]);\\n\\n  const addTodo = () => {\\n    if (inputValue.trim() === \\"\\") return;\\n\\n    const newTodo: Todo = {\\n      id: Date.now().toString(),\\n      text: inputValue.trim(),\\n      completed: false,\\n      createdAt: Date.now(),\\n    };\\n\\n    setTodos([newTodo, ...todos]);\\n    setInputValue(\\"\\");\\n  };\\n\\n  const toggleTodo = (id: string) => {\\n    setTodos(\\n      todos.map((todo) =>\\n        todo.id === id ? { ...todo, completed: !todo.completed } : todo\\n      )\\n    );\\n  };\\n\\n  const deleteTodo = (id: string) => {\\n    setTodos(todos.filter((todo) => todo.id !== id));\\n  };\\n\\n  const clearCompleted = () => {\\n    setTodos(todos.filter((todo) => !todo.completed));\\n  };\\n\\n  const filteredTodos = todos.filter((todo) => {\\n    if (filter === \\"active\\") return !todo.completed;\\n    if (filter === \\"completed\\") return todo.completed;\\n    return true;\\n  });\\n\\n  const activeTodosCount = todos.filter((todo) => !todo.completed).length;\\n  const completedTodosCount = todos.filter((todo) => todo.completed).length;\\n\\n  return (\\n    <div className=\\"min-h-screen bg-gradient-to-br from-slate-50 to-slate-100 dark:from-black dark:to-black\\">\\n      {/* Header */}\\n      <header className=\\"border-b border-slate-200 dark:border-zinc-800 bg-white/80 dark:bg-black backdrop-blur-sm sticky top-0 z-10\\">\\n        <div className=\\"max-w-3xl mx-auto px-4 py-6 flex justify-between items-start\\">\\n          <div>\\n            <h1 className=\\"text-3xl font-bold text-slate-900 dark:text-white\\">\\n              ✅ Todo App\\n            </h1>\\n            <p className=\\"text-slate-600 dark:text-zinc-400 mt-1\\">\\n              Stay organized, get things done\\n            </p>\\n          </div>\\n          <ThemeToggle />\\n        </div>\\n      </header>\\n\\n      {/* Main Content */}\\n      <main className=\\"max-w-3xl mx-auto px-4 py-8\\">\\n        {/* Add Todo Form */}\\n        <Card className=\\"mb-6 shadow-lg border border-slate-200 dark:border-zinc-800 bg-white dark:bg-zinc-900\\">\\n          <CardHeader>\\n            <CardTitle className=\\"text-lg text-slate-900 dark:text-white\\">\\n              Add a new task\\n            </CardTitle>\\n          </CardHeader>\\n          <CardContent>\\n            <div className=\\"flex gap-3\\">\\n              <Input\\n                type=\\"text\\"\\n                placeholder=\\"What needs to be done?\\"\\n                value={inputValue}\\n                onChange={(e) => setInputValue(e.target.value)}\\n                onKeyDown={(e) => e.key === \\"Enter\\" && addTodo()}\\n                className=\\"flex-1\\"\\n              />\\n              <Button onClick={addTodo} className=\\"gap-2\\">\\n                <Plus className=\\"h-4 w-4\\" />\\n                Add\\n              </Button>\\n            </div>\\n          </CardContent>\\n        </Card>\\n\\n        {/* Stats and Filters */}\\n        <div className=\\"flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4 mb-6\\">\\n          <div className=\\"flex gap-4 text-sm text-slate-600 dark:text-zinc-400\\">\\n            <span>\\n              <strong className=\\"text-slate-900 dark:text-white\\">\\n                {activeTodosCount}\\n              </strong>{\\" \\"}\\n              active\\n            </span>\\n            <span>\\n              <strong className=\\"text-slate-900 dark:text-white\\">\\n                {completedTodosCount}\\n              </strong>{\\" \\"}\\n              completed\\n            </span>\\n          </div>\\n\\n          <div className=\\"flex gap-2 flex-wrap\\">\\n            {([\\"all\\", \\"active\\", \\"completed\\"] as FilterType[]).map((f) => (\\n              <Button\\n                key={f}\\n                variant={filter === f ? \\"default\\" : \\"outline\\"}\\n                size=\\"sm\\"\\n                onClick={() => setFilter(f)}\\n                className=\\"capitalize\\"\\n              >\\n                {f}\\n              </Button>\\n            ))}\\n            {completedTodosCount > 0 && (\\n              <Button\\n                variant=\\"ghost\\"\\n                size=\\"sm\\"\\n                onClick={clearCompleted}\\n                className=\\"text-red-600 hover:text-red-700 hover:bg-red-50 dark:hover:bg-red-950/50\\"\\n              >\\n                Clear completed\\n              </Button>\\n            )}\\n          </div>\\n        </div>\\n\\n        {/* Todo List */}\\n        <Card className=\\"shadow-lg border border-slate-200 dark:border-zinc-800 bg-white dark:bg-zinc-900\\">\\n          <CardContent className=\\"p-0\\">\\n            {filteredTodos.length === 0 ? (\\n              <div className=\\"py-16 text-center text-slate-500 dark:text-zinc-400\\">\\n                <div className=\\"text-5xl mb-4\\">📝</div>\\n                <p className=\\"text-lg\\">\\n                  {filter === \\"all\\"\\n                    ? \\"No tasks yet. Add one above!\\"\\n                    : filter === \\"active\\"\\n                    ? \\"No active tasks. Great job!\\"\\n                    : \\"No completed tasks yet.\\"}\\n                </p>\\n              </div>\\n            ) : (\\n              <ul className=\\"divide-y divide-slate-200 dark:divide-zinc-800\\">\\n                {filteredTodos.map((todo) => (\\n                  <li\\n                    key={todo.id}\\n                    className=\\"flex items-center gap-3 p-4 hover:bg-slate-50 dark:hover:bg-zinc-800/50 transition-colors group\\"\\n                  >\\n                    <button\\n                      onClick={() => toggleTodo(todo.id)}\\n                      className=\\"flex-shrink-0 text-slate-400 hover:text-slate-600 dark:hover:text-zinc-300 transition-colors\\"\\n                      aria-label={\\n                        todo.completed ? \\"Mark as incomplete\\" : \\"Mark as complete\\"\\n                      }\\n                    >\\n                      {todo.completed ? (\\n                        <div className=\\"h-6 w-6 rounded-full bg-green-500 flex items-center justify-center\\">\\n                          <Check className=\\"h-4 w-4 text-white\\" />\\n                        </div>\\n                      ) : (\\n                        <Circle className=\\"h-6 w-6\\" />\\n                      )}\\n                    </button>\\n\\n                    <span\\n                      className={`flex-1 text-slate-800 dark:text-zinc-200 transition-all ${\\n                        todo.completed\\n                          ? \\"line-through text-slate-400 dark:text-zinc-500\\"\\n                          : \\"\\"\\n                      }`}\\n                    >\\n                      {todo.text}\\n                    </span>\\n\\n                    <Button\\n                      variant=\\"ghost\\"\\n                      size=\\"icon\\"\\n                      onClick={() => deleteTodo(todo.id)}\\n                      className=\\"opacity-0 group-hover:opacity-100 text-red-500 hover:text-red-600 hover:bg-red-50 dark:hover:bg-red-950/50 transition-all\\"\\n                      aria-label=\\"Delete task\\"\\n                    >\\n                      <Trash2 className=\\"h-4 w-4\\" />\\n                    </Button>\\n                  </li>\\n                ))}\\n              </ul>\\n            )}\\n          </CardContent>\\n        </Card>\\n\\n        {/* Footer */}\\n        <footer className=\\"mt-12 text-center text-sm text-slate-500 dark:text-zinc-500\\">\\n          <p>Double-click a task to edit • Press Enter to save</p>\\n          <p className=\\"mt-1\\">Built with Next.js & Shadcn UI</p>\\n        </footer>\\n      </main>\\n    </div>\\n  );\\n}\\n"}	2026-03-13 15:04:41.106	2026-03-13 15:04:41.106	Fixed the dark mode theme to use a pure black background instead of navy/slate colors. Updated all dark mode classes to use black and zinc color palette for a true dark theme.
171bb381-fb72-4c91-8d51-dec10d4e34d8	5f45a53f-e2bf-4f05-9835-a9e9bc91be74	https://3000-iaovuv911wj1go8q0mu33.e2b.app	Revolution Study Guide\n	{"app/page.tsx": "\\"use client\\";\\n\\nimport { useState } from \\"react\\";\\nimport { Tabs, TabsContent, TabsList, TabsTrigger } from \\"@/components/ui/tabs\\";\\nimport { Card, CardContent, CardDescription, CardHeader, CardTitle } from \\"@/components/ui/card\\";\\nimport { Badge } from \\"@/components/ui/badge\\";\\nimport { Progress } from \\"@/components/ui/progress\\";\\nimport { Button } from \\"@/components/ui/button\\";\\nimport { Accordion, AccordionContent, AccordionItem, AccordionTrigger } from \\"@/components/ui/accordion\\";\\nimport { BookOpen, Clock, Users, Lightbulb, Trophy, ChevronRight, RotateCcw, CheckCircle2, XCircle } from \\"lucide-react\\";\\nimport { timelineEvents } from \\"./data/timeline\\";\\nimport { keyFigures } from \\"./data/figures\\";\\nimport { flashcards, type Flashcard } from \\"./data/flashcards\\";\\nimport { quizQuestions, type QuizQuestion } from \\"./data/quiz\\";\\nimport { keyTerms } from \\"./data/terms\\";\\n\\nexport default function StudyGuidePage() {\\n  const [currentFlashcard, setCurrentFlashcard] = useState(0);\\n  const [showAnswer, setShowAnswer] = useState(false);\\n  const [studiedCards, setStudiedCards] = useState<Set<number>>(new Set());\\n  \\n  const [currentQuiz, setCurrentQuiz] = useState(0);\\n  const [selectedAnswer, setSelectedAnswer] = useState<number | null>(null);\\n  const [showQuizResult, setShowQuizResult] = useState(false);\\n  const [score, setScore] = useState(0);\\n  const [quizCompleted, setQuizCompleted] = useState(false);\\n  const [answeredQuestions, setAnsweredQuestions] = useState<Set<number>>(new Set());\\n\\n  const handleNextFlashcard = () => {\\n    setShowAnswer(false);\\n    setCurrentFlashcard((prev) => (prev + 1) % flashcards.length);\\n  };\\n\\n  const handlePrevFlashcard = () => {\\n    setShowAnswer(false);\\n    setCurrentFlashcard((prev) => (prev - 1 + flashcards.length) % flashcards.length);\\n  };\\n\\n  const handleShowAnswer = () => {\\n    setShowAnswer(true);\\n    setStudiedCards((prev) => new Set([...prev, currentFlashcard]));\\n  };\\n\\n  const handleAnswerSelect = (answerIndex: number) => {\\n    if (showQuizResult) return;\\n    setSelectedAnswer(answerIndex);\\n  };\\n\\n  const handleCheckAnswer = () => {\\n    if (selectedAnswer === null) return;\\n    setShowQuizResult(true);\\n    if (selectedAnswer === quizQuestions[currentQuiz].correctAnswer) {\\n      setScore((prev) => prev + 1);\\n    }\\n    setAnsweredQuestions((prev) => new Set([...prev, currentQuiz]));\\n  };\\n\\n  const handleNextQuestion = () => {\\n    if (currentQuiz === quizQuestions.length - 1) {\\n      setQuizCompleted(true);\\n    } else {\\n      setCurrentQuiz((prev) => prev + 1);\\n      setSelectedAnswer(null);\\n      setShowQuizResult(false);\\n    }\\n  };\\n\\n  const handleRestartQuiz = () => {\\n    setCurrentQuiz(0);\\n    setSelectedAnswer(null);\\n    setShowQuizResult(false);\\n    setScore(0);\\n    setQuizCompleted(false);\\n    setAnsweredQuestions(new Set());\\n  };\\n\\n  const flashcardProgress = (studiedCards.size / flashcards.length) * 100;\\n\\n  return (\\n    <div className=\\"min-h-screen bg-gradient-to-b from-amber-50 to-orange-50 dark:from-slate-950 dark:to-slate-900\\">\\n      {/* Header */}\\n      <header className=\\"bg-gradient-to-r from-red-800 via-red-700 to-blue-900 text-white py-8 px-4 shadow-lg\\">\\n        <div className=\\"max-w-6xl mx-auto\\">\\n          <div className=\\"flex items-center gap-3 mb-2\\">\\n            <span className=\\"text-4xl\\">📜</span>\\n            <h1 className=\\"text-3xl md:text-4xl font-bold\\">American Revolution Study Guide</h1>\\n          </div>\\n          <p className=\\"text-amber-100 text-lg mt-2\\">Your comprehensive guide to understanding America's fight for independence (1765-1783)</p>\\n        </div>\\n      </header>\\n\\n      {/* Main Content */}\\n      <main className=\\"max-w-6xl mx-auto px-4 py-8\\">\\n        <Tabs defaultValue=\\"overview\\" className=\\"space-y-6\\">\\n          <TabsList className=\\"grid w-full grid-cols-2 md:grid-cols-6 gap-2 h-auto p-1\\">\\n            <TabsTrigger value=\\"overview\\" className=\\"flex items-center gap-2 py-2\\">\\n              <BookOpen className=\\"w-4 h-4\\" />\\n              <span className=\\"hidden sm:inline\\">Overview</span>\\n            </TabsTrigger>\\n            <TabsTrigger value=\\"timeline\\" className=\\"flex items-center gap-2 py-2\\">\\n              <Clock className=\\"w-4 h-4\\" />\\n              <span className=\\"hidden sm:inline\\">Timeline</span>\\n            </TabsTrigger>\\n            <TabsTrigger value=\\"figures\\" className=\\"flex items-center gap-2 py-2\\">\\n              <Users className=\\"w-4 h-4\\" />\\n              <span className=\\"hidden sm:inline\\">Figures</span>\\n            </TabsTrigger>\\n            <TabsTrigger value=\\"terms\\" className=\\"flex items-center gap-2 py-2\\">\\n              <Lightbulb className=\\"w-4 h-4\\" />\\n              <span className=\\"hidden sm:inline\\">Key Terms</span>\\n            </TabsTrigger>\\n            <TabsTrigger value=\\"flashcards\\" className=\\"flex items-center gap-2 py-2\\">\\n              <BookOpen className=\\"w-4 h-4\\" />\\n              <span className=\\"hidden sm:inline\\">Flashcards</span>\\n            </TabsTrigger>\\n            <TabsTrigger value=\\"quiz\\" className=\\"flex items-center gap-2 py-2\\">\\n              <Trophy className=\\"w-4 h-4\\" />\\n              <span className=\\"hidden sm:inline\\">Quiz</span>\\n            </TabsTrigger>\\n          </TabsList>\\n\\n          {/* Overview Tab */}\\n          <TabsContent value=\\"overview\\" className=\\"space-y-6\\">\\n            <Card className=\\"border-2 border-amber-200 dark:border-amber-800\\">\\n              <CardHeader>\\n                <CardTitle className=\\"text-2xl flex items-center gap-2\\">\\n                  <span>🏛️</span> Introduction to the American Revolution\\n                </CardTitle>\\n                <CardDescription className=\\"text-base\\">\\n                  The American Revolution (1765-1783) was a political and military rebellion in which thirteen of Great Britain's North American colonies rejected its rule, established the United States, and founded a new nation.\\n                </CardDescription>\\n              </CardHeader>\\n              <CardContent className=\\"space-y-6\\">\\n                <div className=\\"grid md:grid-cols-2 gap-6\\">\\n                  <div className=\\"space-y-4\\">\\n                    <h3 className=\\"font-semibold text-lg flex items-center gap-2\\">\\n                      <span>🎯</span> Key Causes\\n                    </h3>\\n                    <ul className=\\"space-y-2\\">\\n                      <li className=\\"flex items-start gap-2\\">\\n                        <ChevronRight className=\\"w-4 h-4 mt-1 text-red-600\\" />\\n                        <span><strong>Taxation without Representation:</strong> Britain imposed taxes without colonial consent</span>\\n                      </li>\\n                      <li className=\\"flex items-start gap-2\\">\\n                        <ChevronRight className=\\"w-4 h-4 mt-1 text-red-600\\" />\\n                        <span><strong>Stamp Act (1765):</strong> First direct tax on colonists for printed materials</span>\\n                      </li>\\n                      <li className=\\"flex items-start gap-2\\">\\n                        <ChevronRight className=\\"w-4 h-4 mt-1 text-red-600\\" />\\n                        <span><strong>Townshend Acts (1767):</strong> Taxes on imported goods, led to boycotts</span>\\n                      </li>\\n                      <li className=\\"flex items-start gap-2\\">\\n                        <ChevronRight className=\\"w-4 h-4 mt-1 text-red-600\\" />\\n                        <span><strong>Boston Massacre (1770):</strong> British soldiers killed five colonists</span>\\n                      </li>\\n                      <li className=\\"flex items-start gap-2\\">\\n                        <ChevronRight className=\\"w-4 h-4 mt-1 text-red-600\\" />\\n                        <span><strong>Intolerable Acts (1774):</strong> Punitive laws after Boston Tea Party</span>\\n                      </li>\\n                    </ul>\\n                  </div>\\n                  <div className=\\"space-y-4\\">\\n                    <h3 className=\\"font-semibold text-lg flex items-center gap-2\\">\\n                      <span>⚔️</span> Major Outcomes\\n                    </h3>\\n                    <ul className=\\"space-y-2\\">\\n                      <li className=\\"flex items-start gap-2\\">\\n                        <ChevronRight className=\\"w-4 h-4 mt-1 text-blue-600\\" />\\n                        <span><strong>Independence:</strong> 13 colonies became the United States of America</span>\\n                      </li>\\n                      <li className=\\"flex items-start gap-2\\">\\n                        <ChevronRight className=\\"w-4 h-4 mt-1 text-blue-600\\" />\\n                        <span><strong>Declaration of Independence:</strong> Adopted July 4, 1776</span>\\n                      </li>\\n                      <li className=\\"flex items-start gap-2\\">\\n                        <ChevronRight className=\\"w-4 h-4 mt-1 text-blue-600\\" />\\n                        <span><strong>Treaty of Paris (1783):</strong> Britain recognized US independence</span>\\n                      </li>\\n                      <li className=\\"flex items-start gap-2\\">\\n                        <ChevronRight className=\\"w-4 h-4 mt-1 text-blue-600\\" />\\n                        <span><strong>Constitution (1787):</strong> Framework for new government</span>\\n                      </li>\\n                      <li className=\\"flex items-start gap-2\\">\\n                        <ChevronRight className=\\"w-4 h-4 mt-1 text-blue-600\\" />\\n                        <span><strong>Bill of Rights (1791):</strong> First 10 amendments protecting liberties</span>\\n                      </li>\\n                    </ul>\\n                  </div>\\n                </div>\\n\\n                <div className=\\"bg-amber-100 dark:bg-amber-900/30 p-4 rounded-lg border border-amber-300 dark:border-amber-700\\">\\n                  <h4 className=\\"font-semibold mb-2 flex items-center gap-2\\">\\n                    <span>💡</span> Quick Facts\\n                  </h4>\\n                  <div className=\\"grid sm:grid-cols-3 gap-4 text-sm\\">\\n                    <div><strong>Duration:</strong> 1775-1783 (8 years)</div>\\n                    <div><strong>Colonies Involved:</strong> 13</div>\\n                    <div><strong>First President:</strong> George Washington (1789)</div>\\n                  </div>\\n                </div>\\n              </CardContent>\\n            </Card>\\n\\n            {/* Study Tips */}\\n            <Card>\\n              <CardHeader>\\n                <CardTitle className=\\"text-xl flex items-center gap-2\\">\\n                  <span>📚</span> How to Use This Study Guide\\n                </CardTitle>\\n              </CardHeader>\\n              <CardContent>\\n                <div className=\\"grid sm:grid-cols-2 lg:grid-cols-3 gap-4\\">\\n                  <div className=\\"p-4 bg-blue-50 dark:bg-blue-900/20 rounded-lg\\">\\n                    <h4 className=\\"font-semibold mb-2\\">1. Timeline</h4>\\n                    <p className=\\"text-sm text-muted-foreground\\">Study events chronologically to understand cause and effect relationships.</p>\\n                  </div>\\n                  <div className=\\"p-4 bg-green-50 dark:bg-green-900/20 rounded-lg\\">\\n                    <h4 className=\\"font-semibold mb-2\\">2. Key Figures</h4>\\n                    <p className=\\"text-sm text-muted-foreground\\">Learn about important people and their roles in the revolution.</p>\\n                  </div>\\n                  <div className=\\"p-4 bg-purple-50 dark:bg-purple-900/20 rounded-lg\\">\\n                    <h4 className=\\"font-semibold mb-2\\">3. Flashcards</h4>\\n                    <p className=\\"text-sm text-muted-foreground\\">Test your memory with interactive flashcards.</p>\\n                  </div>\\n                  <div className=\\"p-4 bg-amber-50 dark:bg-amber-900/20 rounded-lg\\">\\n                    <h4 className=\\"font-semibold mb-2\\">4. Key Terms</h4>\\n                    <p className=\\"text-sm text-muted-foreground\\">Master important vocabulary and concepts.</p>\\n                  </div>\\n                  <div className=\\"p-4 bg-red-50 dark:bg-red-900/20 rounded-lg\\">\\n                    <h4 className=\\"font-semibold mb-2\\">5. Quiz</h4>\\n                    <p className=\\"text-sm text-muted-foreground\\">Test your knowledge with multiple-choice questions.</p>\\n                  </div>\\n                  <div className=\\"p-4 bg-teal-50 dark:bg-teal-900/20 rounded-lg\\">\\n                    <h4 className=\\"font-semibold mb-2\\">6. Review</h4>\\n                    <p className=\\"text-sm text-muted-foreground\\">Return to areas where you need more practice.</p>\\n                  </div>\\n                </div>\\n              </CardContent>\\n            </Card>\\n          </TabsContent>\\n\\n          {/* Timeline Tab */}\\n          <TabsContent value=\\"timeline\\" className=\\"space-y-6\\">\\n            <Card>\\n              <CardHeader>\\n                <CardTitle className=\\"text-2xl flex items-center gap-2\\">\\n                  <span>📅</span> Timeline of Key Events\\n                </CardTitle>\\n                <CardDescription>\\n                  Follow the path from colonial unrest to American independence\\n                </CardDescription>\\n              </CardHeader>\\n              <CardContent>\\n                <div className=\\"relative\\">\\n                  {/* Timeline line */}\\n                  <div className=\\"absolute left-4 md:left-1/2 top-0 bottom-0 w-0.5 bg-gradient-to-b from-red-600 via-blue-600 to-amber-600\\" />\\n                  \\n                  <div className=\\"space-y-8\\">\\n                    {timelineEvents.map((event, index) => (\\n                      <div\\n                        key={event.id}\\n                        className={`relative flex items-start gap-4 ${\\n                          index % 2 === 0 ? \\"md:flex-row\\" : \\"md:flex-row-reverse\\"\\n                        }`}\\n                      >\\n                        {/* Timeline dot */}\\n                        <div className=\\"absolute left-4 md:left-1/2 -translate-x-1/2 w-4 h-4 bg-white border-4 border-red-600 rounded-full z-10\\" />\\n                        \\n                        {/* Content */}\\n                        <div className={`ml-12 md:ml-0 md:w-1/2 ${index % 2 === 0 ? \\"md:pr-12 md:text-right\\" : \\"md:pl-12\\"}`}>\\n                          <Badge variant={event.category === \\"military\\" ? \\"destructive\\" : event.category === \\"political\\" ? \\"default\\" : \\"secondary\\"} className=\\"mb-2\\">\\n                            {event.year}\\n                          </Badge>\\n                          <h3 className=\\"font-semibold text-lg\\">{event.title}</h3>\\n                          <p className=\\"text-muted-foreground mt-1\\">{event.description}</p>\\n                        </div>\\n                      </div>\\n                    ))}\\n                  </div>\\n                </div>\\n              </CardContent>\\n            </Card>\\n          </TabsContent>\\n\\n          {/* Key Figures Tab */}\\n          <TabsContent value=\\"figures\\" className=\\"space-y-6\\">\\n            <Card>\\n              <CardHeader>\\n                <CardTitle className=\\"text-2xl flex items-center gap-2\\">\\n                  <span>👥</span> Key Figures of the Revolution\\n                </CardTitle>\\n                <CardDescription>\\n                  Learn about the important people who shaped American independence\\n                </CardDescription>\\n              </CardHeader>\\n              <CardContent>\\n                <div className=\\"grid md:grid-cols-2 gap-6\\">\\n                  {keyFigures.map((figure) => (\\n                    <Card key={figure.id} className=\\"overflow-hidden\\">\\n                      <div className=\\"h-2 bg-gradient-to-r from-red-600 to-blue-600\\" />\\n                      <CardHeader>\\n                        <div className=\\"flex items-start justify-between\\">\\n                          <div>\\n                            <CardTitle className=\\"text-lg\\">{figure.name}</CardTitle>\\n                            <CardDescription>{figure.role}</CardDescription>\\n                          </div>\\n                          <Badge variant={figure.side === \\"Patriot\\" ? \\"default\\" : \\"secondary\\"}>\\n                            {figure.side}\\n                          </Badge>\\n                        </div>\\n                      </CardHeader>\\n                      <CardContent>\\n                        <p className=\\"text-sm text-muted-foreground mb-3\\">{figure.biography}</p>\\n                        <div className=\\"space-y-2\\">\\n                          <h4 className=\\"font-semibold text-sm\\">Key Contributions:</h4>\\n                          <ul className=\\"text-sm space-y-1\\">\\n                            {figure.contributions.map((contribution, i) => (\\n                              <li key={i} className=\\"flex items-start gap-2\\">\\n                                <CheckCircle2 className=\\"w-4 h-4 mt-0.5 text-green-600\\" />\\n                                <span>{contribution}</span>\\n                              </li>\\n                            ))}\\n                          </ul>\\n                        </div>\\n                      </CardContent>\\n                    </Card>\\n                  ))}\\n                </div>\\n              </CardContent>\\n            </Card>\\n          </TabsContent>\\n\\n          {/* Key Terms Tab */}\\n          <TabsContent value=\\"terms\\" className=\\"space-y-6\\">\\n            <Card>\\n              <CardHeader>\\n                <CardTitle className=\\"text-2xl flex items-center gap-2\\">\\n                  <span>📖</span> Key Terms & Definitions\\n                </CardTitle>\\n                <CardDescription>\\n                  Master the essential vocabulary of the American Revolution\\n                </CardDescription>\\n              </CardHeader>\\n              <CardContent>\\n                <Accordion type=\\"single\\" collapsible className=\\"w-full\\">\\n                  {keyTerms.map((term) => (\\n                    <AccordionItem key={term.id} value={`term-${term.id}`}>\\n                      <AccordionTrigger className=\\"text-left\\">\\n                        <div className=\\"flex items-center gap-3\\">\\n                          <Badge variant=\\"outline\\" className=\\"shrink-0\\">{term.category}</Badge>\\n                          <span className=\\"font-semibold\\">{term.term}</span>\\n                        </div>\\n                      </AccordionTrigger>\\n                      <AccordionContent>\\n                        <div className=\\"pl-4 space-y-2\\">\\n                          <p className=\\"text-muted-foreground\\">{term.definition}</p>\\n                          {term.significance && (\\n                            <p className=\\"text-sm\\"><strong>Significance:</strong> {term.significance}</p>\\n                          )}\\n                        </div>\\n                      </AccordionContent>\\n                    </AccordionItem>\\n                  ))}\\n                </Accordion>\\n              </CardContent>\\n            </Card>\\n          </TabsContent>\\n\\n          {/* Flashcards Tab */}\\n          <TabsContent value=\\"flashcards\\" className=\\"space-y-6\\">\\n            <Card>\\n              <CardHeader>\\n                <CardTitle className=\\"text-2xl flex items-center gap-2\\">\\n                  <span>🃏</span> Interactive Flashcards\\n                </CardTitle>\\n                <CardDescription>\\n                  Click to reveal answers and test your knowledge\\n                </CardDescription>\\n              </CardHeader>\\n              <CardContent className=\\"space-y-6\\">\\n                {/* Progress */}\\n                <div className=\\"space-y-2\\">\\n                  <div className=\\"flex justify-between text-sm\\">\\n                    <span>Progress: {studiedCards.size} / {flashcards.length} cards studied</span>\\n                    <span>{Math.round(flashcardProgress)}%</span>\\n                  </div>\\n                  <Progress value={flashcardProgress} />\\n                </div>\\n\\n                {/* Flashcard */}\\n                <div\\n                  className={`relative min-h-[300px] p-8 rounded-xl border-2 cursor-pointer transition-all duration-300 ${\\n                    showAnswer\\n                      ? \\"bg-blue-50 dark:bg-blue-900/20 border-blue-300 dark:border-blue-700\\"\\n                      : \\"bg-amber-50 dark:bg-amber-900/20 border-amber-300 dark:border-amber-700\\"\\n                  }`}\\n                  onClick={() => !showAnswer && handleShowAnswer()}\\n                >\\n                  <div className=\\"absolute top-4 left-4\\">\\n                    <Badge variant={showAnswer ? \\"default\\" : \\"secondary\\"}>\\n                      {showAnswer ? \\"Answer\\" : \\"Question\\"}\\n                    </Badge>\\n                  </div>\\n                  <div className=\\"absolute top-4 right-4 text-sm text-muted-foreground\\">\\n                    Card {currentFlashcard + 1} of {flashcards.length}\\n                  </div>\\n                  \\n                  <div className=\\"flex items-center justify-center min-h-[200px]\\">\\n                    <p className=\\"text-xl text-center font-medium\\">\\n                      {showAnswer ? flashcards[currentFlashcard].answer : flashcards[currentFlashcard].question}\\n                    </p>\\n                  </div>\\n\\n                  {!showAnswer && (\\n                    <p className=\\"absolute bottom-4 left-1/2 -translate-x-1/2 text-sm text-muted-foreground\\">\\n                      Click to reveal answer\\n                    </p>\\n                  )}\\n                </div>\\n\\n                {/* Controls */}\\n                <div className=\\"flex justify-center gap-4\\">\\n                  <Button variant=\\"outline\\" onClick={handlePrevFlashcard}>\\n                    ← Previous\\n                  </Button>\\n                  {!showAnswer ? (\\n                    <Button onClick={handleShowAnswer}>Show Answer</Button>\\n                  ) : (\\n                    <Button onClick={handleNextFlashcard}>Next Card →</Button>\\n                  )}\\n                </div>\\n\\n                {/* Card Navigation */}\\n                <div className=\\"flex flex-wrap justify-center gap-2\\">\\n                  {flashcards.map((_, index) => (\\n                    <button\\n                      key={index}\\n                      onClick={() => {\\n                        setCurrentFlashcard(index);\\n                        setShowAnswer(false);\\n                      }}\\n                      className={`w-8 h-8 rounded-full text-sm font-medium transition-all ${\\n                        index === currentFlashcard\\n                          ? \\"bg-primary text-primary-foreground\\"\\n                          : studiedCards.has(index)\\n                          ? \\"bg-green-100 dark:bg-green-900/30 text-green-700 dark:text-green-300 border border-green-300\\"\\n                          : \\"bg-gray-100 dark:bg-gray-800 text-gray-600 dark:text-gray-400 hover:bg-gray-200 dark:hover:bg-gray-700\\"\\n                      }`}\\n                    >\\n                      {index + 1}\\n                    </button>\\n                  ))}\\n                </div>\\n              </CardContent>\\n            </Card>\\n          </TabsContent>\\n\\n          {/* Quiz Tab */}\\n          <TabsContent value=\\"quiz\\" className=\\"space-y-6\\">\\n            <Card>\\n              <CardHeader>\\n                <CardTitle className=\\"text-2xl flex items-center gap-2\\">\\n                  <span>🎯</span> Test Your Knowledge\\n                </CardTitle>\\n                <CardDescription>\\n                  Answer these questions to check your understanding\\n                </CardDescription>\\n              </CardHeader>\\n              <CardContent className=\\"space-y-6\\">\\n                {!quizCompleted ? (\\n                  <>\\n                    {/* Progress */}\\n                    <div className=\\"space-y-2\\">\\n                      <div className=\\"flex justify-between text-sm\\">\\n                        <span>Question {currentQuiz + 1} of {quizQuestions.length}</span>\\n                        <span>Score: {score}/{answeredQuestions.size}</span>\\n                      </div>\\n                      <Progress value={((currentQuiz + 1) / quizQuestions.length) * 100} />\\n                    </div>\\n\\n                    {/* Question */}\\n                    <div className=\\"p-6 bg-gray-50 dark:bg-gray-800/50 rounded-lg\\">\\n                      <p className=\\"text-lg font-medium mb-4\\">\\n                        {quizQuestions[currentQuiz].question}\\n                      </p>\\n                      \\n                      <div className=\\"space-y-3\\">\\n                        {quizQuestions[currentQuiz].options.map((option, index) => (\\n                          <button\\n                            key={index}\\n                            onClick={() => handleAnswerSelect(index)}\\n                            disabled={showQuizResult}\\n                            className={`w-full p-4 text-left rounded-lg border-2 transition-all ${\\n                              selectedAnswer === index\\n                                ? showQuizResult\\n                                  ? index === quizQuestions[currentQuiz].correctAnswer\\n                                    ? \\"border-green-500 bg-green-50 dark:bg-green-900/30\\"\\n                                    : \\"border-red-500 bg-red-50 dark:bg-red-900/30\\"\\n                                  : \\"border-primary bg-primary/10\\"\\n                                : showQuizResult && index === quizQuestions[currentQuiz].correctAnswer\\n                                ? \\"border-green-500 bg-green-50 dark:bg-green-900/30\\"\\n                                : \\"border-gray-200 dark:border-gray-700 hover:border-gray-300 dark:hover:border-gray-600\\"\\n                            }`}\\n                          >\\n                            <div className=\\"flex items-center gap-3\\">\\n                              <span className={`w-8 h-8 rounded-full flex items-center justify-center text-sm font-medium ${\\n                                selectedAnswer === index\\n                                  ? showQuizResult\\n                                    ? index === quizQuestions[currentQuiz].correctAnswer\\n                                      ? \\"bg-green-500 text-white\\"\\n                                      : \\"bg-red-500 text-white\\"\\n                                    : \\"bg-primary text-primary-foreground\\"\\n                                  : showQuizResult && index === quizQuestions[currentQuiz].correctAnswer\\n                                  ? \\"bg-green-500 text-white\\"\\n                                  : \\"bg-gray-200 dark:bg-gray-700\\"\\n                              }`}>\\n                                {showQuizResult ? (\\n                                  index === quizQuestions[currentQuiz].correctAnswer ? (\\n                                    <CheckCircle2 className=\\"w-5 h-5\\" />\\n                                  ) : selectedAnswer === index ? (\\n                                    <XCircle className=\\"w-5 h-5\\" />\\n                                  ) : (\\n                                    String.fromCharCode(65 + index)\\n                                  )\\n                                ) : (\\n                                  String.fromCharCode(65 + index)\\n                                )}\\n                              </span>\\n                              <span>{option}</span>\\n                            </div>\\n                          </button>\\n                        ))}\\n                      </div>\\n                    </div>\\n\\n                    {/* Explanation */}\\n                    {showQuizResult && quizQuestions[currentQuiz].explanation && (\\n                      <div className=\\"p-4 bg-blue-50 dark:bg-blue-900/20 rounded-lg border border-blue-200 dark:border-blue-800\\">\\n                        <p className=\\"text-sm\\"><strong>Explanation:</strong> {quizQuestions[currentQuiz].explanation}</p>\\n                      </div>\\n                    )}\\n\\n                    {/* Controls */}\\n                    <div className=\\"flex justify-end gap-4\\">\\n                      {!showQuizResult ? (\\n                        <Button onClick={handleCheckAnswer} disabled={selectedAnswer === null}>\\n                          Check Answer\\n                        </Button>\\n                      ) : (\\n                        <Button onClick={handleNextQuestion}>\\n                          {currentQuiz === quizQuestions.length - 1 ? \\"See Results\\" : \\"Next Question\\"}\\n                        </Button>\\n                      )}\\n                    </div>\\n                  </>\\n                ) : (\\n                  /* Results */\\n                  <div className=\\"text-center py-8 space-y-6\\">\\n                    <div className=\\"text-6xl\\">🏆</div>\\n                    <h3 className=\\"text-2xl font-bold\\">Quiz Complete!</h3>\\n                    <div className=\\"text-4xl font-bold text-primary\\">\\n                      {score} / {quizQuestions.length}\\n                    </div>\\n                    <p className=\\"text-muted-foreground\\">\\n                      {score === quizQuestions.length\\n                        ? \\"Perfect score! You're a Revolution expert!\\"\\n                        : score >= quizQuestions.length * 0.7\\n                        ? \\"Great job! You have a solid understanding!\\"\\n                        : score >= quizQuestions.length * 0.5\\n                        ? \\"Good effort! Keep studying to improve!\\"\\n                        : \\"Keep practicing! Review the material and try again.\\"}\\n                    </p>\\n                    <div className=\\"flex justify-center gap-4\\">\\n                      <Button variant=\\"outline\\" onClick={handleRestartQuiz}>\\n                        <RotateCcw className=\\"w-4 h-4 mr-2\\" />\\n                        Try Again\\n                      </Button>\\n                    </div>\\n                  </div>\\n                )}\\n              </CardContent>\\n            </Card>\\n          </TabsContent>\\n        </Tabs>\\n      </main>\\n\\n      {/* Footer */}\\n      <footer className=\\"bg-slate-100 dark:bg-slate-900 py-6 px-4 mt-12 border-t\\">\\n        <div className=\\"max-w-6xl mx-auto text-center text-sm text-muted-foreground\\">\\n          <p>American Revolution Study Guide • Created for educational purposes</p>\\n          <p className=\\"mt-1\\">📚 Study hard, learn well, and ace your exam!</p>\\n        </div>\\n      </footer>\\n    </div>\\n  );\\n}\\n", "app/data/quiz.ts": "export interface QuizQuestion {\\n  id: number;\\n  question: string;\\n  options: string[];\\n  correctAnswer: number;\\n  explanation: string;\\n}\\n\\nexport const quizQuestions: QuizQuestion[] = [\\n  {\\n    id: 1,\\n    question: \\"What was the first direct tax imposed by Britain on the American colonists?\\",\\n    options: [\\"Townshend Acts\\", \\"Tea Act\\", \\"Stamp Act\\", \\"Sugar Act\\"],\\n    correctAnswer: 2,\\n    explanation: \\"The Stamp Act of 1765 was the first direct tax imposed on American colonists, requiring them to pay a tax on all printed materials including newspapers, legal documents, and playing cards.\\"\\n  },\\n  {\\n    id: 2,\\n    question: \\"Which event is considered the start of the American Revolutionary War?\\",\\n    options: [\\"Boston Tea Party\\", \\"Battles of Lexington and Concord\\", \\"Boston Massacre\\", \\"Declaration of Independence\\"],\\n    correctAnswer: 1,\\n    explanation: \\"The Battles of Lexington and Concord on April 19, 1775, marked the first military engagements of the Revolutionary War, often referred to as 'the shot heard 'round the world.'\\"\\n  },\\n  {\\n    id: 3,\\n    question: \\"Who was the principal author of the Declaration of Independence?\\",\\n    options: [\\"Benjamin Franklin\\", \\"John Adams\\", \\"George Washington\\", \\"Thomas Jefferson\\"],\\n    correctAnswer: 3,\\n    explanation: \\"Thomas Jefferson was the principal author of the Declaration of Independence, though he worked with a committee that included John Adams, Benjamin Franklin, Roger Sherman, and Robert Livingston.\\"\\n  },\\n  {\\n    id: 4,\\n    question: \\"Which battle is considered the turning point of the Revolutionary War?\\",\\n    options: [\\"Battle of Bunker Hill\\", \\"Battle of Saratoga\\", \\"Battle of Yorktown\\", \\"Battle of Trenton\\"],\\n    correctAnswer: 1,\\n    explanation: \\"The American victory at Saratoga in 1777 convinced France that the Americans could win, leading to the crucial French alliance in 1778 that provided essential military and financial support.\\"\\n  },\\n  {\\n    id: 5,\\n    question: \\"What did the Intolerable Acts do?\\",\\n    options: [\\"Imposed new taxes on tea\\", \\"Closed Boston Harbor and punished Massachusetts\\", \\"Required colonists to house British soldiers\\", \\"Granted independence to the colonies\\"],\\n    correctAnswer: 1,\\n    explanation: \\"The Intolerable Acts (1774) were punitive laws passed in response to the Boston Tea Party. They closed Boston Harbor, revoked Massachusetts' charter, and allowed British officials to be tried in Britain.\\"\\n  },\\n  {\\n    id: 6,\\n    question: \\"Which country's alliance was crucial to American victory in the Revolutionary War?\\",\\n    options: [\\"Spain\\", \\"Netherlands\\", \\"France\\", \\"Russia\\"],\\n    correctAnswer: 2,\\n    explanation: \\"France's alliance in 1778 provided crucial military support including troops, naval power, weapons, and financial aid. The French navy was essential to the victory at Yorktown.\\"\\n  },\\n  {\\n    id: 7,\\n    question: \\"What event led directly to the Intolerable Acts?\\",\\n    options: [\\"Boston Massacre\\", \\"Boston Tea Party\\", \\"Stamp Act protests\\", \\"Battle of Bunker Hill\\"],\\n    correctAnswer: 1,\\n    explanation: \\"The Boston Tea Party (December 1773), where colonists dumped British tea into Boston Harbor, led directly to Britain passing the Intolerable Acts to punish Massachusetts.\\"\\n  },\\n  {\\n    id: 8,\\n    question: \\"Who commanded the Continental Army during the Revolutionary War?\\",\\n    options: [\\"Thomas Jefferson\\", \\"Benedict Arnold\\", \\"George Washington\\", \\"John Adams\\"],\\n    correctAnswer: 2,\\n    explanation: \\"George Washington was appointed by the Continental Congress as Commander-in-Chief of the Continental Army in 1775 and led the army throughout the war.\\"\\n  },\\n  {\\n    id: 9,\\n    question: \\"What did the Treaty of Paris (1783) accomplish?\\",\\n    options: [\\"Ended the French and Indian War\\", \\"Established the U.S. Constitution\\", \\"Recognized American independence\\", \\"Created the Bill of Rights\\"],\\n    correctAnswer: 2,\\n    explanation: \\"The Treaty of Paris (1783) officially ended the Revolutionary War and Britain recognized American independence. The U.S. gained territory from the Atlantic to the Mississippi River.\\"\\n  },\\n  {\\n    id: 10,\\n    question: \\"What was the significance of Thomas Paine's 'Common Sense'?\\",\\n    options: [\\"It outlined the U.S. Constitution\\", \\"It argued for American independence in plain language\\", \\"It described British military strategy\\", \\"It was the first American newspaper\\"],\\n    correctAnswer: 1,\\n    explanation: \\"Thomas Paine's 'Common Sense' (1776) was a pamphlet that made a passionate case for independence in language ordinary Americans could understand, helping shift public opinion toward supporting independence.\\"\\n  },\\n  {\\n    id: 11,\\n    question: \\"Where did General Cornwallis surrender, effectively ending the Revolutionary War?\\",\\n    options: [\\"Saratoga\\", \\"Trenton\\", \\"Yorktown\\", \\"Bunker Hill\\"],\\n    correctAnswer: 2,\\n    explanation: \\"General Cornwallis surrendered at Yorktown, Virginia in 1781 after American and French forces trapped his army. This effectively ended major fighting in the Revolutionary War.\\"\\n  },\\n  {\\n    id: 12,\\n    question: \\"What were the Minutemen known for?\\",\\n    options: [\\"Serving in the British army\\", \\"Being ready to fight at a minute's notice\\", \\"Writing revolutionary pamphlets\\", \\"Leading the Continental Congress\\"],\\n    correctAnswer: 1,\\n    explanation: \\"Minutemen were colonial militia members who could be ready to fight 'at a minute's notice.' They played a key role in the early battles of the Revolution, especially at Lexington and Concord.\\"\\n  },\\n  {\\n    id: 13,\\n    question: \\"What famous phrase describes the battles of Lexington and Concord?\\",\\n    options: [\\"'Give me liberty or give me death'\\", \\"'The shot heard 'round the world'\\", \\"'No taxation without representation'\\", \\"'Don't fire until you see the whites of their eyes'\\"],\\n    correctAnswer: 1,\\n    explanation: \\"Ralph Waldo Emerson's phrase 'the shot heard 'round the world' describes the first shots fired at Lexington and Concord, which began the Revolutionary War.\\"\\n  },\\n  {\\n    id: 14,\\n    question: \\"What was the Boston Massacre?\\",\\n    options: [\\"A naval battle in Boston Harbor\\", \\"British soldiers killing five colonists\\", \\"The dumping of British tea\\", \\"A fire that destroyed Boston\\"],\\n    correctAnswer: 1,\\n    explanation: \\"The Boston Massacre (1770) occurred when British soldiers fired into a crowd of colonists, killing five. Patriots used this event as propaganda to rally support against British policies.\\"\\n  },\\n  {\\n    id: 15,\\n    question: \\"What was Benedict Arnold famous for?\\",\\n    options: [\\"Writing the Declaration of Independence\\", \\"Becoming a traitor to the American cause\\", \\"Leading the French alliance\\", \\"Inventing the submarine\\"],\\n    correctAnswer: 1,\\n    explanation: \\"Benedict Arnold was initially a skilled American general who helped win the Battle of Saratoga, but later betrayed his country by attempting to surrender West Point to the British.\\"\\n  }\\n];\\n", "app/data/terms.ts": "export interface KeyTerm {\\n  id: number;\\n  term: string;\\n  definition: string;\\n  significance?: string;\\n  category: string;\\n}\\n\\nexport const keyTerms: KeyTerm[] = [\\n  {\\n    id: 1,\\n    term: \\"Patriots\\",\\n    definition: \\"American colonists who supported independence from Britain. Also known as 'Rebels,' 'Whigs,' or 'Revolutionaries.'\\",\\n    significance: \\"Patriots formed the Continental Army, organized resistance, and established the new American government.\\",\\n    category: \\"Groups\\"\\n  },\\n  {\\n    id: 2,\\n    term: \\"Loyalists\\",\\n    definition: \\"American colonists who remained loyal to Britain during the Revolution. Also known as 'Tories.'\\",\\n    significance: \\"Approximately 20-30% of colonists were Loyalists. Many fled to Canada or Britain after the war.\\",\\n    category: \\"Groups\\"\\n  },\\n  {\\n    id: 3,\\n    term: \\"Sons of Liberty\\",\\n    definition: \\"A secret organization formed to advance the rights of colonists and fight taxation by the British government.\\",\\n    significance: \\"They organized protests, boycotts, and the Boston Tea Party. Leaders included Samuel Adams and Paul Revere.\\",\\n    category: \\"Groups\\"\\n  },\\n  {\\n    id: 4,\\n    term: \\"Continental Congress\\",\\n    definition: \\"The governing body representing the American colonies during and after the Revolutionary War. There were two Continental Congresses.\\",\\n    significance: \\"The First Continental Congress (1774) coordinated resistance; the Second (1775-1781) declared independence and managed the war effort.\\",\\n    category: \\"Government\\"\\n  },\\n  {\\n    id: 5,\\n    term: \\"Natural Rights\\",\\n    definition: \\"Rights that all people are born with, including life, liberty, and the pursuit of happiness. Central to Enlightenment philosophy.\\",\\n    significance: \\"These ideas, articulated by John Locke, formed the philosophical foundation of the Declaration of Independence.\\",\\n    category: \\"Philosophy\\"\\n  },\\n  {\\n    id: 6,\\n    term: \\"Salutary Neglect\\",\\n    definition: \\"Britain's unofficial policy of not strictly enforcing parliamentary laws on the American colonies, allowing them to develop self-government.\\",\\n    significance: \\"When Britain ended this policy after the French and Indian War, colonists resented the new enforcement of laws and taxes.\\",\\n    category: \\"Policy\\"\\n  },\\n  {\\n    id: 7,\\n    term: \\"Mercantilism\\",\\n    definition: \\"An economic theory that colonies exist to benefit the mother country by providing raw materials and buying manufactured goods.\\",\\n    significance: \\"British mercantile policies restricted colonial trade and manufacturing, contributing to colonial resentment.\\",\\n    category: \\"Economics\\"\\n  },\\n  {\\n    id: 8,\\n    term: \\"Boycott\\",\\n    definition: \\"A refusal to buy or use goods and services as a form of protest. Colonists boycotted British goods to protest taxes.\\",\\n    significance: \\"Boycotts were an effective non-violent protest method that hurt British merchants and pressured Parliament to repeal some taxes.\\",\\n    category: \\"Tactics\\"\\n  },\\n  {\\n    id: 9,\\n    term: \\"Quartering Act\\",\\n    definition: \\"Laws requiring American colonists to provide housing and supplies for British soldiers stationed in the colonies.\\",\\n    significance: \\"Colonists resented being forced to house soldiers in peacetime. This grievance was included in the Declaration of Independence.\\",\\n    category: \\"Laws\\"\\n  },\\n  {\\n    id: 10,\\n    term: \\"Tea Act\\",\\n    definition: \\"A 1773 law that gave the British East India Company a monopoly on tea sales in the colonies and kept a tax on tea.\\",\\n    significance: \\"This act led directly to the Boston Tea Party and was seen as a trick to get colonists to accept Parliament's right to tax them.\\",\\n    category: \\"Laws\\"\\n  },\\n  {\\n    id: 11,\\n    term: \\"Hessians\\",\\n    definition: \\"German mercenaries hired by Britain to fight in the Revolutionary War. About 30,000 served in America.\\",\\n    significance: \\"Their use angered colonists who saw it as Britain using foreign troops against its own citizens. Washington defeated Hessians at Trenton.\\",\\n    category: \\"Military\\"\\n  },\\n  {\\n    id: 12,\\n    term: \\"Continental Army\\",\\n    definition: \\"The professional fighting force established by the Continental Congress in 1775 to fight the British.\\",\\n    significance: \\"Commanded by George Washington, it was initially poorly trained and equipped but grew into an effective fighting force.\\",\\n    category: \\"Military\\"\\n  },\\n  {\\n    id: 13,\\n    term: \\"Militia\\",\\n    definition: \\"Citizen soldiers who could be called up for military service in emergencies. They trained occasionally and provided their own weapons.\\",\\n    significance: \\"Militia forces supplemented the Continental Army and played important roles in battles like Lexington and Concord.\\",\\n    category: \\"Military\\"\\n  },\\n  {\\n    id: 14,\\n    term: \\"Blockade\\",\\n    definition: \\"A military action preventing ships from entering or leaving a port, used to cut off supplies and trade.\\",\\n    significance: \\"The French naval blockade at Yorktown prevented British evacuation and led to Cornwallis's surrender.\\",\\n    category: \\"Military\\"\\n  },\\n  {\\n    id: 15,\\n    term: \\"Republic\\",\\n    definition: \\"A form of government where power is held by elected representatives and leaders are elected rather than inheriting power.\\",\\n    significance: \\"The United States was founded as a republic, rejecting monarchy and establishing representative democracy.\\",\\n    category: \\"Government\\"\\n  },\\n  {\\n    id: 16,\\n    term: \\"Federalism\\",\\n    definition: \\"A system of government where power is divided between a central (federal) government and state governments.\\",\\n    significance: \\"The U.S. Constitution established a federal system, balancing power between national and state governments.\\",\\n    category: \\"Government\\"\\n  },\\n  {\\n    id: 17,\\n    term: \\"Checks and Balances\\",\\n    definition: \\"A system where each branch of government can limit the powers of the others, preventing any one branch from becoming too powerful.\\",\\n    significance: \\"This principle was built into the U.S. Constitution to protect against tyranny and ensure balanced government.\\",\\n    category: \\"Government\\"\\n  },\\n  {\\n    id: 18,\\n    term: \\"Popular Sovereignty\\",\\n    definition: \\"The principle that government derives its power from the consent of the governed; the people are the source of governmental power.\\",\\n    significance: \\"This principle, stated in the Declaration of Independence, became a foundation of American government.\\",\\n    category: \\"Philosophy\\"\\n  },\\n  {\\n    id: 19,\\n    term: \\"Tyranny\\",\\n    definition: \\"Cruel and oppressive government or rule; the arbitrary or unrestrained exercise of power.\\",\\n    significance: \\"Colonists accused King George III of tyranny, justifying their revolution as a defense of liberty.\\",\\n    category: \\"Philosophy\\"\\n  },\\n  {\\n    id: 20,\\n    term: \\"Ratification\\",\\n    definition: \\"The formal approval of a document, such as a constitution or treaty, making it official and binding.\\",\\n    significance: \\"The Constitution required ratification by 9 of 13 states to take effect. The Bill of Rights was added to secure ratification.\\",\\n    category: \\"Government\\"\\n  }\\n];\\n", "app/data/figures.ts": "export interface KeyFigure {\\n  id: number;\\n  name: string;\\n  role: string;\\n  side: \\"Patriot\\" | \\"British\\" | \\"French\\";\\n  biography: string;\\n  contributions: string[];\\n}\\n\\nexport const keyFigures: KeyFigure[] = [\\n  {\\n    id: 1,\\n    name: \\"George Washington\\",\\n    role: \\"Commander-in-Chief & First President\\",\\n    side: \\"Patriot\\",\\n    biography: \\"Virginia planter and military leader who commanded the Continental Army throughout the Revolutionary War. His leadership, patience, and ability to keep the army together through difficult times were crucial to American victory.\\",\\n    contributions: [\\n      \\"Led Continental Army to victory despite limited resources\\",\\n      \\"Presided over Constitutional Convention\\",\\n      \\"Set precedent for peaceful transfer of power\\",\\n      \\"Established many presidential traditions still followed today\\"\\n    ]\\n  },\\n  {\\n    id: 2,\\n    name: \\"Thomas Jefferson\\",\\n    role: \\"Author of Declaration of Independence\\",\\n    side: \\"Patriot\\",\\n    biography: \\"Virginia lawyer and philosopher who became the principal author of the Declaration of Independence. His eloquent words articulated the colonies' reasons for seeking independence and established enduring principles of human liberty.\\",\\n    contributions: [\\n      \\"Wrote the Declaration of Independence\\",\\n      \\"Served as Minister to France during the war\\",\\n      \\"Third President of the United States\\",\\n      \\"Negotiated the Louisiana Purchase\\"\\n    ]\\n  },\\n  {\\n    id: 3,\\n    name: \\"Benjamin Franklin\\",\\n    role: \\"Diplomat & Founding Father\\",\\n    side: \\"Patriot\\",\\n    biography: \\"Philadelphia printer, scientist, and statesman who played a crucial diplomatic role in securing French support for the American cause. His fame and charm made him an effective advocate in Paris.\\",\\n    contributions: [\\n      \\"Secured crucial French alliance and military support\\",\\n      \\"Helped draft the Declaration of Independence\\",\\n      \\"Negotiated the Treaty of Paris ending the war\\",\\n      \\"Contributed to the Constitutional Convention\\"\\n    ]\\n  },\\n  {\\n    id: 4,\\n    name: \\"John Adams\\",\\n    role: \\"Diplomat & Second President\\",\\n    side: \\"Patriot\\",\\n    biography: \\"Massachusetts lawyer and passionate advocate for independence. He nominated Washington as commander-in-chief and was a key figure in the push for declaring independence from Britain.\\",\\n    contributions: [\\n      \\"Leading voice for independence in Continental Congress\\",\\n      \\"Helped draft the Declaration of Independence\\",\\n      \\"Negotiated crucial loans from the Dutch\\",\\n      \\"First Vice President and Second President\\"\\n    ]\\n  },\\n  {\\n    id: 5,\\n    name: \\"Alexander Hamilton\\",\\n    role: \\"Military Aide & First Treasury Secretary\\",\\n    side: \\"Patriot\\",\\n    biography: \\"Immigrant from the West Indies who became Washington's trusted aide-de-camp. After the war, he was instrumental in creating the federal financial system and writing the Federalist Papers.\\",\\n    contributions: [\\n      \\"Served as Washington's aide-de-camp\\",\\n      \\"Led charge at Battle of Yorktown\\",\\n      \\"First Secretary of the Treasury\\",\\n      \\"Principal author of the Federalist Papers\\"\\n    ]\\n  },\\n  {\\n    id: 6,\\n    name: \\"Marquis de Lafayette\\",\\n    role: \\"French General & American Ally\\",\\n    side: \\"French\\",\\n    biography: \\"Young French aristocrat who volunteered to serve in the Continental Army. He became a trusted general under Washington and played a key role in securing French support for the American cause.\\",\\n    contributions: [\\n      \\"Commanded American troops at several key battles\\",\\n      \\"Helped secure French military support\\",\\n      \\"Played crucial role at Yorktown\\",\\n      \\"Lifelong advocate for liberty and democracy\\"\\n    ]\\n  },\\n  {\\n    id: 7,\\n    name: \\"King George III\\",\\n    role: \\"British Monarch\\",\\n    side: \\"British\\",\\n    biography: \\"King of Great Britain during the American Revolution. His insistence on maintaining British authority over the colonies and his refusal to compromise contributed to the escalation of the conflict.\\",\\n    contributions: [\\n      \\"Refused to address colonial grievances\\",\\n      \\"Supported coercive policies against colonies\\",\\n      \\"Declared colonies in rebellion\\",\\n      \\"Ultimately recognized American independence\\"\\n    ]\\n  },\\n  {\\n    id: 8,\\n    name: \\"Benedict Arnold\\",\\n    role: \\"General (Turned Traitor)\\",\\n    side: \\"Patriot\\",\\n    biography: \\"Initially one of America's most talented generals, Arnold played a key role in the victory at Saratoga. However, feeling unappreciated and facing financial troubles, he famously betrayed his country by attempting to surrender West Point to the British.\\",\\n    contributions: [\\n      \\"Heroic leadership at Battle of Saratoga\\",\\n      \\"Critical victory at Fort Ticonderoga\\",\\n      \\"His treason became synonymous with betrayal\\",\\n      \\"Served British after defection\\"\\n    ]\\n  },\\n  {\\n    id: 9,\\n    name: \\"Thomas Paine\\",\\n    role: \\"Political Writer & Philosopher\\",\\n    side: \\"Patriot\\",\\n    biography: \\"English immigrant whose pamphlet 'Common Sense' (1776) made the case for independence in plain language that ordinary Americans could understand. His writing helped shift public opinion toward supporting independence.\\",\\n    contributions: [\\n      \\"Wrote 'Common Sense' advocating independence\\",\\n      \\"Authored 'The American Crisis' series\\",\\n      \\"Served in Continental Army\\",\\n      \\"Influenced public opinion toward revolution\\"\\n    ]\\n  },\\n  {\\n    id: 10,\\n    name: \\"General Cornwallis\\",\\n    role: \\"British General\\",\\n    side: \\"British\\",\\n    biography: \\"British general who led campaigns in the southern colonies. His surrender at Yorktown in 1781 effectively ended major combat operations and led to peace negotiations.\\",\\n    contributions: [\\n      \\"Led British forces in Southern Campaign\\",\\n      \\"Won several victories in the Carolinas\\",\\n      \\"Surrendered at Yorktown - turning point\\",\\n      \\"Later served as Governor-General of India\\"\\n    ]\\n  }\\n];\\n", "app/data/timeline.ts": "export interface TimelineEvent {\\n  id: number;\\n  year: string;\\n  title: string;\\n  description: string;\\n  category: \\"political\\" | \\"military\\" | \\"social\\";\\n}\\n\\nexport const timelineEvents: TimelineEvent[] = [\\n  {\\n    id: 1,\\n    year: \\"1765\\",\\n    title: \\"Stamp Act Passed\\",\\n    description: \\"British Parliament passes the Stamp Act, imposing the first direct tax on American colonists for all printed materials, sparking widespread protest and the cry of 'No taxation without representation!'\\",\\n    category: \\"political\\"\\n  },\\n  {\\n    id: 2,\\n    year: \\"1767\\",\\n    title: \\"Townshend Acts\\",\\n    description: \\"Britain imposes new taxes on imported goods including tea, glass, paper, and paint. Colonists respond with boycotts of British goods and the formation of the Sons of Liberty.\\",\\n    category: \\"political\\"\\n  },\\n  {\\n    id: 3,\\n    year: \\"1770\\",\\n    title: \\"Boston Massacre\\",\\n    description: \\"British soldiers fire into a crowd of colonists, killing five people including Crispus Attucks. This event becomes a powerful propaganda tool for Patriots and intensifies anti-British sentiment.\\",\\n    category: \\"social\\"\\n  },\\n  {\\n    id: 4,\\n    year: \\"1773\\",\\n    title: \\"Boston Tea Party\\",\\n    description: \\"Patriots disguised as Mohawk Indians dump 342 chests of British tea into Boston Harbor to protest the Tea Act. This act of defiance leads to the Coercive (Intolerable) Acts.\\",\\n    category: \\"political\\"\\n  },\\n  {\\n    id: 5,\\n    year: \\"1774\\",\\n    title: \\"Intolerable Acts\\",\\n    description: \\"Britain passes punitive laws against Massachusetts, closing Boston Harbor and revoking the Massachusetts charter. The First Continental Congress convenes to coordinate colonial response.\\",\\n    category: \\"political\\"\\n  },\\n  {\\n    id: 6,\\n    year: \\"1775\\",\\n    title: \\"Battles of Lexington and Concord\\",\\n    description: \\"British troops march to seize colonial weapons caches. Minutemen engage them at Lexington and Concord, marking the first military engagements of the Revolutionary War. 'The shot heard 'round the world.'\\",\\n    category: \\"military\\"\\n  },\\n  {\\n    id: 7,\\n    year: \\"1775\\",\\n    title: \\"Battle of Bunker Hill\\",\\n    description: \\"Although a British tactical victory, colonial forces inflict heavy casualties. The battle proves Americans can stand up to British regulars. Famous order: 'Don't fire until you see the whites of their eyes.'\\",\\n    category: \\"military\\"\\n  },\\n  {\\n    id: 8,\\n    year: \\"1776\\",\\n    title: \\"Declaration of Independence\\",\\n    description: \\"The Continental Congress adopts the Declaration of Independence, written primarily by Thomas Jefferson. It announces the colonies' separation from Britain and outlines the principles of natural rights.\\",\\n    category: \\"political\\"\\n  },\\n  {\\n    id: 9,\\n    year: \\"1776\\",\\n    title: \\"Battle of Trenton\\",\\n    description: \\"General Washington leads a daring Christmas night crossing of the Delaware River, surprising Hessian mercenaries at Trenton. This crucial victory boosts American morale and reinvigorates the cause.\\",\\n    category: \\"military\\"\\n  },\\n  {\\n    id: 10,\\n    year: \\"1777\\",\\n    title: \\"Battle of Saratoga\\",\\n    description: \\"American forces under Gates and Arnold defeat General Burgoyne's army. This decisive victory is considered the turning point of the war and convinces France to ally with the Americans.\\",\\n    category: \\"military\\"\\n  },\\n  {\\n    id: 11,\\n    year: \\"1778\\",\\n    title: \\"French Alliance\\",\\n    description: \\"France signs the Treaty of Alliance with the United States, providing crucial military and financial support. French navy and troops become essential to American victory.\\",\\n    category: \\"political\\"\\n  },\\n  {\\n    id: 12,\\n    year: \\"1781\\",\\n    title: \\"Battle of Yorktown\\",\\n    description: \\"Combined American and French forces, with the French navy blockading the Chesapeake, trap General Cornwallis's army at Yorktown. His surrender effectively ends major fighting in the war.\\",\\n    category: \\"military\\"\\n  },\\n  {\\n    id: 13,\\n    year: \\"1783\\",\\n    title: \\"Treaty of Paris\\",\\n    description: \\"Britain formally recognizes American independence in the Treaty of Paris. The United States gains territory from the Atlantic to the Mississippi River, establishing the new nation's boundaries.\\",\\n    category: \\"political\\"\\n  },\\n  {\\n    id: 14,\\n    year: \\"1787\\",\\n    title: \\"Constitutional Convention\\",\\n    description: \\"Delegates from 12 states meet in Philadelphia to draft a new framework of government. The resulting Constitution creates a federal system with checks and balances, replacing the weak Articles of Confederation.\\",\\n    category: \\"political\\"\\n  },\\n  {\\n    id: 15,\\n    year: \\"1791\\",\\n    title: \\"Bill of Rights Ratified\\",\\n    description: \\"The first ten amendments to the Constitution are ratified, protecting fundamental rights including freedom of speech, religion, and the press, as well as rights to bear arms and fair legal proceedings.\\",\\n    category: \\"political\\"\\n  }\\n];\\n", "app/data/flashcards.ts": "export interface Flashcard {\\n  id: number;\\n  question: string;\\n  answer: string;\\n  category: string;\\n}\\n\\nexport const flashcards: Flashcard[] = [\\n  {\\n    id: 1,\\n    question: \\"What was the Stamp Act of 1765?\\",\\n    answer: \\"A British law that imposed a direct tax on all printed materials in the American colonies, including newspapers, legal documents, and playing cards. It was the first internal tax levied directly on American colonists by the British Parliament.\\",\\n    category: \\"Causes\\"\\n  },\\n  {\\n    id: 2,\\n    question: \\"What does 'No taxation without representation' mean?\\",\\n    answer: \\"A slogan that summarized a primary grievance of the American colonists: they believed they should not be taxed by a government in which they had no elected representatives. This principle became a rallying cry against British taxation policies.\\",\\n    category: \\"Causes\\"\\n  },\\n  {\\n    id: 3,\\n    question: \\"What was the Boston Tea Party?\\",\\n    answer: \\"On December 16, 1773, American colonists disguised as Mohawk Indians dumped 342 chests of British tea into Boston Harbor to protest the Tea Act and British taxation policies. This act of defiance led to the Intolerable Acts.\\",\\n    category: \\"Events\\"\\n  },\\n  {\\n    id: 4,\\n    question: \\"What were the Intolerable Acts?\\",\\n    answer: \\"A series of punitive laws passed by Britain in 1774 in response to the Boston Tea Party. They closed Boston Harbor, revoked Massachusetts' charter, and allowed British officials to be tried in Britain. They unified the colonies against Britain.\\",\\n    category: \\"Causes\\"\\n  },\\n  {\\n    id: 5,\\n    question: \\"What happened at Lexington and Concord?\\",\\n    answer: \\"On April 19, 1775, British troops marched to seize colonial weapons caches. Minutemen engaged them in the first military battles of the Revolutionary War. This 'shot heard 'round the world' marked the beginning of armed conflict.\\",\\n    category: \\"Events\\"\\n  },\\n  {\\n    id: 6,\\n    question: \\"Why was the Battle of Saratoga significant?\\",\\n    answer: \\"The American victory at Saratoga in 1777 was the turning point of the war. It convinced France that the Americans could win, leading to the French alliance in 1778, which provided crucial military and financial support.\\",\\n    category: \\"Battles\\"\\n  },\\n  {\\n    id: 7,\\n    question: \\"What is the significance of July 4, 1776?\\",\\n    answer: \\"The Continental Congress adopted the Declaration of Independence on July 4, 1776, announcing the colonies' separation from Britain. This date is celebrated as America's Independence Day.\\",\\n    category: \\"Events\\"\\n  },\\n  {\\n    id: 8,\\n    question: \\"Who wrote the Declaration of Independence?\\",\\n    answer: \\"Thomas Jefferson was the principal author of the Declaration of Independence, with input from a committee including John Adams, Benjamin Franklin, Roger Sherman, and Robert Livingston.\\",\\n    category: \\"Documents\\"\\n  },\\n  {\\n    id: 9,\\n    question: \\"What were the main ideas in the Declaration of Independence?\\",\\n    answer: \\"The Declaration stated that all men are created equal with unalienable rights (life, liberty, pursuit of happiness), that governments derive their power from the consent of the governed, and that people have the right to overthrow tyrannical governments.\\",\\n    category: \\"Documents\\"\\n  },\\n  {\\n    id: 10,\\n    question: \\"What was the significance of the Battle of Yorktown?\\",\\n    answer: \\"In 1781, American and French forces trapped General Cornwallis's army at Yorktown, Virginia. His surrender effectively ended major fighting in the Revolutionary War and led to peace negotiations.\\",\\n    category: \\"Battles\\"\\n  },\\n  {\\n    id: 11,\\n    question: \\"What did the Treaty of Paris (1783) accomplish?\\",\\n    answer: \\"The Treaty of Paris officially ended the Revolutionary War. Britain recognized American independence and agreed to withdraw all troops. The United States gained territory from the Atlantic Ocean to the Mississippi River.\\",\\n    category: \\"Documents\\"\\n  },\\n  {\\n    id: 12,\\n    question: \\"Why was French support crucial to American victory?\\",\\n    answer: \\"France provided essential military support including troops, naval power, weapons, and financial aid. The French navy's blockade at Yorktown was decisive in trapping Cornwallis's army, leading to his surrender.\\",\\n    category: \\"Allies\\"\\n  },\\n  {\\n    id: 13,\\n    question: \\"What was the Continental Army?\\",\\n    answer: \\"The military force established by the Continental Congress to fight the British during the Revolutionary War. It was commanded by George Washington and consisted of soldiers from all 13 colonies.\\",\\n    category: \\"Military\\"\\n  },\\n  {\\n    id: 14,\\n    question: \\"Who were the Minutemen?\\",\\n    answer: \\"Colonial militia members who were ready to fight 'at a minute's notice.' They played a key role in the early battles of the Revolution, particularly at Lexington and Concord.\\",\\n    category: \\"Military\\"\\n  },\\n  {\\n    id: 15,\\n    question: \\"What was the significance of Common Sense?\\",\\n    answer: \\"Thomas Paine's 1776 pamphlet 'Common Sense' argued passionately for American independence from Britain. Written in plain language, it reached a wide audience and helped shift public opinion toward supporting independence.\\",\\n    category: \\"Documents\\"\\n  },\\n  {\\n    id: 16,\\n    question: \\"What was the Articles of Confederation?\\",\\n    answer: \\"The first constitution of the United States (1781-1789). It created a weak central government with no power to tax or regulate commerce. Its weaknesses led to the Constitutional Convention of 1787.\\",\\n    category: \\"Documents\\"\\n  },\\n  {\\n    id: 17,\\n    question: \\"What is the Bill of Rights?\\",\\n    answer: \\"The first ten amendments to the U.S. Constitution, ratified in 1791. They protect fundamental rights including freedom of speech, religion, and press; the right to bear arms; and rights of the accused.\\",\\n    category: \\"Documents\\"\\n  },\\n  {\\n    id: 18,\\n    question: \\"What was the Boston Massacre?\\",\\n    answer: \\"On March 5, 1770, British soldiers fired into a crowd of colonists, killing five people. Patriots used this event as propaganda to rally support against British occupation and policies.\\",\\n    category: \\"Events\\"\\n  },\\n  {\\n    id: 19,\\n    question: \\"What was the significance of Washington crossing the Delaware?\\",\\n    answer: \\"On Christmas night 1776, Washington led his troops across the icy Delaware River for a surprise attack on Hessian mercenaries at Trenton. This bold move resulted in a crucial victory that boosted American morale.\\",\\n    category: \\"Events\\"\\n  },\\n  {\\n    id: 20,\\n    question: \\"What were the Townshend Acts?\\",\\n    answer: \\"A series of laws passed in 1767 that imposed taxes on imported goods like tea, glass, paper, and paint. Colonists responded with boycotts, leading to increased tensions and eventually the Boston Massacre.\\",\\n    category: \\"Causes\\"\\n  }\\n];\\n"}	2026-03-13 17:54:36.74	2026-03-13 17:54:36.74	Created a comprehensive, interactive American Revolution study guide with 6 main sections: 1. **Overview** - Introduction to the American Revolution with key causes, major outcomes, quick facts, and study tips 2. **Timeline** - 15 chronological events from the Stamp Act (1765) to the Bill of Rights (1791) with visual timeline 3. **Key Figures** - 10 important people including George Washington, Thomas Jefferson, Benjamin Franklin, Benedict Arnold, and others with biographies and contributions 4. **Key Terms** - 20 essential vocabulary terms with definitions and significance, organized by category 5. **Flashcards** - 20 interactive flashcards with progress tracking, card navigation, and flip-to-reveal functionality 6. **Quiz** - 15 multiple-choice questions with instant feedback, explanations, and final score The study guide features a responsive design with a patriotic color scheme, tabbed navigation, progress indicators, and interactive elements using Shadcn UI components and Tailwind CSS.
e5ad4ad6-d937-43f8-9bf3-9644802ed954	3928c91d-35d9-4414-856e-49d0f4f6b295	https://3000-iaovuv911wj1go8q0mu33.e2b.app	Revolution Study Guide\n	{"app/page.tsx": "\\"use client\\";\\n\\nimport { useState } from \\"react\\";\\nimport { Tabs, TabsContent, TabsList, TabsTrigger } from \\"@/components/ui/tabs\\";\\nimport { Card, CardContent, CardDescription, CardHeader, CardTitle } from \\"@/components/ui/card\\";\\nimport { Badge } from \\"@/components/ui/badge\\";\\nimport { Progress } from \\"@/components/ui/progress\\";\\nimport { Button } from \\"@/components/ui/button\\";\\nimport { Accordion, AccordionContent, AccordionItem, AccordionTrigger } from \\"@/components/ui/accordion\\";\\nimport { BookOpen, Clock, Users, Lightbulb, Trophy, ChevronRight, RotateCcw, CheckCircle2, XCircle } from \\"lucide-react\\";\\nimport { timelineEvents } from \\"./data/timeline\\";\\nimport { keyFigures } from \\"./data/figures\\";\\nimport { flashcards, type Flashcard } from \\"./data/flashcards\\";\\nimport { quizQuestions, type QuizQuestion } from \\"./data/quiz\\";\\nimport { keyTerms } from \\"./data/terms\\";\\nimport { ThemeToggle } from \\"./components/theme-toggle\\";\\n\\nexport default function StudyGuidePage() {\\n  const [currentFlashcard, setCurrentFlashcard] = useState(0);\\n  const [showAnswer, setShowAnswer] = useState(false);\\n  const [studiedCards, setStudiedCards] = useState<Set<number>>(new Set());\\n  \\n  const [currentQuiz, setCurrentQuiz] = useState(0);\\n  const [selectedAnswer, setSelectedAnswer] = useState<number | null>(null);\\n  const [showQuizResult, setShowQuizResult] = useState(false);\\n  const [score, setScore] = useState(0);\\n  const [quizCompleted, setQuizCompleted] = useState(false);\\n  const [answeredQuestions, setAnsweredQuestions] = useState<Set<number>>(new Set());\\n\\n  const handleNextFlashcard = () => {\\n    setShowAnswer(false);\\n    setCurrentFlashcard((prev) => (prev + 1) % flashcards.length);\\n  };\\n\\n  const handlePrevFlashcard = () => {\\n    setShowAnswer(false);\\n    setCurrentFlashcard((prev) => (prev - 1 + flashcards.length) % flashcards.length);\\n  };\\n\\n  const handleShowAnswer = () => {\\n    setShowAnswer(true);\\n    setStudiedCards((prev) => new Set([...prev, currentFlashcard]));\\n  };\\n\\n  const handleAnswerSelect = (answerIndex: number) => {\\n    if (showQuizResult) return;\\n    setSelectedAnswer(answerIndex);\\n  };\\n\\n  const handleCheckAnswer = () => {\\n    if (selectedAnswer === null) return;\\n    setShowQuizResult(true);\\n    if (selectedAnswer === quizQuestions[currentQuiz].correctAnswer) {\\n      setScore((prev) => prev + 1);\\n    }\\n    setAnsweredQuestions((prev) => new Set([...prev, currentQuiz]));\\n  };\\n\\n  const handleNextQuestion = () => {\\n    if (currentQuiz === quizQuestions.length - 1) {\\n      setQuizCompleted(true);\\n    } else {\\n      setCurrentQuiz((prev) => prev + 1);\\n      setSelectedAnswer(null);\\n      setShowQuizResult(false);\\n    }\\n  };\\n\\n  const handleRestartQuiz = () => {\\n    setCurrentQuiz(0);\\n    setSelectedAnswer(null);\\n    setShowQuizResult(false);\\n    setScore(0);\\n    setQuizCompleted(false);\\n    setAnsweredQuestions(new Set());\\n  };\\n\\n  const flashcardProgress = (studiedCards.size / flashcards.length) * 100;\\n\\n  return (\\n    <div className=\\"min-h-screen bg-gradient-to-b from-amber-50 to-orange-50 dark:from-slate-950 dark:to-slate-900\\">\\n      {/* Header */}\\n      <header className=\\"bg-gradient-to-r from-red-800 via-red-700 to-blue-900 text-white py-8 px-4 shadow-lg\\">\\n        <div className=\\"max-w-6xl mx-auto\\">\\n          <div className=\\"flex items-center justify-between gap-3 mb-2\\">\\n            <div className=\\"flex items-center gap-3\\">\\n              <span className=\\"text-4xl\\">📜</span>\\n              <h1 className=\\"text-3xl md:text-4xl font-bold\\">American Revolution Study Guide</h1>\\n            </div>\\n            <ThemeToggle />\\n          </div>\\n          <p className=\\"text-amber-100 text-lg mt-2\\">Your comprehensive guide to understanding America's fight for independence (1765-1783)</p>\\n        </div>\\n      </header>\\n\\n      {/* Main Content */}\\n      <main className=\\"max-w-6xl mx-auto px-4 py-8\\">\\n        <Tabs defaultValue=\\"overview\\" className=\\"space-y-6\\">\\n          <TabsList className=\\"grid w-full grid-cols-2 md:grid-cols-6 gap-2 h-auto p-1\\">\\n            <TabsTrigger value=\\"overview\\" className=\\"flex items-center gap-2 py-2\\">\\n              <BookOpen className=\\"w-4 h-4\\" />\\n              <span className=\\"hidden sm:inline\\">Overview</span>\\n            </TabsTrigger>\\n            <TabsTrigger value=\\"timeline\\" className=\\"flex items-center gap-2 py-2\\">\\n              <Clock className=\\"w-4 h-4\\" />\\n              <span className=\\"hidden sm:inline\\">Timeline</span>\\n            </TabsTrigger>\\n            <TabsTrigger value=\\"figures\\" className=\\"flex items-center gap-2 py-2\\">\\n              <Users className=\\"w-4 h-4\\" />\\n              <span className=\\"hidden sm:inline\\">Figures</span>\\n            </TabsTrigger>\\n            <TabsTrigger value=\\"terms\\" className=\\"flex items-center gap-2 py-2\\">\\n              <Lightbulb className=\\"w-4 h-4\\" />\\n              <span className=\\"hidden sm:inline\\">Key Terms</span>\\n            </TabsTrigger>\\n            <TabsTrigger value=\\"flashcards\\" className=\\"flex items-center gap-2 py-2\\">\\n              <BookOpen className=\\"w-4 h-4\\" />\\n              <span className=\\"hidden sm:inline\\">Flashcards</span>\\n            </TabsTrigger>\\n            <TabsTrigger value=\\"quiz\\" className=\\"flex items-center gap-2 py-2\\">\\n              <Trophy className=\\"w-4 h-4\\" />\\n              <span className=\\"hidden sm:inline\\">Quiz</span>\\n            </TabsTrigger>\\n          </TabsList>\\n\\n          {/* Overview Tab */}\\n          <TabsContent value=\\"overview\\" className=\\"space-y-6\\">\\n            <Card className=\\"border-2 border-amber-200 dark:border-amber-800\\">\\n              <CardHeader>\\n                <CardTitle className=\\"text-2xl flex items-center gap-2\\">\\n                  <span>🏛️</span> Introduction to the American Revolution\\n                </CardTitle>\\n                <CardDescription className=\\"text-base\\">\\n                  The American Revolution (1765-1783) was a political and military rebellion in which thirteen of Great Britain's North American colonies rejected its rule, established the United States, and founded a new nation.\\n                </CardDescription>\\n              </CardHeader>\\n              <CardContent className=\\"space-y-6\\">\\n                <div className=\\"grid md:grid-cols-2 gap-6\\">\\n                  <div className=\\"space-y-4\\">\\n                    <h3 className=\\"font-semibold text-lg flex items-center gap-2\\">\\n                      <span>🎯</span> Key Causes\\n                    </h3>\\n                    <ul className=\\"space-y-2\\">\\n                      <li className=\\"flex items-start gap-2\\">\\n                        <ChevronRight className=\\"w-4 h-4 mt-1 text-red-600\\" />\\n                        <span><strong>Taxation without Representation:</strong> Britain imposed taxes without colonial consent</span>\\n                      </li>\\n                      <li className=\\"flex items-start gap-2\\">\\n                        <ChevronRight className=\\"w-4 h-4 mt-1 text-red-600\\" />\\n                        <span><strong>Stamp Act (1765):</strong> First direct tax on colonists for printed materials</span>\\n                      </li>\\n                      <li className=\\"flex items-start gap-2\\">\\n                        <ChevronRight className=\\"w-4 h-4 mt-1 text-red-600\\" />\\n                        <span><strong>Townshend Acts (1767):</strong> Taxes on imported goods, led to boycotts</span>\\n                      </li>\\n                      <li className=\\"flex items-start gap-2\\">\\n                        <ChevronRight className=\\"w-4 h-4 mt-1 text-red-600\\" />\\n                        <span><strong>Boston Massacre (1770):</strong> British soldiers killed five colonists</span>\\n                      </li>\\n                      <li className=\\"flex items-start gap-2\\">\\n                        <ChevronRight className=\\"w-4 h-4 mt-1 text-red-600\\" />\\n                        <span><strong>Intolerable Acts (1774):</strong> Punitive laws after Boston Tea Party</span>\\n                      </li>\\n                    </ul>\\n                  </div>\\n                  <div className=\\"space-y-4\\">\\n                    <h3 className=\\"font-semibold text-lg flex items-center gap-2\\">\\n                      <span>⚔️</span> Major Outcomes\\n                    </h3>\\n                    <ul className=\\"space-y-2\\">\\n                      <li className=\\"flex items-start gap-2\\">\\n                        <ChevronRight className=\\"w-4 h-4 mt-1 text-blue-600\\" />\\n                        <span><strong>Independence:</strong> 13 colonies became the United States of America</span>\\n                      </li>\\n                      <li className=\\"flex items-start gap-2\\">\\n                        <ChevronRight className=\\"w-4 h-4 mt-1 text-blue-600\\" />\\n                        <span><strong>Declaration of Independence:</strong> Adopted July 4, 1776</span>\\n                      </li>\\n                      <li className=\\"flex items-start gap-2\\">\\n                        <ChevronRight className=\\"w-4 h-4 mt-1 text-blue-600\\" />\\n                        <span><strong>Treaty of Paris (1783):</strong> Britain recognized US independence</span>\\n                      </li>\\n                      <li className=\\"flex items-start gap-2\\">\\n                        <ChevronRight className=\\"w-4 h-4 mt-1 text-blue-600\\" />\\n                        <span><strong>Constitution (1787):</strong> Framework for new government</span>\\n                      </li>\\n                      <li className=\\"flex items-start gap-2\\">\\n                        <ChevronRight className=\\"w-4 h-4 mt-1 text-blue-600\\" />\\n                        <span><strong>Bill of Rights (1791):</strong> First 10 amendments protecting liberties</span>\\n                      </li>\\n                    </ul>\\n                  </div>\\n                </div>\\n\\n                <div className=\\"bg-amber-100 dark:bg-amber-900/30 p-4 rounded-lg border border-amber-300 dark:border-amber-700\\">\\n                  <h4 className=\\"font-semibold mb-2 flex items-center gap-2\\">\\n                    <span>💡</span> Quick Facts\\n                  </h4>\\n                  <div className=\\"grid sm:grid-cols-3 gap-4 text-sm\\">\\n                    <div><strong>Duration:</strong> 1775-1783 (8 years)</div>\\n                    <div><strong>Colonies Involved:</strong> 13</div>\\n                    <div><strong>First President:</strong> George Washington (1789)</div>\\n                  </div>\\n                </div>\\n              </CardContent>\\n            </Card>\\n\\n            {/* Study Tips */}\\n            <Card>\\n              <CardHeader>\\n                <CardTitle className=\\"text-xl flex items-center gap-2\\">\\n                  <span>📚</span> How to Use This Study Guide\\n                </CardTitle>\\n              </CardHeader>\\n              <CardContent>\\n                <div className=\\"grid sm:grid-cols-2 lg:grid-cols-3 gap-4\\">\\n                  <div className=\\"p-4 bg-blue-50 dark:bg-blue-900/20 rounded-lg\\">\\n                    <h4 className=\\"font-semibold mb-2\\">1. Timeline</h4>\\n                    <p className=\\"text-sm text-muted-foreground\\">Study events chronologically to understand cause and effect relationships.</p>\\n                  </div>\\n                  <div className=\\"p-4 bg-green-50 dark:bg-green-900/20 rounded-lg\\">\\n                    <h4 className=\\"font-semibold mb-2\\">2. Key Figures</h4>\\n                    <p className=\\"text-sm text-muted-foreground\\">Learn about important people and their roles in the revolution.</p>\\n                  </div>\\n                  <div className=\\"p-4 bg-purple-50 dark:bg-purple-900/20 rounded-lg\\">\\n                    <h4 className=\\"font-semibold mb-2\\">3. Flashcards</h4>\\n                    <p className=\\"text-sm text-muted-foreground\\">Test your memory with interactive flashcards.</p>\\n                  </div>\\n                  <div className=\\"p-4 bg-amber-50 dark:bg-amber-900/20 rounded-lg\\">\\n                    <h4 className=\\"font-semibold mb-2\\">4. Key Terms</h4>\\n                    <p className=\\"text-sm text-muted-foreground\\">Master important vocabulary and concepts.</p>\\n                  </div>\\n                  <div className=\\"p-4 bg-red-50 dark:bg-red-900/20 rounded-lg\\">\\n                    <h4 className=\\"font-semibold mb-2\\">5. Quiz</h4>\\n                    <p className=\\"text-sm text-muted-foreground\\">Test your knowledge with multiple-choice questions.</p>\\n                  </div>\\n                  <div className=\\"p-4 bg-teal-50 dark:bg-teal-900/20 rounded-lg\\">\\n                    <h4 className=\\"font-semibold mb-2\\">6. Review</h4>\\n                    <p className=\\"text-sm text-muted-foreground\\">Return to areas where you need more practice.</p>\\n                  </div>\\n                </div>\\n              </CardContent>\\n            </Card>\\n          </TabsContent>\\n\\n          {/* Timeline Tab */}\\n          <TabsContent value=\\"timeline\\" className=\\"space-y-6\\">\\n            <Card>\\n              <CardHeader>\\n                <CardTitle className=\\"text-2xl flex items-center gap-2\\">\\n                  <span>📅</span> Timeline of Key Events\\n                </CardTitle>\\n                <CardDescription>\\n                  Follow the path from colonial unrest to American independence\\n                </CardDescription>\\n              </CardHeader>\\n              <CardContent>\\n                <div className=\\"relative\\">\\n                  {/* Timeline line */}\\n                  <div className=\\"absolute left-4 md:left-1/2 top-0 bottom-0 w-0.5 bg-gradient-to-b from-red-600 via-blue-600 to-amber-600\\" />\\n                  \\n                  <div className=\\"space-y-8\\">\\n                    {timelineEvents.map((event, index) => (\\n                      <div\\n                        key={event.id}\\n                        className={`relative flex items-start gap-4 ${\\n                          index % 2 === 0 ? \\"md:flex-row\\" : \\"md:flex-row-reverse\\"\\n                        }`}\\n                      >\\n                        {/* Timeline dot */}\\n                        <div className=\\"absolute left-4 md:left-1/2 -translate-x-1/2 w-4 h-4 bg-white dark:bg-slate-900 border-4 border-red-600 rounded-full z-10\\" />\\n                        \\n                        {/* Content */}\\n                        <div className={`ml-12 md:ml-0 md:w-1/2 ${index % 2 === 0 ? \\"md:pr-12 md:text-right\\" : \\"md:pl-12\\"}`}>\\n                          <Badge variant={event.category === \\"military\\" ? \\"destructive\\" : event.category === \\"political\\" ? \\"default\\" : \\"secondary\\"} className=\\"mb-2\\">\\n                            {event.year}\\n                          </Badge>\\n                          <h3 className=\\"font-semibold text-lg\\">{event.title}</h3>\\n                          <p className=\\"text-muted-foreground mt-1\\">{event.description}</p>\\n                        </div>\\n                      </div>\\n                    ))}\\n                  </div>\\n                </div>\\n              </CardContent>\\n            </Card>\\n          </TabsContent>\\n\\n          {/* Key Figures Tab */}\\n          <TabsContent value=\\"figures\\" className=\\"space-y-6\\">\\n            <Card>\\n              <CardHeader>\\n                <CardTitle className=\\"text-2xl flex items-center gap-2\\">\\n                  <span>👥</span> Key Figures of the Revolution\\n                </CardTitle>\\n                <CardDescription>\\n                  Learn about the important people who shaped American independence\\n                </CardDescription>\\n              </CardHeader>\\n              <CardContent>\\n                <div className=\\"grid md:grid-cols-2 gap-6\\">\\n                  {keyFigures.map((figure) => (\\n                    <Card key={figure.id} className=\\"overflow-hidden\\">\\n                      <div className=\\"h-2 bg-gradient-to-r from-red-600 to-blue-600\\" />\\n                      <CardHeader>\\n                        <div className=\\"flex items-start justify-between\\">\\n                          <div>\\n                            <CardTitle className=\\"text-lg\\">{figure.name}</CardTitle>\\n                            <CardDescription>{figure.role}</CardDescription>\\n                          </div>\\n                          <Badge variant={figure.side === \\"Patriot\\" ? \\"default\\" : \\"secondary\\"}>\\n                            {figure.side}\\n                          </Badge>\\n                        </div>\\n                      </CardHeader>\\n                      <CardContent>\\n                        <p className=\\"text-sm text-muted-foreground mb-3\\">{figure.biography}</p>\\n                        <div className=\\"space-y-2\\">\\n                          <h4 className=\\"font-semibold text-sm\\">Key Contributions:</h4>\\n                          <ul className=\\"text-sm space-y-1\\">\\n                            {figure.contributions.map((contribution, i) => (\\n                              <li key={i} className=\\"flex items-start gap-2\\">\\n                                <CheckCircle2 className=\\"w-4 h-4 mt-0.5 text-green-600\\" />\\n                                <span>{contribution}</span>\\n                              </li>\\n                            ))}\\n                          </ul>\\n                        </div>\\n                      </CardContent>\\n                    </Card>\\n                  ))}\\n                </div>\\n              </CardContent>\\n            </Card>\\n          </TabsContent>\\n\\n          {/* Key Terms Tab */}\\n          <TabsContent value=\\"terms\\" className=\\"space-y-6\\">\\n            <Card>\\n              <CardHeader>\\n                <CardTitle className=\\"text-2xl flex items-center gap-2\\">\\n                  <span>📖</span> Key Terms & Definitions\\n                </CardTitle>\\n                <CardDescription>\\n                  Master the essential vocabulary of the American Revolution\\n                </CardDescription>\\n              </CardHeader>\\n              <CardContent>\\n                <Accordion type=\\"single\\" collapsible className=\\"w-full\\">\\n                  {keyTerms.map((term) => (\\n                    <AccordionItem key={term.id} value={`term-${term.id}`}>\\n                      <AccordionTrigger className=\\"text-left\\">\\n                        <div className=\\"flex items-center gap-3\\">\\n                          <Badge variant=\\"outline\\" className=\\"shrink-0\\">{term.category}</Badge>\\n                          <span className=\\"font-semibold\\">{term.term}</span>\\n                        </div>\\n                      </AccordionTrigger>\\n                      <AccordionContent>\\n                        <div className=\\"pl-4 space-y-2\\">\\n                          <p className=\\"text-muted-foreground\\">{term.definition}</p>\\n                          {term.significance && (\\n                            <p className=\\"text-sm\\"><strong>Significance:</strong> {term.significance}</p>\\n                          )}\\n                        </div>\\n                      </AccordionContent>\\n                    </AccordionItem>\\n                  ))}\\n                </Accordion>\\n              </CardContent>\\n            </Card>\\n          </TabsContent>\\n\\n          {/* Flashcards Tab */}\\n          <TabsContent value=\\"flashcards\\" className=\\"space-y-6\\">\\n            <Card>\\n              <CardHeader>\\n                <CardTitle className=\\"text-2xl flex items-center gap-2\\">\\n                  <span>🃏</span> Interactive Flashcards\\n                </CardTitle>\\n                <CardDescription>\\n                  Click to reveal answers and test your knowledge\\n                </CardDescription>\\n              </CardHeader>\\n              <CardContent className=\\"space-y-6\\">\\n                {/* Progress */}\\n                <div className=\\"space-y-2\\">\\n                  <div className=\\"flex justify-between text-sm\\">\\n                    <span>Progress: {studiedCards.size} / {flashcards.length} cards studied</span>\\n                    <span>{Math.round(flashcardProgress)}%</span>\\n                  </div>\\n                  <Progress value={flashcardProgress} />\\n                </div>\\n\\n                {/* Flashcard */}\\n                <div\\n                  className={`relative min-h-[300px] p-8 rounded-xl border-2 cursor-pointer transition-all duration-300 ${\\n                    showAnswer\\n                      ? \\"bg-blue-50 dark:bg-blue-900/20 border-blue-300 dark:border-blue-700\\"\\n                      : \\"bg-amber-50 dark:bg-amber-900/20 border-amber-300 dark:border-amber-700\\"\\n                  }`}\\n                  onClick={() => !showAnswer && handleShowAnswer()}\\n                >\\n                  <div className=\\"absolute top-4 left-4\\">\\n                    <Badge variant={showAnswer ? \\"default\\" : \\"secondary\\"}>\\n                      {showAnswer ? \\"Answer\\" : \\"Question\\"}\\n                    </Badge>\\n                  </div>\\n                  <div className=\\"absolute top-4 right-4 text-sm text-muted-foreground\\">\\n                    Card {currentFlashcard + 1} of {flashcards.length}\\n                  </div>\\n                  \\n                  <div className=\\"flex items-center justify-center min-h-[200px]\\">\\n                    <p className=\\"text-xl text-center font-medium\\">\\n                      {showAnswer ? flashcards[currentFlashcard].answer : flashcards[currentFlashcard].question}\\n                    </p>\\n                  </div>\\n\\n                  {!showAnswer && (\\n                    <p className=\\"absolute bottom-4 left-1/2 -translate-x-1/2 text-sm text-muted-foreground\\">\\n                      Click to reveal answer\\n                    </p>\\n                  )}\\n                </div>\\n\\n                {/* Controls */}\\n                <div className=\\"flex justify-center gap-4\\">\\n                  <Button variant=\\"outline\\" onClick={handlePrevFlashcard}>\\n                    ← Previous\\n                  </Button>\\n                  {!showAnswer ? (\\n                    <Button onClick={handleShowAnswer}>Show Answer</Button>\\n                  ) : (\\n                    <Button onClick={handleNextFlashcard}>Next Card →</Button>\\n                  )}\\n                </div>\\n\\n                {/* Card Navigation */}\\n                <div className=\\"flex flex-wrap justify-center gap-2\\">\\n                  {flashcards.map((_, index) => (\\n                    <button\\n                      key={index}\\n                      onClick={() => {\\n                        setCurrentFlashcard(index);\\n                        setShowAnswer(false);\\n                      }}\\n                      className={`w-8 h-8 rounded-full text-sm font-medium transition-all ${\\n                        index === currentFlashcard\\n                          ? \\"bg-primary text-primary-foreground\\"\\n                          : studiedCards.has(index)\\n                          ? \\"bg-green-100 dark:bg-green-900/30 text-green-700 dark:text-green-300 border border-green-300\\"\\n                          : \\"bg-gray-100 dark:bg-gray-800 text-gray-600 dark:text-gray-400 hover:bg-gray-200 dark:hover:bg-gray-700\\"\\n                      }`}\\n                    >\\n                      {index + 1}\\n                    </button>\\n                  ))}\\n                </div>\\n              </CardContent>\\n            </Card>\\n          </TabsContent>\\n\\n          {/* Quiz Tab */}\\n          <TabsContent value=\\"quiz\\" className=\\"space-y-6\\">\\n            <Card>\\n              <CardHeader>\\n                <CardTitle className=\\"text-2xl flex items-center gap-2\\">\\n                  <span>🎯</span> Test Your Knowledge\\n                </CardTitle>\\n                <CardDescription>\\n                  Answer these questions to check your understanding\\n                </CardDescription>\\n              </CardHeader>\\n              <CardContent className=\\"space-y-6\\">\\n                {!quizCompleted ? (\\n                  <>\\n                    {/* Progress */}\\n                    <div className=\\"space-y-2\\">\\n                      <div className=\\"flex justify-between text-sm\\">\\n                        <span>Question {currentQuiz + 1} of {quizQuestions.length}</span>\\n                        <span>Score: {score}/{answeredQuestions.size}</span>\\n                      </div>\\n                      <Progress value={((currentQuiz + 1) / quizQuestions.length) * 100} />\\n                    </div>\\n\\n                    {/* Question */}\\n                    <div className=\\"p-6 bg-gray-50 dark:bg-gray-800/50 rounded-lg\\">\\n                      <p className=\\"text-lg font-medium mb-4\\">\\n                        {quizQuestions[currentQuiz].question}\\n                      </p>\\n                      \\n                      <div className=\\"space-y-3\\">\\n                        {quizQuestions[currentQuiz].options.map((option, index) => (\\n                          <button\\n                            key={index}\\n                            onClick={() => handleAnswerSelect(index)}\\n                            disabled={showQuizResult}\\n                            className={`w-full p-4 text-left rounded-lg border-2 transition-all ${\\n                              selectedAnswer === index\\n                                ? showQuizResult\\n                                  ? index === quizQuestions[currentQuiz].correctAnswer\\n                                    ? \\"border-green-500 bg-green-50 dark:bg-green-900/30\\"\\n                                    : \\"border-red-500 bg-red-50 dark:bg-red-900/30\\"\\n                                  : \\"border-primary bg-primary/10\\"\\n                                : showQuizResult && index === quizQuestions[currentQuiz].correctAnswer\\n                                ? \\"border-green-500 bg-green-50 dark:bg-green-900/30\\"\\n                                : \\"border-gray-200 dark:border-gray-700 hover:border-gray-300 dark:hover:border-gray-600\\"\\n                            }`}\\n                          >\\n                            <div className=\\"flex items-center gap-3\\">\\n                              <span className={`w-8 h-8 rounded-full flex items-center justify-center text-sm font-medium ${\\n                                selectedAnswer === index\\n                                  ? showQuizResult\\n                                    ? index === quizQuestions[currentQuiz].correctAnswer\\n                                      ? \\"bg-green-500 text-white\\"\\n                                      : \\"bg-red-500 text-white\\"\\n                                    : \\"bg-primary text-primary-foreground\\"\\n                                  : showQuizResult && index === quizQuestions[currentQuiz].correctAnswer\\n                                  ? \\"bg-green-500 text-white\\"\\n                                  : \\"bg-gray-200 dark:bg-gray-700\\"\\n                              }`}>\\n                                {showQuizResult ? (\\n                                  index === quizQuestions[currentQuiz].correctAnswer ? (\\n                                    <CheckCircle2 className=\\"w-5 h-5\\" />\\n                                  ) : selectedAnswer === index ? (\\n                                    <XCircle className=\\"w-5 h-5\\" />\\n                                  ) : (\\n                                    String.fromCharCode(65 + index)\\n                                  )\\n                                ) : (\\n                                  String.fromCharCode(65 + index)\\n                                )}\\n                              </span>\\n                              <span>{option}</span>\\n                            </div>\\n                          </button>\\n                        ))}\\n                      </div>\\n                    </div>\\n\\n                    {/* Explanation */}\\n                    {showQuizResult && quizQuestions[currentQuiz].explanation && (\\n                      <div className=\\"p-4 bg-blue-50 dark:bg-blue-900/20 rounded-lg border border-blue-200 dark:border-blue-800\\">\\n                        <p className=\\"text-sm\\"><strong>Explanation:</strong> {quizQuestions[currentQuiz].explanation}</p>\\n                      </div>\\n                    )}\\n\\n                    {/* Controls */}\\n                    <div className=\\"flex justify-end gap-4\\">\\n                      {!showQuizResult ? (\\n                        <Button onClick={handleCheckAnswer} disabled={selectedAnswer === null}>\\n                          Check Answer\\n                        </Button>\\n                      ) : (\\n                        <Button onClick={handleNextQuestion}>\\n                          {currentQuiz === quizQuestions.length - 1 ? \\"See Results\\" : \\"Next Question\\"}\\n                        </Button>\\n                      )}\\n                    </div>\\n                  </>\\n                ) : (\\n                  /* Results */\\n                  <div className=\\"text-center py-8 space-y-6\\">\\n                    <div className=\\"text-6xl\\">🏆</div>\\n                    <h3 className=\\"text-2xl font-bold\\">Quiz Complete!</h3>\\n                    <div className=\\"text-4xl font-bold text-primary\\">\\n                      {score} / {quizQuestions.length}\\n                    </div>\\n                    <p className=\\"text-muted-foreground\\">\\n                      {score === quizQuestions.length\\n                        ? \\"Perfect score! You're a Revolution expert!\\"\\n                        : score >= quizQuestions.length * 0.7\\n                        ? \\"Great job! You have a solid understanding!\\"\\n                        : score >= quizQuestions.length * 0.5\\n                        ? \\"Good effort! Keep studying to improve!\\"\\n                        : \\"Keep practicing! Review the material and try again.\\"}\\n                    </p>\\n                    <div className=\\"flex justify-center gap-4\\">\\n                      <Button variant=\\"outline\\" onClick={handleRestartQuiz}>\\n                        <RotateCcw className=\\"w-4 h-4 mr-2\\" />\\n                        Try Again\\n                      </Button>\\n                    </div>\\n                  </div>\\n                )}\\n              </CardContent>\\n            </Card>\\n          </TabsContent>\\n        </Tabs>\\n      </main>\\n\\n      {/* Footer */}\\n      <footer className=\\"bg-slate-100 dark:bg-slate-900 py-6 px-4 mt-12 border-t\\">\\n        <div className=\\"max-w-6xl mx-auto text-center text-sm text-muted-foreground\\">\\n          <p>American Revolution Study Guide • Created for educational purposes</p>\\n          <p className=\\"mt-1\\">📚 Study hard, learn well, and ace your exam!</p>\\n        </div>\\n      </footer>\\n    </div>\\n  );\\n}\\n", "app/layout.tsx": "import type { Metadata } from \\"next\\";\\nimport { Geist, Geist_Mono } from \\"next/font/google\\";\\nimport \\"./globals.css\\";\\nimport { ThemeProvider } from \\"./providers/theme-provider\\";\\n\\nconst geistSans = Geist({\\n  variable: \\"--font-geist-sans\\",\\n  subsets: [\\"latin\\"],\\n});\\n\\nconst geistMono = Geist_Mono({\\n  variable: \\"--font-geist-mono\\",\\n  subsets: [\\"latin\\"],\\n});\\n\\nexport const metadata: Metadata = {\\n  title: \\"American Revolution Study Guide\\",\\n  description: \\"Your comprehensive guide to understanding America's fight for independence\\",\\n};\\n\\nexport default function RootLayout({\\n  children,\\n}: Readonly<{\\n  children: React.ReactNode;\\n}>) {\\n  return (\\n    <html lang=\\"en\\" suppressHydrationWarning>\\n      <body\\n        className={`${geistSans.variable} ${geistMono.variable} antialiased`}\\n      >\\n        <ThemeProvider defaultTheme=\\"system\\" storageKey=\\"study-guide-theme\\">\\n          {children}\\n        </ThemeProvider>\\n      </body>\\n    </html>\\n  );\\n}\\n", "app/components/theme-toggle.tsx": "\\"use client\\";\\n\\nimport { Moon, Sun } from \\"lucide-react\\";\\nimport { Button } from \\"@/components/ui/button\\";\\nimport { useTheme } from \\"../providers/theme-provider\\";\\n\\nexport function ThemeToggle() {\\n  const { theme, setTheme } = useTheme();\\n\\n  const toggleTheme = () => {\\n    if (theme === \\"light\\") {\\n      setTheme(\\"dark\\");\\n    } else if (theme === \\"dark\\") {\\n      setTheme(\\"light\\");\\n    } else {\\n      // If system, toggle to opposite of current system preference\\n      const isDark = window.matchMedia(\\"(prefers-color-scheme: dark)\\").matches;\\n      setTheme(isDark ? \\"light\\" : \\"dark\\");\\n    }\\n  };\\n\\n  return (\\n    <Button\\n      variant=\\"ghost\\"\\n      size=\\"icon\\"\\n      onClick={toggleTheme}\\n      className=\\"relative h-9 w-9\\"\\n    >\\n      <Sun className=\\"h-5 w-5 rotate-0 scale-100 transition-all dark:-rotate-90 dark:scale-0\\" />\\n      <Moon className=\\"absolute h-5 w-5 rotate-90 scale-0 transition-all dark:rotate-0 dark:scale-100\\" />\\n      <span className=\\"sr-only\\">Toggle theme</span>\\n    </Button>\\n  );\\n}\\n", "app/providers/theme-provider.tsx": "\\"use client\\";\\n\\nimport * as React from \\"react\\";\\nimport { createContext, useContext, useEffect, useState } from \\"react\\";\\n\\ntype Theme = \\"dark\\" | \\"light\\" | \\"system\\";\\n\\ntype ThemeProviderProps = {\\n  children: React.ReactNode;\\n  defaultTheme?: Theme;\\n  storageKey?: string;\\n};\\n\\ntype ThemeProviderState = {\\n  theme: Theme;\\n  setTheme: (theme: Theme) => void;\\n};\\n\\nconst initialState: ThemeProviderState = {\\n  theme: \\"system\\",\\n  setTheme: () => null,\\n};\\n\\nconst ThemeProviderContext = createContext<ThemeProviderState>(initialState);\\n\\nexport function ThemeProvider({\\n  children,\\n  defaultTheme = \\"system\\",\\n  storageKey = \\"study-guide-theme\\",\\n  ...props\\n}: ThemeProviderProps) {\\n  const [theme, setTheme] = useState<Theme>(defaultTheme);\\n\\n  useEffect(() => {\\n    const stored = localStorage.getItem(storageKey) as Theme | null;\\n    if (stored) {\\n      setTheme(stored);\\n    }\\n  }, [storageKey]);\\n\\n  useEffect(() => {\\n    const root = window.document.documentElement;\\n\\n    root.classList.remove(\\"light\\", \\"dark\\");\\n\\n    if (theme === \\"system\\") {\\n      const systemTheme = window.matchMedia(\\"(prefers-color-scheme: dark)\\")\\n        .matches\\n        ? \\"dark\\"\\n        : \\"light\\";\\n\\n      root.classList.add(systemTheme);\\n      return;\\n    }\\n\\n    root.classList.add(theme);\\n  }, [theme]);\\n\\n  const value = {\\n    theme,\\n    setTheme: (theme: Theme) => {\\n      localStorage.setItem(storageKey, theme);\\n      setTheme(theme);\\n    },\\n  };\\n\\n  return (\\n    <ThemeProviderContext.Provider {...props} value={value}>\\n      {children}\\n    </ThemeProviderContext.Provider>\\n  );\\n}\\n\\nexport const useTheme = () => {\\n  const context = useContext(ThemeProviderContext);\\n\\n  if (context === undefined)\\n    throw new Error(\\"useTheme must be used within a ThemeProvider\\");\\n\\n  return context;\\n};\\n"}	2026-03-13 19:48:18.041	2026-03-13 19:48:18.041	Added dark mode support to the American Revolution Study Guide by creating a ThemeProvider with localStorage persistence, a ThemeToggle component with sun/moon icons, and integrating it into the layout and header. The toggle allows users to switch between light and dark themes, with the preference saved and applied across sessions.
d1c4a0f1-5cba-4732-a8a7-7cbb55635fcd	b82861f8-73f8-477f-9452-f58d0bdebce8	https://3000-iaovuv911wj1go8q0mu33.e2b.app	Revolution Study Guide\n	{"app/page.tsx": "\\"use client\\";\\n\\nimport { useState } from \\"react\\";\\nimport { Tabs, TabsContent, TabsList, TabsTrigger } from \\"@/components/ui/tabs\\";\\nimport { Card, CardContent, CardDescription, CardHeader, CardTitle } from \\"@/components/ui/card\\";\\nimport { Badge } from \\"@/components/ui/badge\\";\\nimport { Progress } from \\"@/components/ui/progress\\";\\nimport { Button } from \\"@/components/ui/button\\";\\nimport { Accordion, AccordionContent, AccordionItem, AccordionTrigger } from \\"@/components/ui/accordion\\";\\nimport { BookOpen, Clock, Users, Lightbulb, Trophy, ChevronRight, RotateCcw, CheckCircle2, XCircle } from \\"lucide-react\\";\\nimport { timelineEvents } from \\"./data/timeline\\";\\nimport { keyFigures } from \\"./data/figures\\";\\nimport { flashcards, type Flashcard } from \\"./data/flashcards\\";\\nimport { quizQuestions, type QuizQuestion } from \\"./data/quiz\\";\\nimport { keyTerms } from \\"./data/terms\\";\\n\\nexport default function StudyGuidePage() {\\n  const [currentFlashcard, setCurrentFlashcard] = useState(0);\\n  const [showAnswer, setShowAnswer] = useState(false);\\n  const [studiedCards, setStudiedCards] = useState<Set<number>>(new Set());\\n  \\n  const [currentQuiz, setCurrentQuiz] = useState(0);\\n  const [selectedAnswer, setSelectedAnswer] = useState<number | null>(null);\\n  const [showQuizResult, setShowQuizResult] = useState(false);\\n  const [score, setScore] = useState(0);\\n  const [quizCompleted, setQuizCompleted] = useState(false);\\n  const [answeredQuestions, setAnsweredQuestions] = useState<Set<number>>(new Set());\\n\\n  const handleNextFlashcard = () => {\\n    setShowAnswer(false);\\n    setCurrentFlashcard((prev) => (prev + 1) % flashcards.length);\\n  };\\n\\n  const handlePrevFlashcard = () => {\\n    setShowAnswer(false);\\n    setCurrentFlashcard((prev) => (prev - 1 + flashcards.length) % flashcards.length);\\n  };\\n\\n  const handleShowAnswer = () => {\\n    setShowAnswer(true);\\n    setStudiedCards((prev) => new Set([...prev, currentFlashcard]));\\n  };\\n\\n  const handleAnswerSelect = (answerIndex: number) => {\\n    if (showQuizResult) return;\\n    setSelectedAnswer(answerIndex);\\n  };\\n\\n  const handleCheckAnswer = () => {\\n    if (selectedAnswer === null) return;\\n    setShowQuizResult(true);\\n    if (selectedAnswer === quizQuestions[currentQuiz].correctAnswer) {\\n      setScore((prev) => prev + 1);\\n    }\\n    setAnsweredQuestions((prev) => new Set([...prev, currentQuiz]));\\n  };\\n\\n  const handleNextQuestion = () => {\\n    if (currentQuiz === quizQuestions.length - 1) {\\n      setQuizCompleted(true);\\n    } else {\\n      setCurrentQuiz((prev) => prev + 1);\\n      setSelectedAnswer(null);\\n      setShowQuizResult(false);\\n    }\\n  };\\n\\n  const handleRestartQuiz = () => {\\n    setCurrentQuiz(0);\\n    setSelectedAnswer(null);\\n    setShowQuizResult(false);\\n    setScore(0);\\n    setQuizCompleted(false);\\n    setAnsweredQuestions(new Set());\\n  };\\n\\n  const flashcardProgress = (studiedCards.size / flashcards.length) * 100;\\n\\n  return (\\n    <div className=\\"min-h-screen bg-gradient-to-b from-amber-50 to-orange-50\\">\\n      {/* Header */}\\n      <header className=\\"bg-gradient-to-r from-red-800 via-red-700 to-blue-900 text-white py-8 px-4 shadow-lg\\">\\n        <div className=\\"max-w-6xl mx-auto\\">\\n          <div className=\\"flex items-center gap-3 mb-2\\">\\n            <span className=\\"text-4xl\\">📜</span>\\n            <h1 className=\\"text-3xl md:text-4xl font-bold\\">American Revolution Study Guide</h1>\\n          </div>\\n          <p className=\\"text-amber-100 text-lg mt-2\\">Your comprehensive guide to understanding America's fight for independence (1765-1783)</p>\\n        </div>\\n      </header>\\n\\n      {/* Main Content */}\\n      <main className=\\"max-w-6xl mx-auto px-4 py-8\\">\\n        <Tabs defaultValue=\\"overview\\" className=\\"space-y-6\\">\\n          <TabsList className=\\"grid w-full grid-cols-2 md:grid-cols-6 gap-2 h-auto p-1\\">\\n            <TabsTrigger value=\\"overview\\" className=\\"flex items-center gap-2 py-2\\">\\n              <BookOpen className=\\"w-4 h-4\\" />\\n              <span className=\\"hidden sm:inline\\">Overview</span>\\n            </TabsTrigger>\\n            <TabsTrigger value=\\"timeline\\" className=\\"flex items-center gap-2 py-2\\">\\n              <Clock className=\\"w-4 h-4\\" />\\n              <span className=\\"hidden sm:inline\\">Timeline</span>\\n            </TabsTrigger>\\n            <TabsTrigger value=\\"figures\\" className=\\"flex items-center gap-2 py-2\\">\\n              <Users className=\\"w-4 h-4\\" />\\n              <span className=\\"hidden sm:inline\\">Figures</span>\\n            </TabsTrigger>\\n            <TabsTrigger value=\\"terms\\" className=\\"flex items-center gap-2 py-2\\">\\n              <Lightbulb className=\\"w-4 h-4\\" />\\n              <span className=\\"hidden sm:inline\\">Key Terms</span>\\n            </TabsTrigger>\\n            <TabsTrigger value=\\"flashcards\\" className=\\"flex items-center gap-2 py-2\\">\\n              <BookOpen className=\\"w-4 h-4\\" />\\n              <span className=\\"hidden sm:inline\\">Flashcards</span>\\n            </TabsTrigger>\\n            <TabsTrigger value=\\"quiz\\" className=\\"flex items-center gap-2 py-2\\">\\n              <Trophy className=\\"w-4 h-4\\" />\\n              <span className=\\"hidden sm:inline\\">Quiz</span>\\n            </TabsTrigger>\\n          </TabsList>\\n\\n          {/* Overview Tab */}\\n          <TabsContent value=\\"overview\\" className=\\"space-y-6\\">\\n            <Card className=\\"border-2 border-amber-200\\">\\n              <CardHeader>\\n                <CardTitle className=\\"text-2xl flex items-center gap-2\\">\\n                  <span>🏛️</span> Introduction to the American Revolution\\n                </CardTitle>\\n                <CardDescription className=\\"text-base\\">\\n                  The American Revolution (1765-1783) was a political and military rebellion in which thirteen of Great Britain's North American colonies rejected its rule, established the United States, and founded a new nation.\\n                </CardDescription>\\n              </CardHeader>\\n              <CardContent className=\\"space-y-6\\">\\n                <div className=\\"grid md:grid-cols-2 gap-6\\">\\n                  <div className=\\"space-y-4\\">\\n                    <h3 className=\\"font-semibold text-lg flex items-center gap-2\\">\\n                      <span>🎯</span> Key Causes\\n                    </h3>\\n                    <ul className=\\"space-y-2\\">\\n                      <li className=\\"flex items-start gap-2\\">\\n                        <ChevronRight className=\\"w-4 h-4 mt-1 text-red-600\\" />\\n                        <span><strong>Taxation without Representation:</strong> Britain imposed taxes without colonial consent</span>\\n                      </li>\\n                      <li className=\\"flex items-start gap-2\\">\\n                        <ChevronRight className=\\"w-4 h-4 mt-1 text-red-600\\" />\\n                        <span><strong>Stamp Act (1765):</strong> First direct tax on colonists for printed materials</span>\\n                      </li>\\n                      <li className=\\"flex items-start gap-2\\">\\n                        <ChevronRight className=\\"w-4 h-4 mt-1 text-red-600\\" />\\n                        <span><strong>Townshend Acts (1767):</strong> Taxes on imported goods, led to boycotts</span>\\n                      </li>\\n                      <li className=\\"flex items-start gap-2\\">\\n                        <ChevronRight className=\\"w-4 h-4 mt-1 text-red-600\\" />\\n                        <span><strong>Boston Massacre (1770):</strong> British soldiers killed five colonists</span>\\n                      </li>\\n                      <li className=\\"flex items-start gap-2\\">\\n                        <ChevronRight className=\\"w-4 h-4 mt-1 text-red-600\\" />\\n                        <span><strong>Intolerable Acts (1774):</strong> Punitive laws after Boston Tea Party</span>\\n                      </li>\\n                    </ul>\\n                  </div>\\n                  <div className=\\"space-y-4\\">\\n                    <h3 className=\\"font-semibold text-lg flex items-center gap-2\\">\\n                      <span>⚔️</span> Major Outcomes\\n                    </h3>\\n                    <ul className=\\"space-y-2\\">\\n                      <li className=\\"flex items-start gap-2\\">\\n                        <ChevronRight className=\\"w-4 h-4 mt-1 text-blue-600\\" />\\n                        <span><strong>Independence:</strong> 13 colonies became the United States of America</span>\\n                      </li>\\n                      <li className=\\"flex items-start gap-2\\">\\n                        <ChevronRight className=\\"w-4 h-4 mt-1 text-blue-600\\" />\\n                        <span><strong>Declaration of Independence:</strong> Adopted July 4, 1776</span>\\n                      </li>\\n                      <li className=\\"flex items-start gap-2\\">\\n                        <ChevronRight className=\\"w-4 h-4 mt-1 text-blue-600\\" />\\n                        <span><strong>Treaty of Paris (1783):</strong> Britain recognized US independence</span>\\n                      </li>\\n                      <li className=\\"flex items-start gap-2\\">\\n                        <ChevronRight className=\\"w-4 h-4 mt-1 text-blue-600\\" />\\n                        <span><strong>Constitution (1787):</strong> Framework for new government</span>\\n                      </li>\\n                      <li className=\\"flex items-start gap-2\\">\\n                        <ChevronRight className=\\"w-4 h-4 mt-1 text-blue-600\\" />\\n                        <span><strong>Bill of Rights (1791):</strong> First 10 amendments protecting liberties</span>\\n                      </li>\\n                    </ul>\\n                  </div>\\n                </div>\\n\\n                <div className=\\"bg-amber-100 p-4 rounded-lg border border-amber-300\\">\\n                  <h4 className=\\"font-semibold mb-2 flex items-center gap-2\\">\\n                    <span>💡</span> Quick Facts\\n                  </h4>\\n                  <div className=\\"grid sm:grid-cols-3 gap-4 text-sm\\">\\n                    <div><strong>Duration:</strong> 1775-1783 (8 years)</div>\\n                    <div><strong>Colonies Involved:</strong> 13</div>\\n                    <div><strong>First President:</strong> George Washington (1789)</div>\\n                  </div>\\n                </div>\\n              </CardContent>\\n            </Card>\\n\\n            {/* Study Tips */}\\n            <Card>\\n              <CardHeader>\\n                <CardTitle className=\\"text-xl flex items-center gap-2\\">\\n                  <span>📚</span> How to Use This Study Guide\\n                </CardTitle>\\n              </CardHeader>\\n              <CardContent>\\n                <div className=\\"grid sm:grid-cols-2 lg:grid-cols-3 gap-4\\">\\n                  <div className=\\"p-4 bg-blue-50 rounded-lg\\">\\n                    <h4 className=\\"font-semibold mb-2\\">1. Timeline</h4>\\n                    <p className=\\"text-sm text-muted-foreground\\">Study events chronologically to understand cause and effect relationships.</p>\\n                  </div>\\n                  <div className=\\"p-4 bg-green-50 rounded-lg\\">\\n                    <h4 className=\\"font-semibold mb-2\\">2. Key Figures</h4>\\n                    <p className=\\"text-sm text-muted-foreground\\">Learn about important people and their roles in the revolution.</p>\\n                  </div>\\n                  <div className=\\"p-4 bg-purple-50 rounded-lg\\">\\n                    <h4 className=\\"font-semibold mb-2\\">3. Flashcards</h4>\\n                    <p className=\\"text-sm text-muted-foreground\\">Test your memory with interactive flashcards.</p>\\n                  </div>\\n                  <div className=\\"p-4 bg-amber-50 rounded-lg\\">\\n                    <h4 className=\\"font-semibold mb-2\\">4. Key Terms</h4>\\n                    <p className=\\"text-sm text-muted-foreground\\">Master important vocabulary and concepts.</p>\\n                  </div>\\n                  <div className=\\"p-4 bg-red-50 rounded-lg\\">\\n                    <h4 className=\\"font-semibold mb-2\\">5. Quiz</h4>\\n                    <p className=\\"text-sm text-muted-foreground\\">Test your knowledge with multiple-choice questions.</p>\\n                  </div>\\n                  <div className=\\"p-4 bg-teal-50 rounded-lg\\">\\n                    <h4 className=\\"font-semibold mb-2\\">6. Review</h4>\\n                    <p className=\\"text-sm text-muted-foreground\\">Return to areas where you need more practice.</p>\\n                  </div>\\n                </div>\\n              </CardContent>\\n            </Card>\\n          </TabsContent>\\n\\n          {/* Timeline Tab */}\\n          <TabsContent value=\\"timeline\\" className=\\"space-y-6\\">\\n            <Card>\\n              <CardHeader>\\n                <CardTitle className=\\"text-2xl flex items-center gap-2\\">\\n                  <span>📅</span> Timeline of Key Events\\n                </CardTitle>\\n                <CardDescription>\\n                  Follow the path from colonial unrest to American independence\\n                </CardDescription>\\n              </CardHeader>\\n              <CardContent>\\n                <div className=\\"relative\\">\\n                  {/* Timeline line */}\\n                  <div className=\\"absolute left-4 md:left-1/2 top-0 bottom-0 w-0.5 bg-gradient-to-b from-red-600 via-blue-600 to-amber-600\\" />\\n                  \\n                  <div className=\\"space-y-8\\">\\n                    {timelineEvents.map((event, index) => (\\n                      <div\\n                        key={event.id}\\n                        className={`relative flex items-start gap-4 ${\\n                          index % 2 === 0 ? \\"md:flex-row\\" : \\"md:flex-row-reverse\\"\\n                        }`}\\n                      >\\n                        {/* Timeline dot */}\\n                        <div className=\\"absolute left-4 md:left-1/2 -translate-x-1/2 w-4 h-4 bg-white border-4 border-red-600 rounded-full z-10\\" />\\n                        \\n                        {/* Content */}\\n                        <div className={`ml-12 md:ml-0 md:w-1/2 ${index % 2 === 0 ? \\"md:pr-12 md:text-right\\" : \\"md:pl-12\\"}`}>\\n                          <Badge variant={event.category === \\"military\\" ? \\"destructive\\" : event.category === \\"political\\" ? \\"default\\" : \\"secondary\\"} className=\\"mb-2\\">\\n                            {event.year}\\n                          </Badge>\\n                          <h3 className=\\"font-semibold text-lg\\">{event.title}</h3>\\n                          <p className=\\"text-muted-foreground mt-1\\">{event.description}</p>\\n                        </div>\\n                      </div>\\n                    ))}\\n                  </div>\\n                </div>\\n              </CardContent>\\n            </Card>\\n          </TabsContent>\\n\\n          {/* Key Figures Tab */}\\n          <TabsContent value=\\"figures\\" className=\\"space-y-6\\">\\n            <Card>\\n              <CardHeader>\\n                <CardTitle className=\\"text-2xl flex items-center gap-2\\">\\n                  <span>👥</span> Key Figures of the Revolution\\n                </CardTitle>\\n                <CardDescription>\\n                  Learn about the important people who shaped American independence\\n                </CardDescription>\\n              </CardHeader>\\n              <CardContent>\\n                <div className=\\"grid md:grid-cols-2 gap-6\\">\\n                  {keyFigures.map((figure) => (\\n                    <Card key={figure.id} className=\\"overflow-hidden\\">\\n                      <div className=\\"h-2 bg-gradient-to-r from-red-600 to-blue-600\\" />\\n                      <CardHeader>\\n                        <div className=\\"flex items-start justify-between\\">\\n                          <div>\\n                            <CardTitle className=\\"text-lg\\">{figure.name}</CardTitle>\\n                            <CardDescription>{figure.role}</CardDescription>\\n                          </div>\\n                          <Badge variant={figure.side === \\"Patriot\\" ? \\"default\\" : \\"secondary\\"}>\\n                            {figure.side}\\n                          </Badge>\\n                        </div>\\n                      </CardHeader>\\n                      <CardContent>\\n                        <p className=\\"text-sm text-muted-foreground mb-3\\">{figure.biography}</p>\\n                        <div className=\\"space-y-2\\">\\n                          <h4 className=\\"font-semibold text-sm\\">Key Contributions:</h4>\\n                          <ul className=\\"text-sm space-y-1\\">\\n                            {figure.contributions.map((contribution, i) => (\\n                              <li key={i} className=\\"flex items-start gap-2\\">\\n                                <CheckCircle2 className=\\"w-4 h-4 mt-0.5 text-green-600\\" />\\n                                <span>{contribution}</span>\\n                              </li>\\n                            ))}\\n                          </ul>\\n                        </div>\\n                      </CardContent>\\n                    </Card>\\n                  ))}\\n                </div>\\n              </CardContent>\\n            </Card>\\n          </TabsContent>\\n\\n          {/* Key Terms Tab */}\\n          <TabsContent value=\\"terms\\" className=\\"space-y-6\\">\\n            <Card>\\n              <CardHeader>\\n                <CardTitle className=\\"text-2xl flex items-center gap-2\\">\\n                  <span>📖</span> Key Terms & Definitions\\n                </CardTitle>\\n                <CardDescription>\\n                  Master the essential vocabulary of the American Revolution\\n                </CardDescription>\\n              </CardHeader>\\n              <CardContent>\\n                <Accordion type=\\"single\\" collapsible className=\\"w-full\\">\\n                  {keyTerms.map((term) => (\\n                    <AccordionItem key={term.id} value={`term-${term.id}`}>\\n                      <AccordionTrigger className=\\"text-left\\">\\n                        <div className=\\"flex items-center gap-3\\">\\n                          <Badge variant=\\"outline\\" className=\\"shrink-0\\">{term.category}</Badge>\\n                          <span className=\\"font-semibold\\">{term.term}</span>\\n                        </div>\\n                      </AccordionTrigger>\\n                      <AccordionContent>\\n                        <div className=\\"pl-4 space-y-2\\">\\n                          <p className=\\"text-muted-foreground\\">{term.definition}</p>\\n                          {term.significance && (\\n                            <p className=\\"text-sm\\"><strong>Significance:</strong> {term.significance}</p>\\n                          )}\\n                        </div>\\n                      </AccordionContent>\\n                    </AccordionItem>\\n                  ))}\\n                </Accordion>\\n              </CardContent>\\n            </Card>\\n          </TabsContent>\\n\\n          {/* Flashcards Tab */}\\n          <TabsContent value=\\"flashcards\\" className=\\"space-y-6\\">\\n            <Card>\\n              <CardHeader>\\n                <CardTitle className=\\"text-2xl flex items-center gap-2\\">\\n                  <span>🃏</span> Interactive Flashcards\\n                </CardTitle>\\n                <CardDescription>\\n                  Click to reveal answers and test your knowledge\\n                </CardDescription>\\n              </CardHeader>\\n              <CardContent className=\\"space-y-6\\">\\n                {/* Progress */}\\n                <div className=\\"space-y-2\\">\\n                  <div className=\\"flex justify-between text-sm\\">\\n                    <span>Progress: {studiedCards.size} / {flashcards.length} cards studied</span>\\n                    <span>{Math.round(flashcardProgress)}%</span>\\n                  </div>\\n                  <Progress value={flashcardProgress} />\\n                </div>\\n\\n                {/* Flashcard */}\\n                <div\\n                  className={`relative min-h-[300px] p-8 rounded-xl border-2 cursor-pointer transition-all duration-300 ${\\n                    showAnswer\\n                      ? \\"bg-blue-50 border-blue-300\\"\\n                      : \\"bg-amber-50 border-amber-300\\"\\n                  }`}\\n                  onClick={() => !showAnswer && handleShowAnswer()}\\n                >\\n                  <div className=\\"absolute top-4 left-4\\">\\n                    <Badge variant={showAnswer ? \\"default\\" : \\"secondary\\"}>\\n                      {showAnswer ? \\"Answer\\" : \\"Question\\"}\\n                    </Badge>\\n                  </div>\\n                  <div className=\\"absolute top-4 right-4 text-sm text-muted-foreground\\">\\n                    Card {currentFlashcard + 1} of {flashcards.length}\\n                  </div>\\n                  \\n                  <div className=\\"flex items-center justify-center min-h-[200px]\\">\\n                    <p className=\\"text-xl text-center font-medium\\">\\n                      {showAnswer ? flashcards[currentFlashcard].answer : flashcards[currentFlashcard].question}\\n                    </p>\\n                  </div>\\n\\n                  {!showAnswer && (\\n                    <p className=\\"absolute bottom-4 left-1/2 -translate-x-1/2 text-sm text-muted-foreground\\">\\n                      Click to reveal answer\\n                    </p>\\n                  )}\\n                </div>\\n\\n                {/* Controls */}\\n                <div className=\\"flex justify-center gap-4\\">\\n                  <Button variant=\\"outline\\" onClick={handlePrevFlashcard}>\\n                    ← Previous\\n                  </Button>\\n                  {!showAnswer ? (\\n                    <Button onClick={handleShowAnswer}>Show Answer</Button>\\n                  ) : (\\n                    <Button onClick={handleNextFlashcard}>Next Card →</Button>\\n                  )}\\n                </div>\\n\\n                {/* Card Navigation */}\\n                <div className=\\"flex flex-wrap justify-center gap-2\\">\\n                  {flashcards.map((_, index) => (\\n                    <button\\n                      key={index}\\n                      onClick={() => {\\n                        setCurrentFlashcard(index);\\n                        setShowAnswer(false);\\n                      }}\\n                      className={`w-8 h-8 rounded-full text-sm font-medium transition-all ${\\n                        index === currentFlashcard\\n                          ? \\"bg-primary text-primary-foreground\\"\\n                          : studiedCards.has(index)\\n                          ? \\"bg-green-100 text-green-700 border border-green-300\\"\\n                          : \\"bg-gray-100 text-gray-600 hover:bg-gray-200\\"\\n                      }`}\\n                    >\\n                      {index + 1}\\n                    </button>\\n                  ))}\\n                </div>\\n              </CardContent>\\n            </Card>\\n          </TabsContent>\\n\\n          {/* Quiz Tab */}\\n          <TabsContent value=\\"quiz\\" className=\\"space-y-6\\">\\n            <Card>\\n              <CardHeader>\\n                <CardTitle className=\\"text-2xl flex items-center gap-2\\">\\n                  <span>🎯</span> Test Your Knowledge\\n                </CardTitle>\\n                <CardDescription>\\n                  Answer these questions to check your understanding\\n                </CardDescription>\\n              </CardHeader>\\n              <CardContent className=\\"space-y-6\\">\\n                {!quizCompleted ? (\\n                  <>\\n                    {/* Progress */}\\n                    <div className=\\"space-y-2\\">\\n                      <div className=\\"flex justify-between text-sm\\">\\n                        <span>Question {currentQuiz + 1} of {quizQuestions.length}</span>\\n                        <span>Score: {score}/{answeredQuestions.size}</span>\\n                      </div>\\n                      <Progress value={((currentQuiz + 1) / quizQuestions.length) * 100} />\\n                    </div>\\n\\n                    {/* Question */}\\n                    <div className=\\"p-6 bg-gray-50 rounded-lg\\">\\n                      <p className=\\"text-lg font-medium mb-4\\">\\n                        {quizQuestions[currentQuiz].question}\\n                      </p>\\n                      \\n                      <div className=\\"space-y-3\\">\\n                        {quizQuestions[currentQuiz].options.map((option, index) => (\\n                          <button\\n                            key={index}\\n                            onClick={() => handleAnswerSelect(index)}\\n                            disabled={showQuizResult}\\n                            className={`w-full p-4 text-left rounded-lg border-2 transition-all ${\\n                              selectedAnswer === index\\n                                ? showQuizResult\\n                                  ? index === quizQuestions[currentQuiz].correctAnswer\\n                                    ? \\"border-green-500 bg-green-50\\"\\n                                    : \\"border-red-500 bg-red-50\\"\\n                                  : \\"border-primary bg-primary/10\\"\\n                                : showQuizResult && index === quizQuestions[currentQuiz].correctAnswer\\n                                ? \\"border-green-500 bg-green-50\\"\\n                                : \\"border-gray-200 hover:border-gray-300\\"\\n                            }`}\\n                          >\\n                            <div className=\\"flex items-center gap-3\\">\\n                              <span className={`w-8 h-8 rounded-full flex items-center justify-center text-sm font-medium ${\\n                                selectedAnswer === index\\n                                  ? showQuizResult\\n                                    ? index === quizQuestions[currentQuiz].correctAnswer\\n                                      ? \\"bg-green-500 text-white\\"\\n                                      : \\"bg-red-500 text-white\\"\\n                                    : \\"bg-primary text-primary-foreground\\"\\n                                  : showQuizResult && index === quizQuestions[currentQuiz].correctAnswer\\n                                  ? \\"bg-green-500 text-white\\"\\n                                  : \\"bg-gray-200\\"\\n                              }`}>\\n                                {showQuizResult ? (\\n                                  index === quizQuestions[currentQuiz].correctAnswer ? (\\n                                    <CheckCircle2 className=\\"w-5 h-5\\" />\\n                                  ) : selectedAnswer === index ? (\\n                                    <XCircle className=\\"w-5 h-5\\" />\\n                                  ) : (\\n                                    String.fromCharCode(65 + index)\\n                                  )\\n                                ) : (\\n                                  String.fromCharCode(65 + index)\\n                                )}\\n                              </span>\\n                              <span>{option}</span>\\n                            </div>\\n                          </button>\\n                        ))}\\n                      </div>\\n                    </div>\\n\\n                    {/* Explanation */}\\n                    {showQuizResult && quizQuestions[currentQuiz].explanation && (\\n                      <div className=\\"p-4 bg-blue-50 rounded-lg border border-blue-200\\">\\n                        <p className=\\"text-sm\\"><strong>Explanation:</strong> {quizQuestions[currentQuiz].explanation}</p>\\n                      </div>\\n                    )}\\n\\n                    {/* Controls */}\\n                    <div className=\\"flex justify-end gap-4\\">\\n                      {!showQuizResult ? (\\n                        <Button onClick={handleCheckAnswer} disabled={selectedAnswer === null}>\\n                          Check Answer\\n                        </Button>\\n                      ) : (\\n                        <Button onClick={handleNextQuestion}>\\n                          {currentQuiz === quizQuestions.length - 1 ? \\"See Results\\" : \\"Next Question\\"}\\n                        </Button>\\n                      )}\\n                    </div>\\n                  </>\\n                ) : (\\n                  /* Results */\\n                  <div className=\\"text-center py-8 space-y-6\\">\\n                    <div className=\\"text-6xl\\">🏆</div>\\n                    <h3 className=\\"text-2xl font-bold\\">Quiz Complete!</h3>\\n                    <div className=\\"text-4xl font-bold text-primary\\">\\n                      {score} / {quizQuestions.length}\\n                    </div>\\n                    <p className=\\"text-muted-foreground\\">\\n                      {score === quizQuestions.length\\n                        ? \\"Perfect score! You're a Revolution expert!\\"\\n                        : score >= quizQuestions.length * 0.7\\n                        ? \\"Great job! You have a solid understanding!\\"\\n                        : score >= quizQuestions.length * 0.5\\n                        ? \\"Good effort! Keep studying to improve!\\"\\n                        : \\"Keep practicing! Review the material and try again.\\"}\\n                    </p>\\n                    <div className=\\"flex justify-center gap-4\\">\\n                      <Button variant=\\"outline\\" onClick={handleRestartQuiz}>\\n                        <RotateCcw className=\\"w-4 h-4 mr-2\\" />\\n                        Try Again\\n                      </Button>\\n                    </div>\\n                  </div>\\n                )}\\n              </CardContent>\\n            </Card>\\n          </TabsContent>\\n        </Tabs>\\n      </main>\\n\\n      {/* Footer */}\\n      <footer className=\\"bg-slate-100 py-6 px-4 mt-12 border-t\\">\\n        <div className=\\"max-w-6xl mx-auto text-center text-sm text-muted-foreground\\">\\n          <p>American Revolution Study Guide • Created for educational purposes</p>\\n          <p className=\\"mt-1\\">📚 Study hard, learn well, and ace your exam!</p>\\n        </div>\\n      </footer>\\n    </div>\\n  );\\n}", "app/layout.tsx": "import type { Metadata } from \\"next\\";\\nimport { Geist, Geist_Mono } from \\"next/font/google\\";\\nimport \\"./globals.css\\";\\n\\nconst geistSans = Geist({\\n  variable: \\"--font-geist-sans\\",\\n  subsets: [\\"latin\\"],\\n});\\n\\nconst geistMono = Geist_Mono({\\n  variable: \\"--font-geist-mono\\",\\n  subsets: [\\"latin\\"],\\n});\\n\\nexport const metadata: Metadata = {\\n  title: \\"American Revolution Study Guide\\",\\n  description: \\"Your comprehensive guide to understanding America's fight for independence\\",\\n};\\n\\nexport default function RootLayout({\\n  children,\\n}: Readonly<{\\n  children: React.ReactNode;\\n}>) {\\n  return (\\n    <html lang=\\"en\\">\\n      <body\\n        className={`${geistSans.variable} ${geistMono.variable} antialiased`}\\n      >\\n        {children}\\n      </body>\\n    </html>\\n  );\\n}"}	2026-03-13 20:42:34.465	2026-03-13 20:42:34.465	Removed dark mode from the American Revolution Study Guide by: (1) removing the ThemeToggle component import and usage from app/page.tsx, (2) removing all dark: Tailwind classes throughout the page, (3) removing the ThemeProvider wrapper from app/layout.tsx, and (4) deleting the theme-toggle.tsx and theme-provider.tsx files. The application now uses only light mode styling.
93b2375a-9f4a-4f61-813e-b888c5fa701d	933ab8cc-beb9-4110-829b-c915933d810a	https://3000-ixitmb1ofjol7m4ns0vjc.e2b.app	Revolution Study Guide\n	{"app/page.tsx": "\\"use client\\";\\n\\nimport { useState } from \\"react\\";\\nimport { Tabs, TabsContent, TabsList, TabsTrigger } from \\"@/components/ui/tabs\\";\\nimport { Card, CardContent, CardDescription, CardHeader, CardTitle } from \\"@/components/ui/card\\";\\nimport { Badge } from \\"@/components/ui/badge\\";\\nimport { Progress } from \\"@/components/ui/progress\\";\\nimport { Button } from \\"@/components/ui/button\\";\\nimport { Accordion, AccordionContent, AccordionItem, AccordionTrigger } from \\"@/components/ui/accordion\\";\\nimport { BookOpen, Clock, Users, Lightbulb, Trophy, ChevronRight, RotateCcw, CheckCircle2, XCircle } from \\"lucide-react\\";\\nimport { timelineEvents } from \\"./data/timeline\\";\\nimport { keyFigures } from \\"./data/figures\\";\\nimport { flashcards } from \\"./data/flashcards\\";\\nimport { quizQuestions } from \\"./data/quiz\\";\\nimport { keyTerms } from \\"./data/terms\\";\\n\\nexport default function StudyGuidePage() {\\n  const [currentFlashcard, setCurrentFlashcard] = useState(0);\\n  const [showAnswer, setShowAnswer] = useState(false);\\n  const [studiedCards, setStudiedCards] = useState<Set<number>>(new Set());\\n  \\n  const [currentQuiz, setCurrentQuiz] = useState(0);\\n  const [selectedAnswer, setSelectedAnswer] = useState<number | null>(null);\\n  const [showQuizResult, setShowQuizResult] = useState(false);\\n  const [score, setScore] = useState(0);\\n  const [quizCompleted, setQuizCompleted] = useState(false);\\n  const [answeredQuestions, setAnsweredQuestions] = useState<Set<number>>(new Set());\\n\\n  const handleNextFlashcard = () => {\\n    setShowAnswer(false);\\n    setCurrentFlashcard((prev) => (prev + 1) % flashcards.length);\\n  };\\n\\n  const handlePrevFlashcard = () => {\\n    setShowAnswer(false);\\n    setCurrentFlashcard((prev) => (prev - 1 + flashcards.length) % flashcards.length);\\n  };\\n\\n  const handleShowAnswer = () => {\\n    setShowAnswer(true);\\n    setStudiedCards((prev) => new Set([...prev, currentFlashcard]));\\n  };\\n\\n  const handleAnswerSelect = (answerIndex: number) => {\\n    if (showQuizResult) return;\\n    setSelectedAnswer(answerIndex);\\n  };\\n\\n  const handleCheckAnswer = () => {\\n    if (selectedAnswer === null) return;\\n    setShowQuizResult(true);\\n    if (selectedAnswer === quizQuestions[currentQuiz].correctAnswer) {\\n      setScore((prev) => prev + 1);\\n    }\\n    setAnsweredQuestions((prev) => new Set([...prev, currentQuiz]));\\n  };\\n\\n  const handleNextQuestion = () => {\\n    if (currentQuiz === quizQuestions.length - 1) {\\n      setQuizCompleted(true);\\n    } else {\\n      setCurrentQuiz((prev) => prev + 1);\\n      setSelectedAnswer(null);\\n      setShowQuizResult(false);\\n    }\\n  };\\n\\n  const handleRestartQuiz = () => {\\n    setCurrentQuiz(0);\\n    setSelectedAnswer(null);\\n    setShowQuizResult(false);\\n    setScore(0);\\n    setQuizCompleted(false);\\n    setAnsweredQuestions(new Set());\\n  };\\n\\n  const flashcardProgress = (studiedCards.size / flashcards.length) * 100;\\n\\n  return (\\n    <div className=\\"min-h-screen bg-gradient-to-b from-amber-50 to-orange-50\\">\\n      {/* Header */}\\n      <header className=\\"bg-gradient-to-r from-red-800 via-red-700 to-blue-900 text-white py-8 px-4 shadow-lg\\">\\n        <div className=\\"max-w-6xl mx-auto\\">\\n          <div className=\\"flex items-center gap-3 mb-2\\">\\n            <span className=\\"text-4xl\\">📜</span>\\n            <h1 className=\\"text-3xl md:text-4xl font-bold\\">American Revolution Study Guide</h1>\\n          </div>\\n          <p className=\\"text-amber-100 text-lg mt-2\\">Your comprehensive guide to understanding America's fight for independence (1765-1783)</p>\\n        </div>\\n      </header>\\n\\n      {/* Main Content */}\\n      <main className=\\"max-w-6xl mx-auto px-4 py-8\\">\\n        <Tabs defaultValue=\\"overview\\" className=\\"space-y-6\\">\\n          <TabsList className=\\"grid w-full grid-cols-2 md:grid-cols-6 gap-2 h-auto p-1\\">\\n            <TabsTrigger value=\\"overview\\" className=\\"flex items-center gap-2 py-2\\">\\n              <BookOpen className=\\"w-4 h-4\\" />\\n              <span className=\\"hidden sm:inline\\">Overview</span>\\n            </TabsTrigger>\\n            <TabsTrigger value=\\"timeline\\" className=\\"flex items-center gap-2 py-2\\">\\n              <Clock className=\\"w-4 h-4\\" />\\n              <span className=\\"hidden sm:inline\\">Timeline</span>\\n            </TabsTrigger>\\n            <TabsTrigger value=\\"figures\\" className=\\"flex items-center gap-2 py-2\\">\\n              <Users className=\\"w-4 h-4\\" />\\n              <span className=\\"hidden sm:inline\\">Figures</span>\\n            </TabsTrigger>\\n            <TabsTrigger value=\\"terms\\" className=\\"flex items-center gap-2 py-2\\">\\n              <Lightbulb className=\\"w-4 h-4\\" />\\n              <span className=\\"hidden sm:inline\\">Key Terms</span>\\n            </TabsTrigger>\\n            <TabsTrigger value=\\"flashcards\\" className=\\"flex items-center gap-2 py-2\\">\\n              <BookOpen className=\\"w-4 h-4\\" />\\n              <span className=\\"hidden sm:inline\\">Flashcards</span>\\n            </TabsTrigger>\\n            <TabsTrigger value=\\"quiz\\" className=\\"flex items-center gap-2 py-2\\">\\n              <Trophy className=\\"w-4 h-4\\" />\\n              <span className=\\"hidden sm:inline\\">Quiz</span>\\n            </TabsTrigger>\\n          </TabsList>\\n\\n          {/* Overview Tab */}\\n          <TabsContent value=\\"overview\\" className=\\"space-y-6\\">\\n            <Card className=\\"border-2 border-amber-200\\">\\n              <CardHeader>\\n                <CardTitle className=\\"text-2xl flex items-center gap-2\\">\\n                  <span>🏛️</span> Introduction to the American Revolution\\n                </CardTitle>\\n                <CardDescription className=\\"text-base\\">\\n                  The American Revolution (1765-1783) was a political and military rebellion in which thirteen of Great Britain's North American colonies rejected its rule, established the United States, and founded a new nation.\\n                </CardDescription>\\n              </CardHeader>\\n              <CardContent className=\\"space-y-6\\">\\n                <div className=\\"grid md:grid-cols-2 gap-6\\">\\n                  <div className=\\"space-y-4\\">\\n                    <h3 className=\\"font-semibold text-lg flex items-center gap-2\\">\\n                      <span>🎯</span> Key Causes\\n                    </h3>\\n                    <ul className=\\"space-y-2\\">\\n                      <li className=\\"flex items-start gap-2\\">\\n                        <ChevronRight className=\\"w-4 h-4 mt-1 text-red-600\\" />\\n                        <span><strong>Taxation without Representation:</strong> Britain imposed taxes without colonial consent</span>\\n                      </li>\\n                      <li className=\\"flex items-start gap-2\\">\\n                        <ChevronRight className=\\"w-4 h-4 mt-1 text-red-600\\" />\\n                        <span><strong>Stamp Act (1765):</strong> First direct tax on colonists for printed materials</span>\\n                      </li>\\n                      <li className=\\"flex items-start gap-2\\">\\n                        <ChevronRight className=\\"w-4 h-4 mt-1 text-red-600\\" />\\n                        <span><strong>Townshend Acts (1767):</strong> Taxes on imported goods, led to boycotts</span>\\n                      </li>\\n                      <li className=\\"flex items-start gap-2\\">\\n                        <ChevronRight className=\\"w-4 h-4 mt-1 text-red-600\\" />\\n                        <span><strong>Boston Massacre (1770):</strong> British soldiers killed five colonists</span>\\n                      </li>\\n                      <li className=\\"flex items-start gap-2\\">\\n                        <ChevronRight className=\\"w-4 h-4 mt-1 text-red-600\\" />\\n                        <span><strong>Intolerable Acts (1774):</strong> Punitive laws after Boston Tea Party</span>\\n                      </li>\\n                    </ul>\\n                  </div>\\n                  <div className=\\"space-y-4\\">\\n                    <h3 className=\\"font-semibold text-lg flex items-center gap-2\\">\\n                      <span>⚔️</span> Major Outcomes\\n                    </h3>\\n                    <ul className=\\"space-y-2\\">\\n                      <li className=\\"flex items-start gap-2\\">\\n                        <ChevronRight className=\\"w-4 h-4 mt-1 text-blue-600\\" />\\n                        <span><strong>Independence:</strong> 13 colonies became the United States of America</span>\\n                      </li>\\n                      <li className=\\"flex items-start gap-2\\">\\n                        <ChevronRight className=\\"w-4 h-4 mt-1 text-blue-600\\" />\\n                        <span><strong>Declaration of Independence:</strong> Adopted July 4, 1776</span>\\n                      </li>\\n                      <li className=\\"flex items-start gap-2\\">\\n                        <ChevronRight className=\\"w-4 h-4 mt-1 text-blue-600\\" />\\n                        <span><strong>Treaty of Paris (1783):</strong> Britain recognized US independence</span>\\n                      </li>\\n                      <li className=\\"flex items-start gap-2\\">\\n                        <ChevronRight className=\\"w-4 h-4 mt-1 text-blue-600\\" />\\n                        <span><strong>Constitution (1787):</strong> Framework for new government</span>\\n                      </li>\\n                      <li className=\\"flex items-start gap-2\\">\\n                        <ChevronRight className=\\"w-4 h-4 mt-1 text-blue-600\\" />\\n                        <span><strong>Bill of Rights (1791):</strong> First 10 amendments protecting liberties</span>\\n                      </li>\\n                    </ul>\\n                  </div>\\n                </div>\\n\\n                <div className=\\"bg-amber-100 p-4 rounded-lg border border-amber-300\\">\\n                  <h4 className=\\"font-semibold mb-2 flex items-center gap-2\\">\\n                    <span>💡</span> Quick Facts\\n                  </h4>\\n                  <div className=\\"grid sm:grid-cols-3 gap-4 text-sm\\">\\n                    <div><strong>Duration:</strong> 1775-1783 (8 years)</div>\\n                    <div><strong>Colonies Involved:</strong> 13</div>\\n                    <div><strong>First President:</strong> George Washington (1789)</div>\\n                  </div>\\n                </div>\\n              </CardContent>\\n            </Card>\\n\\n            {/* Study Tips */}\\n            <Card>\\n              <CardHeader>\\n                <CardTitle className=\\"text-xl flex items-center gap-2\\">\\n                  <span>📚</span> How to Use This Study Guide\\n                </CardTitle>\\n              </CardHeader>\\n              <CardContent>\\n                <div className=\\"grid sm:grid-cols-2 lg:grid-cols-3 gap-4\\">\\n                  <div className=\\"p-4 bg-blue-50 rounded-lg\\">\\n                    <h4 className=\\"font-semibold mb-2\\">1. Timeline</h4>\\n                    <p className=\\"text-sm text-gray-600\\">Study events chronologically to understand cause and effect relationships.</p>\\n                  </div>\\n                  <div className=\\"p-4 bg-green-50 rounded-lg\\">\\n                    <h4 className=\\"font-semibold mb-2\\">2. Key Figures</h4>\\n                    <p className=\\"text-sm text-gray-600\\">Learn about important people and their roles in the revolution.</p>\\n                  </div>\\n                  <div className=\\"p-4 bg-purple-50 rounded-lg\\">\\n                    <h4 className=\\"font-semibold mb-2\\">3. Flashcards</h4>\\n                    <p className=\\"text-sm text-gray-600\\">Test your memory with interactive flashcards.</p>\\n                  </div>\\n                  <div className=\\"p-4 bg-amber-50 rounded-lg\\">\\n                    <h4 className=\\"font-semibold mb-2\\">4. Key Terms</h4>\\n                    <p className=\\"text-sm text-gray-600\\">Master important vocabulary and concepts.</p>\\n                  </div>\\n                  <div className=\\"p-4 bg-red-50 rounded-lg\\">\\n                    <h4 className=\\"font-semibold mb-2\\">5. Quiz</h4>\\n                    <p className=\\"text-sm text-gray-600\\">Test your knowledge with multiple-choice questions.</p>\\n                  </div>\\n                  <div className=\\"p-4 bg-teal-50 rounded-lg\\">\\n                    <h4 className=\\"font-semibold mb-2\\">6. Review</h4>\\n                    <p className=\\"text-sm text-gray-600\\">Return to areas where you need more practice.</p>\\n                  </div>\\n                </div>\\n              </CardContent>\\n            </Card>\\n          </TabsContent>\\n\\n          {/* Timeline Tab */}\\n          <TabsContent value=\\"timeline\\" className=\\"space-y-6\\">\\n            <Card>\\n              <CardHeader>\\n                <CardTitle className=\\"text-2xl flex items-center gap-2\\">\\n                  <span>📅</span> Timeline of Key Events\\n                </CardTitle>\\n                <CardDescription>\\n                  Follow the path from colonial unrest to American independence\\n                </CardDescription>\\n              </CardHeader>\\n              <CardContent>\\n                <div className=\\"relative\\">\\n                  {/* Timeline line */}\\n                  <div className=\\"absolute left-4 md:left-1/2 top-0 bottom-0 w-0.5 bg-gradient-to-b from-red-600 via-blue-600 to-amber-600\\" />\\n                  \\n                  <div className=\\"space-y-8\\">\\n                    {timelineEvents.map((event, index) => (\\n                      <div\\n                        key={event.id}\\n                        className={`relative flex items-start gap-4 ${\\n                          index % 2 === 0 ? \\"md:flex-row\\" : \\"md:flex-row-reverse\\"\\n                        }`}\\n                      >\\n                        {/* Timeline dot */}\\n                        <div className=\\"absolute left-4 md:left-1/2 -translate-x-1/2 w-4 h-4 bg-white border-4 border-red-600 rounded-full z-10\\" />\\n                        \\n                        {/* Content */}\\n                        <div className={`ml-12 md:ml-0 md:w-1/2 ${index % 2 === 0 ? \\"md:pr-12 md:text-right\\" : \\"md:pl-12\\"}`}>\\n                          <Badge variant={event.category === \\"military\\" ? \\"destructive\\" : event.category === \\"political\\" ? \\"default\\" : \\"secondary\\"} className=\\"mb-2\\">\\n                            {event.year}\\n                          </Badge>\\n                          <h3 className=\\"font-semibold text-lg\\">{event.title}</h3>\\n                          <p className=\\"text-gray-600 mt-1\\">{event.description}</p>\\n                        </div>\\n                      </div>\\n                    ))}\\n                  </div>\\n                </div>\\n              </CardContent>\\n            </Card>\\n          </TabsContent>\\n\\n          {/* Key Figures Tab */}\\n          <TabsContent value=\\"figures\\" className=\\"space-y-6\\">\\n            <Card>\\n              <CardHeader>\\n                <CardTitle className=\\"text-2xl flex items-center gap-2\\">\\n                  <span>👥</span> Key Figures of the Revolution\\n                </CardTitle>\\n                <CardDescription>\\n                  Learn about the important people who shaped American independence\\n                </CardDescription>\\n              </CardHeader>\\n              <CardContent>\\n                <div className=\\"grid md:grid-cols-2 gap-6\\">\\n                  {keyFigures.map((figure) => (\\n                    <Card key={figure.id} className=\\"overflow-hidden\\">\\n                      <div className=\\"h-2 bg-gradient-to-r from-red-600 to-blue-600\\" />\\n                      <CardHeader>\\n                        <div className=\\"flex items-start justify-between\\">\\n                          <div>\\n                            <CardTitle className=\\"text-lg\\">{figure.name}</CardTitle>\\n                            <CardDescription>{figure.role}</CardDescription>\\n                          </div>\\n                          <Badge variant={figure.side === \\"Patriot\\" ? \\"default\\" : \\"secondary\\"}>\\n                            {figure.side}\\n                          </Badge>\\n                        </div>\\n                      </CardHeader>\\n                      <CardContent>\\n                        <p className=\\"text-sm text-gray-600 mb-3\\">{figure.biography}</p>\\n                        <div className=\\"space-y-2\\">\\n                          <h4 className=\\"font-semibold text-sm\\">Key Contributions:</h4>\\n                          <ul className=\\"text-sm space-y-1\\">\\n                            {figure.contributions.map((contribution, i) => (\\n                              <li key={i} className=\\"flex items-start gap-2\\">\\n                                <CheckCircle2 className=\\"w-4 h-4 mt-0.5 text-green-600\\" />\\n                                <span>{contribution}</span>\\n                              </li>\\n                            ))}\\n                          </ul>\\n                        </div>\\n                      </CardContent>\\n                    </Card>\\n                  ))}\\n                </div>\\n              </CardContent>\\n            </Card>\\n          </TabsContent>\\n\\n          {/* Key Terms Tab */}\\n          <TabsContent value=\\"terms\\" className=\\"space-y-6\\">\\n            <Card>\\n              <CardHeader>\\n                <CardTitle className=\\"text-2xl flex items-center gap-2\\">\\n                  <span>📖</span> Key Terms & Definitions\\n                </CardTitle>\\n                <CardDescription>\\n                  Master the essential vocabulary of the American Revolution\\n                </CardDescription>\\n              </CardHeader>\\n              <CardContent>\\n                <Accordion type=\\"single\\" collapsible className=\\"w-full\\">\\n                  {keyTerms.map((term) => (\\n                    <AccordionItem key={term.id} value={`term-${term.id}`}>\\n                      <AccordionTrigger className=\\"text-left\\">\\n                        <div className=\\"flex items-center gap-3\\">\\n                          <Badge variant=\\"outline\\" className=\\"shrink-0\\">{term.category}</Badge>\\n                          <span className=\\"font-semibold\\">{term.term}</span>\\n                        </div>\\n                      </AccordionTrigger>\\n                      <AccordionContent>\\n                        <div className=\\"pl-4 space-y-2\\">\\n                          <p className=\\"text-gray-600\\">{term.definition}</p>\\n                          {term.significance && (\\n                            <p className=\\"text-sm\\"><strong>Significance:</strong> {term.significance}</p>\\n                          )}\\n                        </div>\\n                      </AccordionContent>\\n                    </AccordionItem>\\n                  ))}\\n                </Accordion>\\n              </CardContent>\\n            </Card>\\n          </TabsContent>\\n\\n          {/* Flashcards Tab */}\\n          <TabsContent value=\\"flashcards\\" className=\\"space-y-6\\">\\n            <Card>\\n              <CardHeader>\\n                <CardTitle className=\\"text-2xl flex items-center gap-2\\">\\n                  <span>🃏</span> Interactive Flashcards\\n                </CardTitle>\\n                <CardDescription>\\n                  Click to reveal answers and test your knowledge\\n                </CardDescription>\\n              </CardHeader>\\n              <CardContent className=\\"space-y-6\\">\\n                {/* Progress */}\\n                <div className=\\"space-y-2\\">\\n                  <div className=\\"flex justify-between text-sm\\">\\n                    <span>Progress: {studiedCards.size} / {flashcards.length} cards studied</span>\\n                    <span>{Math.round(flashcardProgress)}%</span>\\n                  </div>\\n                  <Progress value={flashcardProgress} />\\n                </div>\\n\\n                {/* Flashcard */}\\n                <div\\n                  className={`relative min-h-[300px] p-8 rounded-xl border-2 cursor-pointer transition-all duration-300 ${\\n                    showAnswer\\n                      ? \\"bg-blue-50 border-blue-300\\"\\n                      : \\"bg-amber-50 border-amber-300\\"\\n                  }`}\\n                  onClick={() => !showAnswer && handleShowAnswer()}\\n                >\\n                  <div className=\\"absolute top-4 left-4\\">\\n                    <Badge variant={showAnswer ? \\"default\\" : \\"secondary\\"}>\\n                      {showAnswer ? \\"Answer\\" : \\"Question\\"}\\n                    </Badge>\\n                  </div>\\n                  <div className=\\"absolute top-4 right-4 text-sm text-gray-500\\">\\n                    Card {currentFlashcard + 1} of {flashcards.length}\\n                  </div>\\n                  \\n                  <div className=\\"flex items-center justify-center min-h-[200px]\\">\\n                    <p className=\\"text-xl text-center font-medium\\">\\n                      {showAnswer ? flashcards[currentFlashcard].answer : flashcards[currentFlashcard].question}\\n                    </p>\\n                  </div>\\n\\n                  {!showAnswer && (\\n                    <p className=\\"absolute bottom-4 left-1/2 -translate-x-1/2 text-sm text-gray-500\\">\\n                      Click to reveal answer\\n                    </p>\\n                  )}\\n                </div>\\n\\n                {/* Controls */}\\n                <div className=\\"flex justify-center gap-4\\">\\n                  <Button variant=\\"outline\\" onClick={handlePrevFlashcard}>\\n                    ← Previous\\n                  </Button>\\n                  {!showAnswer ? (\\n                    <Button onClick={handleShowAnswer}>Show Answer</Button>\\n                  ) : (\\n                    <Button onClick={handleNextFlashcard}>Next Card →</Button>\\n                  )}\\n                </div>\\n\\n                {/* Card Navigation */}\\n                <div className=\\"flex flex-wrap justify-center gap-2\\">\\n                  {flashcards.map((_, index) => (\\n                    <button\\n                      key={index}\\n                      onClick={() => {\\n                        setCurrentFlashcard(index);\\n                        setShowAnswer(false);\\n                      }}\\n                      className={`w-8 h-8 rounded-full text-sm font-medium transition-all ${\\n                        index === currentFlashcard\\n                          ? \\"bg-blue-600 text-white\\"\\n                          : studiedCards.has(index)\\n                          ? \\"bg-green-100 text-green-700 border border-green-300\\"\\n                          : \\"bg-gray-100 text-gray-600 hover:bg-gray-200\\"\\n                      }`}\\n                    >\\n                      {index + 1}\\n                    </button>\\n                  ))}\\n                </div>\\n              </CardContent>\\n            </Card>\\n          </TabsContent>\\n\\n          {/* Quiz Tab */}\\n          <TabsContent value=\\"quiz\\" className=\\"space-y-6\\">\\n            <Card>\\n              <CardHeader>\\n                <CardTitle className=\\"text-2xl flex items-center gap-2\\">\\n                  <span>🎯</span> Test Your Knowledge\\n                </CardTitle>\\n                <CardDescription>\\n                  Answer these questions to check your understanding\\n                </CardDescription>\\n              </CardHeader>\\n              <CardContent className=\\"space-y-6\\">\\n                {!quizCompleted ? (\\n                  <>\\n                    {/* Progress */}\\n                    <div className=\\"space-y-2\\">\\n                      <div className=\\"flex justify-between text-sm\\">\\n                        <span>Question {currentQuiz + 1} of {quizQuestions.length}</span>\\n                        <span>Score: {score}/{answeredQuestions.size}</span>\\n                      </div>\\n                      <Progress value={((currentQuiz + 1) / quizQuestions.length) * 100} />\\n                    </div>\\n\\n                    {/* Question */}\\n                    <div className=\\"p-6 bg-gray-50 rounded-lg\\">\\n                      <p className=\\"text-lg font-medium mb-4\\">\\n                        {quizQuestions[currentQuiz].question}\\n                      </p>\\n                      \\n                      <div className=\\"space-y-3\\">\\n                        {quizQuestions[currentQuiz].options.map((option, index) => (\\n                          <button\\n                            key={index}\\n                            onClick={() => handleAnswerSelect(index)}\\n                            disabled={showQuizResult}\\n                            className={`w-full p-4 text-left rounded-lg border-2 transition-all ${\\n                              selectedAnswer === index\\n                                ? showQuizResult\\n                                  ? index === quizQuestions[currentQuiz].correctAnswer\\n                                    ? \\"border-green-500 bg-green-50\\"\\n                                    : \\"border-red-500 bg-red-50\\"\\n                                  : \\"border-blue-600 bg-blue-50\\"\\n                                : showQuizResult && index === quizQuestions[currentQuiz].correctAnswer\\n                                ? \\"border-green-500 bg-green-50\\"\\n                                : \\"border-gray-200 hover:border-gray-300\\"\\n                            }`}\\n                          >\\n                            <div className=\\"flex items-center gap-3\\">\\n                              <span className={`w-8 h-8 rounded-full flex items-center justify-center text-sm font-medium ${\\n                                selectedAnswer === index\\n                                  ? showQuizResult\\n                                    ? index === quizQuestions[currentQuiz].correctAnswer\\n                                      ? \\"bg-green-500 text-white\\"\\n                                      : \\"bg-red-500 text-white\\"\\n                                    : \\"bg-blue-600 text-white\\"\\n                                  : showQuizResult && index === quizQuestions[currentQuiz].correctAnswer\\n                                  ? \\"bg-green-500 text-white\\"\\n                                  : \\"bg-gray-200\\"\\n                              }`}>\\n                                {showQuizResult ? (\\n                                  index === quizQuestions[currentQuiz].correctAnswer ? (\\n                                    <CheckCircle2 className=\\"w-5 h-5\\" />\\n                                  ) : selectedAnswer === index ? (\\n                                    <XCircle className=\\"w-5 h-5\\" />\\n                                  ) : (\\n                                    String.fromCharCode(65 + index)\\n                                  )\\n                                ) : (\\n                                  String.fromCharCode(65 + index)\\n                                )}\\n                              </span>\\n                              <span>{option}</span>\\n                            </div>\\n                          </button>\\n                        ))}\\n                      </div>\\n                    </div>\\n\\n                    {/* Explanation */}\\n                    {showQuizResult && quizQuestions[currentQuiz].explanation && (\\n                      <div className=\\"p-4 bg-blue-50 rounded-lg border border-blue-200\\">\\n                        <p className=\\"text-sm\\"><strong>Explanation:</strong> {quizQuestions[currentQuiz].explanation}</p>\\n                      </div>\\n                    )}\\n\\n                    {/* Controls */}\\n                    <div className=\\"flex justify-end gap-4\\">\\n                      {!showQuizResult ? (\\n                        <Button onClick={handleCheckAnswer} disabled={selectedAnswer === null}>\\n                          Check Answer\\n                        </Button>\\n                      ) : (\\n                        <Button onClick={handleNextQuestion}>\\n                          {currentQuiz === quizQuestions.length - 1 ? \\"See Results\\" : \\"Next Question\\"}\\n                        </Button>\\n                      )}\\n                    </div>\\n                  </>\\n                ) : (\\n                  /* Results */\\n                  <div className=\\"text-center py-8 space-y-6\\">\\n                    <div className=\\"text-6xl\\">🏆</div>\\n                    <h3 className=\\"text-2xl font-bold\\">Quiz Complete!</h3>\\n                    <div className=\\"text-4xl font-bold text-blue-600\\">\\n                      {score} / {quizQuestions.length}\\n                    </div>\\n                    <p className=\\"text-gray-600\\">\\n                      {score === quizQuestions.length\\n                        ? \\"Perfect score! You're a Revolution expert!\\"\\n                        : score >= quizQuestions.length * 0.7\\n                        ? \\"Great job! You have a solid understanding!\\"\\n                        : score >= quizQuestions.length * 0.5\\n                        ? \\"Good effort! Keep studying to improve!\\"\\n                        : \\"Keep practicing! Review the material and try again.\\"}\\n                    </p>\\n                    <div className=\\"flex justify-center gap-4\\">\\n                      <Button variant=\\"outline\\" onClick={handleRestartQuiz}>\\n                        <RotateCcw className=\\"w-4 h-4 mr-2\\" />\\n                        Try Again\\n                      </Button>\\n                    </div>\\n                  </div>\\n                )}\\n              </CardContent>\\n            </Card>\\n          </TabsContent>\\n        </Tabs>\\n      </main>\\n\\n      {/* Footer */}\\n      <footer className=\\"bg-slate-100 py-6 px-4 mt-12 border-t\\">\\n        <div className=\\"max-w-6xl mx-auto text-center text-sm text-gray-600\\">\\n          <p>American Revolution Study Guide • Created for educational purposes</p>\\n          <p className=\\"mt-1\\">📚 Study hard, learn well, and ace your exam!</p>\\n        </div>\\n      </footer>\\n    </div>\\n  );\\n}"}	2026-03-13 20:54:12.4	2026-03-15 02:53:37.732	Fixed the American Revolution Study Guide app by removing unused type imports and replacing Tailwind's semantic color classes (text-muted-foreground, bg-primary) with explicit color classes (text-gray-600, bg-blue-600) for better compatibility. The app now loads correctly with all features: Overview, Timeline, Key Figures, Key Terms, Flashcards, and Quiz tabs.
08498233-5698-4307-aed5-a25de0673ebc	eefd2ab9-a512-44fd-8ffc-91f54b65e483	https://3000-ip71wr1bfg5rglndz62gn.e2b.app	Frog Todo App\n	{"app/page.tsx": "\\"use client\\";\\n\\nimport { useState, useEffect } from \\"react\\";\\nimport { Button } from \\"@/components/ui/button\\";\\nimport { Input } from \\"@/components/ui/input\\";\\nimport { Card, CardContent, CardHeader, CardTitle } from \\"@/components/ui/card\\";\\nimport { Checkbox } from \\"@/components/ui/checkbox\\";\\nimport { Sun, Moon, Plus, Trash2, Leaf, Droplets, Bug, CloudRain } from \\"lucide-react\\";\\n\\ninterface Todo {\\n  id: string;\\n  text: string;\\n  completed: boolean;\\n  category: \\"pond\\" | \\"lily\\" | \\"bugs\\" | \\"rain\\";\\n  createdAt: number;\\n}\\n\\nconst categoryConfig = {\\n  pond: { icon: Droplets, label: \\"Pond Tasks\\", color: \\"blue\\" },\\n  lily: { icon: Leaf, label: \\"Lily Pad\\", color: \\"green\\" },\\n  bugs: { icon: Bug, label: \\"Bug Hunting\\", color: \\"amber\\" },\\n  rain: { icon: CloudRain, label: \\"Rainy Day\\", color: \\"slate\\" },\\n};\\n\\nexport default function FrogTodoApp() {\\n  const [todos, setTodos] = useState<Todo[]>([]);\\n  const [newTodo, setNewTodo] = useState(\\"\\");\\n  const [selectedCategory, setSelectedCategory] = useState<Todo[\\"category\\"]>(\\"lily\\");\\n  const [isDark, setIsDark] = useState(true);\\n  const [filter, setFilter] = useState<\\"all\\" | \\"active\\" | \\"completed\\">(\\"all\\");\\n\\n  // Load from localStorage\\n  useEffect(() => {\\n    const savedTheme = localStorage.getItem(\\"frog-theme\\");\\n    const savedTodos = localStorage.getItem(\\"frog-todos\\");\\n    if (savedTheme) setIsDark(savedTheme === \\"dark\\");\\n    if (savedTodos) setTodos(JSON.parse(savedTodos));\\n  }, []);\\n\\n  // Save to localStorage\\n  useEffect(() => {\\n    localStorage.setItem(\\"frog-theme\\", isDark ? \\"dark\\" : \\"light\\");\\n  }, [isDark]);\\n\\n  useEffect(() => {\\n    localStorage.setItem(\\"frog-todos\\", JSON.stringify(todos));\\n  }, [todos]);\\n\\n  const toggleTheme = () => setIsDark((prev) => !prev);\\n\\n  const addTodo = () => {\\n    if (!newTodo.trim()) return;\\n    const todo: Todo = {\\n      id: crypto.randomUUID(),\\n      text: newTodo.trim(),\\n      completed: false,\\n      category: selectedCategory,\\n      createdAt: Date.now(),\\n    };\\n    setTodos((prev) => [todo, ...prev]);\\n    setNewTodo(\\"\\");\\n  };\\n\\n  const toggleTodo = (id: string) => {\\n    setTodos((prev) =>\\n      prev.map((todo) =>\\n        todo.id === id ? { ...todo, completed: !todo.completed } : todo\\n      )\\n    );\\n  };\\n\\n  const deleteTodo = (id: string) => {\\n    setTodos((prev) => prev.filter((todo) => todo.id !== id));\\n  };\\n\\n  const clearCompleted = () => {\\n    setTodos((prev) => prev.filter((todo) => !todo.completed));\\n  };\\n\\n  const filteredTodos = todos.filter((todo) => {\\n    if (filter === \\"active\\") return !todo.completed;\\n    if (filter === \\"completed\\") return todo.completed;\\n    return true;\\n  });\\n\\n  const stats = {\\n    total: todos.length,\\n    active: todos.filter((t) => !t.completed).length,\\n    completed: todos.filter((t) => t.completed).length,\\n  byCategory: {\\n    pond: todos.filter((t) => t.category === \\"pond\\").length,\\n    lily: todos.filter((t) => t.category === \\"lily\\").length,\\n    bugs: todos.filter((t) => t.category === \\"bugs\\").length,\\n    rain: todos.filter((t) => t.category === \\"rain\\").length,\\n  },\\n  };\\n\\n  return (\\n    <div\\n      className={`min-h-screen transition-colors duration-500 ${\\n        isDark\\n          ? \\"bg-gradient-to-br from-slate-900 via-green-900 to-slate-900\\"\\n          : \\"bg-gradient-to-br from-green-50 via-emerald-100 to-green-50\\"\\n      }`}\\n    >\\n      {/* Theme Toggle */}\\n      <div className=\\"absolute top-6 right-6\\">\\n        <Button\\n          variant=\\"outline\\"\\n          size=\\"icon\\"\\n          onClick={toggleTheme}\\n          className={`rounded-full transition-all duration-300 ${\\n            isDark\\n              ? \\"bg-white/10 border-white/30 text-yellow-400 hover:bg-white/20 hover:text-yellow-300\\"\\n              : \\"bg-green-600/10 border-green-300 text-green-600 hover:bg-green-600/20\\"\\n          }`}\\n        >\\n          {isDark ? (\\n            <Sun className=\\"h-5 w-5 transition-transform duration-300 hover:rotate-45\\" />\\n          ) : (\\n            <Moon className=\\"h-5 w-5 transition-transform duration-300 hover:-rotate-12\\" />\\n          )}\\n        </Button>\\n      </div>\\n\\n      <div className=\\"container mx-auto px-4 py-12 max-w-4xl\\">\\n        {/* Header */}\\n        <div className=\\"text-center mb-12\\">\\n          <div className=\\"text-6xl mb-4\\">🐸</div>\\n          <h1\\n            className={`text-4xl font-bold mb-2 transition-colors duration-300 ${\\n              isDark ? \\"text-white\\" : \\"text-slate-800\\"\\n            }`}\\n          >\\n            Froggy Tasks\\n          </h1>\\n          <p\\n            className={`text-lg transition-colors duration-300 ${\\n              isDark ? \\"text-green-300\\" : \\"text-green-700\\"\\n            }`}\\n          >\\n            Hop to it! Your pond of productivity awaits.\\n          </p>\\n        </div>\\n\\n        {/* Add Todo Card */}\\n        <Card\\n          className={`mb-8 backdrop-blur-lg border transition-all duration-500 ${\\n            isDark\\n              ? \\"bg-white/10 border-white/20\\"\\n              : \\"bg-white/80 border-green-200\\"\\n          }`}\\n        >\\n          <CardHeader>\\n            <CardTitle\\n              className={`flex items-center gap-2 transition-colors duration-300 ${\\n                isDark ? \\"text-white\\" : \\"text-slate-800\\"\\n              }`}\\n            >\\n              <span className=\\"text-2xl\\">🌿</span> Add New Task\\n            </CardTitle>\\n          </CardHeader>\\n          <CardContent>\\n            <div className=\\"flex flex-col sm:flex-row gap-4\\">\\n              <Input\\n                value={newTodo}\\n                onChange={(e) => setNewTodo(e.target.value)}\\n                onKeyDown={(e) => e.key === \\"Enter\\" && addTodo()}\\n                placeholder=\\"What does the frog need to do?\\"\\n                className={`flex-1 transition-colors duration-300 ${\\n                  isDark\\n                    ? \\"bg-white/10 border-white/30 text-white placeholder:text-white/50\\"\\n                    : \\"bg-green-50 border-green-300 text-slate-800 placeholder:text-slate-400\\"\\n                }`}\\n              />\\n              <div className=\\"flex gap-2\\">\\n                {(Object.keys(categoryConfig) as Todo[\\"category\\"][]).map(\\n                  (cat) => {\\n                    const config = categoryConfig[cat];\\n                    const Icon = config.icon;\\n                    return (\\n                      <Button\\n                        key={cat}\\n                        variant={selectedCategory === cat ? \\"default\\" : \\"outline\\"}\\n                        size=\\"icon\\"\\n                        onClick={() => setSelectedCategory(cat)}\\n                        className={`transition-all duration-300 ${\\n                          selectedCategory === cat\\n                            ? \\"bg-green-600 hover:bg-green-700 text-white\\"\\n                            : isDark\\n                            ? \\"bg-white/10 border-white/30 text-white/70 hover:bg-white/20 hover:text-white\\"\\n                            : \\"bg-green-100 border-green-300 text-green-700 hover:bg-green-200\\"\\n                        }`}\\n                        title={config.label}\\n                      >\\n                        <Icon className=\\"h-4 w-4\\" />\\n                      </Button>\\n                    );\\n                  }\\n                )}\\n              </div>\\n              <Button\\n                onClick={addTodo}\\n                className=\\"bg-green-600 hover:bg-green-700 text-white\\"\\n              >\\n                <Plus className=\\"h-4 w-4 mr-2\\" />\\n                Add\\n              </Button>\\n            </div>\\n          </CardContent>\\n        </Card>\\n\\n        {/* Stats Row */}\\n        <div className=\\"grid grid-cols-2 sm:grid-cols-4 gap-4 mb-8\\">\\n          {[\\n            { label: \\"Total Tasks\\", value: stats.total, emoji: \\"📋\\" },\\n            { label: \\"Active\\", value: stats.active, emoji: \\"🐸\\" },\\n            { label: \\"Completed\\", value: stats.completed, emoji: \\"✅\\" },\\n            { label: \\"Pond Progress\\", value: stats.total ? `${Math.round((stats.completed / stats.total) * 100)}%` : \\"0%\\", emoji: \\"🎯\\" },\\n          ].map((stat) => (\\n            <Card\\n              key={stat.label}\\n              className={`backdrop-blur-lg border transition-all duration-500 ${\\n                isDark\\n                  ? \\"bg-white/10 border-white/20\\"\\n                  : \\"bg-white/60 border-green-200\\"\\n              }`}\\n            >\\n              <CardContent className=\\"pt-4 pb-4 text-center\\">\\n                <div className=\\"text-2xl mb-1\\">{stat.emoji}</div>\\n                <div\\n                  className={`text-2xl font-bold transition-colors duration-300 ${\\n                    isDark ? \\"text-white\\" : \\"text-slate-800\\"\\n                  }`}\\n                >\\n                  {stat.value}\\n                </div>\\n                <div\\n                  className={`text-sm transition-colors duration-300 ${\\n                    isDark ? \\"text-white/60\\" : \\"text-slate-500\\"\\n                  }`}\\n                >\\n                  {stat.label}\\n                </div>\\n              </CardContent>\\n            </Card>\\n          ))}\\n        </div>\\n\\n        {/* Filter Tabs */}\\n        <div className=\\"flex gap-2 mb-6 justify-center flex-wrap\\">\\n          {[\\n            { key: \\"all\\", label: \\"All Tasks\\", emoji: \\"🐸\\" },\\n            { key: \\"active\\", label: \\"Active\\", emoji: \\"🌿\\" },\\n            { key: \\"completed\\", label: \\"Done\\", emoji: \\"🎉\\" },\\n          ].map((tab) => (\\n            <Button\\n              key={tab.key}\\n              variant={filter === tab.key ? \\"default\\" : \\"outline\\"}\\n              onClick={() => setFilter(tab.key as typeof filter)}\\n              className={`transition-all duration-300 ${\\n                filter === tab.key\\n                  ? \\"bg-green-600 hover:bg-green-700 text-white\\"\\n                  : isDark\\n                  ? \\"bg-white/10 border-white/30 text-white/70 hover:bg-white/20 hover:text-white\\"\\n                  : \\"bg-green-100 border-green-300 text-green-700 hover:bg-green-200\\"\\n              }`}\\n            >\\n              <span className=\\"mr-2\\">{tab.emoji}</span>\\n              {tab.label}\\n            </Button>\\n          ))}\\n          {stats.completed > 0 && (\\n            <Button\\n              variant=\\"ghost\\"\\n              onClick={clearCompleted}\\n              className={`transition-all duration-300 ${\\n                isDark\\n                  ? \\"text-white/60 hover:text-red-400 hover:bg-red-500/10\\"\\n                  : \\"text-slate-500 hover:text-red-600 hover:bg-red-100\\"\\n              }`}\\n            >\\n              <Trash2 className=\\"h-4 w-4 mr-2\\" />\\n              Clear Done\\n            </Button>\\n          )}\\n        </div>\\n\\n        {/* Todo List */}\\n        <div className=\\"space-y-3\\">\\n          {filteredTodos.length === 0 ? (\\n            <Card\\n              className={`backdrop-blur-lg border transition-all duration-500 ${\\n                isDark\\n                  ? \\"bg-white/10 border-white/20\\"\\n                  : \\"bg-white/60 border-green-200\\"\\n              }`}\\n            >\\n              <CardContent className=\\"py-12 text-center\\">\\n                <div className=\\"text-5xl mb-4\\">🪷</div>\\n                <p\\n                  className={`text-lg transition-colors duration-300 ${\\n                    isDark ? \\"text-white/60\\" : \\"text-slate-500\\"\\n                  }`}\\n                >\\n                  {filter === \\"all\\"\\n                    ? \\"No tasks yet! Time to hop into action.\\"\\n                    : filter === \\"active\\"\\n                    ? \\"All caught up! The frog is resting.\\"\\n                    : \\"No completed tasks yet. Keep hopping!\\"}\\n                </p>\\n              </CardContent>\\n            </Card>\\n          ) : (\\n            filteredTodos.map((todo) => {\\n              const config = categoryConfig[todo.category];\\n              const Icon = config.icon;\\n              return (\\n                <Card\\n                  key={todo.id}\\n                  className={`backdrop-blur-lg border transition-all duration-500 hover:scale-[1.01] ${\\n                    isDark\\n                      ? \\"bg-white/10 border-white/20 hover:bg-white/15\\"\\n                      : \\"bg-white/60 border-green-200 hover:bg-white/80\\"\\n                  } ${todo.completed ? \\"opacity-60\\" : \\"\\"}`}\\n                >\\n                  <CardContent className=\\"py-4\\">\\n                    <div className=\\"flex items-center gap-4\\">\\n                      <Checkbox\\n                        checked={todo.completed}\\n                        onCheckedChange={() => toggleTodo(todo.id)}\\n                        className={`border-2 ${\\n                          isDark\\n                            ? \\"border-white/50 data-[state=checked]:bg-green-500 data-[state=checked]:border-green-500\\"\\n                            : \\"border-green-400 data-[state=checked]:bg-green-500 data-[state=checked]:border-green-500\\"\\n                        }`}\\n                      />\\n                      <div\\n                        className={`p-2 rounded-lg ${\\n                          isDark ? \\"bg-white/10\\" : \\"bg-green-100\\"\\n                        }`}\\n                      >\\n                        <Icon\\n                          className={`h-4 w-4 ${\\n                            todo.category === \\"pond\\"\\n                              ? isDark\\n                                ? \\"text-blue-400\\"\\n                                : \\"text-blue-600\\"\\n                              : todo.category === \\"lily\\"\\n                              ? isDark\\n                                ? \\"text-green-400\\"\\n                                : \\"text-green-600\\"\\n                              : todo.category === \\"bugs\\"\\n                              ? isDark\\n                                ? \\"text-amber-400\\"\\n                                : \\"text-amber-600\\"\\n                              : isDark\\n                              ? \\"text-slate-400\\"\\n                              : \\"text-slate-600\\"\\n                          }`}\\n                        />\\n                      </div>\\n                      <span\\n                        className={`flex-1 transition-all duration-300 ${\\n                          todo.completed\\n                            ? isDark\\n                              ? \\"text-white/50 line-through\\"\\n                              : \\"text-slate-400 line-through\\"\\n                            : isDark\\n                            ? \\"text-white\\"\\n                            : \\"text-slate-800\\"\\n                        }`}\\n                      >\\n                        {todo.text}\\n                      </span>\\n                      <Button\\n                        variant=\\"ghost\\"\\n                        size=\\"icon\\"\\n                        onClick={() => deleteTodo(todo.id)}\\n                        className={`transition-all duration-300 ${\\n                          isDark\\n                            ? \\"text-white/40 hover:text-red-400 hover:bg-red-500/20\\"\\n                            : \\"text-slate-400 hover:text-red-500 hover:bg-red-100\\"\\n                        }`}\\n                      >\\n                        <Trash2 className=\\"h-4 w-4\\" />\\n                      </Button>\\n                    </div>\\n                  </CardContent>\\n                </Card>\\n              );\\n            })\\n          )}\\n        </div>\\n\\n        {/* Footer */}\\n        <div className=\\"mt-12 text-center\\">\\n          <p\\n            className={`text-sm transition-colors duration-300 ${\\n              isDark ? \\"text-white/40\\" : \\"text-slate-400\\"\\n            }`}\\n          >\\n            🐸 Ribbit! Tasks are saved automatically to your lily pad.\\n          </p>\\n        </div>\\n      </div>\\n    </div>\\n  );\\n}\\n"}	2026-03-13 03:20:05.596	2026-03-15 20:53:13.969	\N
82558331-7b7b-464f-82ba-db05bcd5b00a	bc0dcd34-fc3c-40fc-8e9d-ead421b64da1	https://3000-i0sognaiss1y5rcj7x2yl.e2b.app	Study Planner Dashboard\n	{"app/page.tsx": "\\"use client\\";\\n\\nimport React, { useState } from \\"react\\";\\nimport { Button } from \\"@/components/ui/button\\";\\nimport { Input } from \\"@/components/ui/input\\";\\nimport { Label } from \\"@/components/ui/label\\";\\nimport {\\n  Dialog,\\n  DialogTrigger,\\n  DialogContent,\\n  DialogHeader,\\n  DialogTitle,\\n  DialogDescription,\\n  DialogFooter,\\n  DialogClose,\\n} from \\"@/components/ui/dialog\\";\\nimport { Checkbox } from \\"@/components/ui/checkbox\\";\\nimport { cn } from \\"@/lib/utils\\";\\nimport {\\n  Plus,\\n  Pencil,\\n  Trash2,\\n  BookOpen,\\n  Target,\\n  Timer,\\n  Play,\\n  Pause,\\n  RotateCcw,\\n  Calendar,\\n  CheckCircle2,\\n  Circle,\\n  MoreHorizontal,\\n} from \\"lucide-react\\";\\nimport {\\n  DropdownMenu,\\n  DropdownMenuContent,\\n  DropdownMenuItem,\\n  DropdownMenuTrigger,\\n} from \\"@/components/ui/dropdown-menu\\";\\nimport {\\n  AlertDialog,\\n  AlertDialogAction,\\n  AlertDialogCancel,\\n  AlertDialogContent,\\n  AlertDialogDescription,\\n  AlertDialogFooter,\\n  AlertDialogHeader,\\n  AlertDialogTitle,\\n  AlertDialogTrigger,\\n} from \\"@/components/ui/alert-dialog\\";\\nimport { ThemeToggle } from \\"@/components/theme-toggle\\";\\n\\ninterface Assignment {\\n  id: number;\\n  title: string;\\n  dueDate: string;\\n  subject: string;\\n  completed: boolean;\\n}\\n\\ninterface Goal {\\n  id: number;\\n  description: string;\\n  category: string;\\n  completed: boolean;\\n}\\n\\nconst initialAssignments: Assignment[] = [\\n  { id: 1, title: \\"Math Homework - Chapter 5\\", dueDate: \\"2024-01-15\\", subject: \\"Mathematics\\", completed: false },\\n  { id: 2, title: \\"Science Project Proposal\\", dueDate: \\"2024-01-17\\", subject: \\"Science\\", completed: false },\\n  { id: 3, title: \\"History Essay - WWII\\", dueDate: \\"2024-01-20\\", subject: \\"History\\", completed: true },\\n];\\n\\nconst initialGoals: Goal[] = [\\n  { id: 1, description: \\"Study 5 hours this week\\", category: \\"Study Time\\", completed: false },\\n  { id: 2, description: \\"Complete 3 assignments\\", category: \\"Productivity\\", completed: false },\\n  { id: 3, description: \\"Read 2 chapters of textbook\\", category: \\"Reading\\", completed: false },\\n];\\n\\nconst Page = () => {\\n  const [assignments, setAssignments] = useState<Assignment[]>(initialAssignments);\\n  const [goals, setGoals] = useState<Goal[]>(initialGoals);\\n  const [focusTime, setFocusTime] = useState(25);\\n  const [timerActive, setTimerActive] = useState(false);\\n  const [timeLeft, setTimeLeft] = useState(focusTime * 60);\\n  const [timerInterval, setTimerInterval] = useState<NodeJS.Timeout | null>(null);\\n\\n  // Assignment Dialog State\\n  const [isAssignmentDialogOpen, setIsAssignmentDialogOpen] = useState(false);\\n  const [editingAssignment, setEditingAssignment] = useState<Assignment | null>(null);\\n  const [assignmentForm, setAssignmentForm] = useState({\\n    title: \\"\\",\\n    dueDate: \\"\\",\\n    subject: \\"\\",\\n  });\\n\\n  // Goal Dialog State\\n  const [isGoalDialogOpen, setIsGoalDialogOpen] = useState(false);\\n  const [editingGoal, setEditingGoal] = useState<Goal | null>(null);\\n  const [goalForm, setGoalForm] = useState({\\n    description: \\"\\",\\n    category: \\"\\",\\n  });\\n\\n  // Timer functions\\n  const startTimer = () => {\\n    if (timerInterval) return;\\n    setTimerActive(true);\\n    const interval = setInterval(() => {\\n      setTimeLeft((prev) => {\\n        if (prev <= 1) {\\n          clearInterval(interval);\\n          setTimerActive(false);\\n          setTimerInterval(null);\\n          return 0;\\n        }\\n        return prev - 1;\\n      });\\n    }, 1000);\\n    setTimerInterval(interval);\\n  };\\n\\n  const pauseTimer = () => {\\n    if (timerInterval) {\\n      clearInterval(timerInterval);\\n      setTimerInterval(null);\\n    }\\n    setTimerActive(false);\\n  };\\n\\n  const resetTimer = () => {\\n    if (timerInterval) {\\n      clearInterval(timerInterval);\\n      setTimerInterval(null);\\n    }\\n    setTimerActive(false);\\n    setTimeLeft(focusTime * 60);\\n  };\\n\\n  // Assignment CRUD\\n  const openAddAssignment = () => {\\n    setEditingAssignment(null);\\n    setAssignmentForm({ title: \\"\\", dueDate: \\"\\", subject: \\"\\" });\\n    setIsAssignmentDialogOpen(true);\\n  };\\n\\n  const openEditAssignment = (assignment: Assignment) => {\\n    setEditingAssignment(assignment);\\n    setAssignmentForm({\\n      title: assignment.title,\\n      dueDate: assignment.dueDate,\\n      subject: assignment.subject,\\n    });\\n    setIsAssignmentDialogOpen(true);\\n  };\\n\\n  const saveAssignment = () => {\\n    if (!assignmentForm.title || !assignmentForm.dueDate) return;\\n\\n    if (editingAssignment) {\\n      setAssignments((prev) =>\\n        prev.map((a) =>\\n          a.id === editingAssignment.id\\n            ? { ...a, ...assignmentForm }\\n            : a\\n        )\\n      );\\n    } else {\\n      const newAssignment: Assignment = {\\n        id: Date.now(),\\n        ...assignmentForm,\\n        completed: false,\\n      };\\n      setAssignments((prev) => [...prev, newAssignment]);\\n    }\\n    setIsAssignmentDialogOpen(false);\\n  };\\n\\n  const deleteAssignment = (id: number) => {\\n    setAssignments((prev) => prev.filter((a) => a.id !== id));\\n  };\\n\\n  const toggleAssignmentCompletion = (id: number) => {\\n    setAssignments((prev) =>\\n      prev.map((a) =>\\n        a.id === id ? { ...a, completed: !a.completed } : a\\n      )\\n    );\\n  };\\n\\n  // Goal CRUD\\n  const openAddGoal = () => {\\n    setEditingGoal(null);\\n    setGoalForm({ description: \\"\\", category: \\"\\" });\\n    setIsGoalDialogOpen(true);\\n  };\\n\\n  const openEditGoal = (goal: Goal) => {\\n    setEditingGoal(goal);\\n    setGoalForm({\\n      description: goal.description,\\n      category: goal.category,\\n    });\\n    setIsGoalDialogOpen(true);\\n  };\\n\\n  const saveGoal = () => {\\n    if (!goalForm.description) return;\\n\\n    if (editingGoal) {\\n      setGoals((prev) =>\\n        prev.map((g) =>\\n          g.id === editingGoal.id\\n            ? { ...g, ...goalForm }\\n            : g\\n        )\\n      );\\n    } else {\\n      const newGoal: Goal = {\\n        id: Date.now(),\\n        ...goalForm,\\n        completed: false,\\n      };\\n      setGoals((prev) => [...prev, newGoal]);\\n    }\\n    setIsGoalDialogOpen(false);\\n  };\\n\\n  const deleteGoal = (id: number) => {\\n    setGoals((prev) => prev.filter((g) => g.id !== id));\\n  };\\n\\n  const toggleGoalCompletion = (id: number) => {\\n    setGoals((prev) =>\\n      prev.map((g) =>\\n        g.id === id ? { ...g, completed: !g.completed } : g\\n      )\\n    );\\n  };\\n\\n  const formatDate = (dateString: string) => {\\n    const date = new Date(dateString);\\n    return date.toLocaleDateString(\\"en-US\\", {\\n      month: \\"short\\",\\n      day: \\"numeric\\",\\n      year: \\"numeric\\",\\n    });\\n  };\\n\\n  const getDaysUntilDue = (dueDate: string) => {\\n    const today = new Date();\\n    const due = new Date(dueDate);\\n    const diffTime = due.getTime() - today.getTime();\\n    const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));\\n    if (diffDays < 0) return \\"Overdue\\";\\n    if (diffDays === 0) return \\"Due today\\";\\n    if (diffDays === 1) return \\"Due tomorrow\\";\\n    return `${diffDays} days left`;\\n  };\\n\\n  const getDueDateColor = (dueDate: string) => {\\n    const days = Math.ceil(\\n      (new Date(dueDate).getTime() - new Date().getTime()) / (1000 * 60 * 60 * 24)\\n    );\\n    if (days < 0) return \\"text-red-600 dark:text-red-400\\";\\n    if (days <= 2) return \\"text-amber-600 dark:text-amber-400\\";\\n    return \\"text-emerald-600 dark:text-emerald-400\\";\\n  };\\n\\n  return (\\n    <div className=\\"min-h-screen bg-slate-50 dark:bg-slate-950\\">\\n      {/* Header */}\\n      <header className=\\"bg-white dark:bg-slate-900 border-b border-slate-200 dark:border-slate-800 sticky top-0 z-10\\">\\n        <div className=\\"max-w-6xl mx-auto px-4 sm:px-6 lg:px-8 py-4\\">\\n          <div className=\\"flex items-center justify-between\\">\\n            <div className=\\"flex items-center gap-3\\">\\n              <div className=\\"p-2 bg-indigo-100 dark:bg-indigo-950 rounded-lg\\">\\n                <BookOpen className=\\"h-6 w-6 text-indigo-600 dark:text-indigo-400\\" />\\n              </div>\\n              <div>\\n                <h1 className=\\"text-xl font-bold text-slate-900 dark:text-slate-100\\">Study Planner</h1>\\n                <p className=\\"text-sm text-slate-500 dark:text-slate-400\\">Stay organized, achieve your goals</p>\\n              </div>\\n            </div>\\n            <div className=\\"flex items-center gap-4\\">\\n              <div className=\\"hidden sm:flex items-center gap-4 text-sm text-slate-600 dark:text-slate-400\\">\\n                <div className=\\"flex items-center gap-2\\">\\n                  <CheckCircle2 className=\\"h-4 w-4 text-emerald-500\\" />\\n                  <span>{assignments.filter(a => a.completed).length}/{assignments.length} Assignments</span>\\n                </div>\\n                <div className=\\"flex items-center gap-2\\">\\n                  <Target className=\\"h-4 w-4 text-indigo-500\\" />\\n                  <span>{goals.filter(g => g.completed).length}/{goals.length} Goals</span>\\n                </div>\\n              </div>\\n              <ThemeToggle />\\n            </div>\\n          </div>\\n        </div>\\n      </header>\\n\\n      <main className=\\"max-w-6xl mx-auto px-4 sm:px-6 lg:px-8 py-8\\">\\n        <div className=\\"grid grid-cols-1 lg:grid-cols-3 gap-6\\">\\n          {/* Assignments Section */}\\n          <div className=\\"lg:col-span-2 space-y-6\\">\\n            <section className=\\"bg-white dark:bg-slate-900 rounded-xl border border-slate-200 dark:border-slate-800 shadow-sm\\">\\n              <div className=\\"p-4 border-b border-slate-100 dark:border-slate-800 flex items-center justify-between\\">\\n                <div className=\\"flex items-center gap-2\\">\\n                  <BookOpen className=\\"h-5 w-5 text-indigo-600 dark:text-indigo-400\\" />\\n                  <h2 className=\\"font-semibold text-slate-900 dark:text-slate-100\\">Upcoming Assignments</h2>\\n                </div>\\n                <Button onClick={openAddAssignment} size=\\"sm\\" className=\\"gap-1\\">\\n                  <Plus className=\\"h-4 w-4\\" />\\n                  Add Assignment\\n                </Button>\\n              </div>\\n              <div className=\\"p-4 space-y-3\\">\\n                {assignments.length === 0 ? (\\n                  <div className=\\"text-center py-8 text-slate-500 dark:text-slate-400\\">\\n                    <BookOpen className=\\"h-12 w-12 mx-auto mb-3 opacity-30\\" />\\n                    <p>No assignments yet. Add your first one!</p>\\n                  </div>\\n                ) : (\\n                  assignments\\n                    .sort((a, b) => new Date(a.dueDate).getTime() - new Date(b.dueDate).getTime())\\n                    .map((assignment) => (\\n                    <div\\n                      key={assignment.id}\\n                      className={cn(\\n                        \\"group flex items-start gap-3 p-4 rounded-lg border transition-all\\",\\n                        assignment.completed\\n                          ? \\"bg-slate-50 dark:bg-slate-800/50 border-slate-200 dark:border-slate-800 opacity-60\\"\\n                          : \\"bg-white dark:bg-slate-900 border-slate-200 dark:border-slate-800 hover:border-indigo-300 dark:hover:border-indigo-700 hover:shadow-sm\\"\\n                      )}\\n                    >\\n                      <Checkbox\\n                        checked={assignment.completed}\\n                        onCheckedChange={() => toggleAssignmentCompletion(assignment.id)}\\n                        className=\\"mt-1\\"\\n                      />\\n                      <div className=\\"flex-1 min-w-0\\">\\n                        <h3\\n                          className={cn(\\n                            \\"font-medium text-slate-900 dark:text-slate-100\\",\\n                            assignment.completed && \\"line-through text-slate-500 dark:text-slate-500\\"\\n                          )}\\n                        >\\n                          {assignment.title}\\n                        </h3>\\n                        <div className=\\"flex items-center gap-3 mt-1 text-sm\\">\\n                          <span className=\\"text-slate-500 dark:text-slate-400\\">{assignment.subject}</span>\\n                          <span className=\\"text-slate-300 dark:text-slate-600\\">•</span>\\n                          <span className={cn(\\"font-medium\\", getDueDateColor(assignment.dueDate))}>\\n                            {getDaysUntilDue(assignment.dueDate)}\\n                          </span>\\n                        </div>\\n                      </div>\\n                      <DropdownMenu>\\n                        <DropdownMenuTrigger asChild>\\n                          <Button variant=\\"ghost\\" size=\\"icon\\" className=\\"h-8 w-8 opacity-0 group-hover:opacity-100 transition-opacity\\">\\n                            <MoreHorizontal className=\\"h-4 w-4\\" />\\n                          </Button>\\n                        </DropdownMenuTrigger>\\n                        <DropdownMenuContent align=\\"end\\">\\n                          <DropdownMenuItem onClick={() => openEditAssignment(assignment)}>\\n                            <Pencil className=\\"h-4 w-4 mr-2\\" />\\n                            Edit\\n                          </DropdownMenuItem>\\n                          <AlertDialog>\\n                            <AlertDialogTrigger asChild>\\n                              <DropdownMenuItem onSelect={(e) => e.preventDefault()} className=\\"text-red-600\\">\\n                                <Trash2 className=\\"h-4 w-4 mr-2\\" />\\n                                Delete\\n                              </DropdownMenuItem>\\n                            </AlertDialogTrigger>\\n                            <AlertDialogContent>\\n                              <AlertDialogHeader>\\n                                <AlertDialogTitle>Delete Assignment</AlertDialogTitle>\\n                                <AlertDialogDescription>\\n                                  Are you sure you want to delete \\"{assignment.title}\\"? This action cannot be undone.\\n                                </AlertDialogDescription>\\n                              </AlertDialogHeader>\\n                              <AlertDialogFooter>\\n                                <AlertDialogCancel>Cancel</AlertDialogCancel>\\n                                <AlertDialogAction\\n                                  onClick={() => deleteAssignment(assignment.id)}\\n                                  className=\\"bg-red-600 hover:bg-red-700\\"\\n                                >\\n                                  Delete\\n                                </AlertDialogAction>\\n                              </AlertDialogFooter>\\n                            </AlertDialogContent>\\n                          </AlertDialog>\\n                        </DropdownMenuContent>\\n                      </DropdownMenu>\\n                    </div>\\n                  ))\\n                )}\\n              </div>\\n            </section>\\n\\n            {/* Goals Section */}\\n            <section className=\\"bg-white dark:bg-slate-900 rounded-xl border border-slate-200 dark:border-slate-800 shadow-sm\\">\\n              <div className=\\"p-4 border-b border-slate-100 dark:border-slate-800 flex items-center justify-between\\">\\n                <div className=\\"flex items-center gap-2\\">\\n                  <Target className=\\"h-5 w-5 text-emerald-600 dark:text-emerald-400\\" />\\n                  <h2 className=\\"font-semibold text-slate-900 dark:text-slate-100\\">Weekly Goals</h2>\\n                </div>\\n                <Button onClick={openAddGoal} size=\\"sm\\" variant=\\"outline\\" className=\\"gap-1\\">\\n                  <Plus className=\\"h-4 w-4\\" />\\n                  Add Goal\\n                </Button>\\n              </div>\\n              <div className=\\"p-4 space-y-3\\">\\n                {goals.length === 0 ? (\\n                  <div className=\\"text-center py-8 text-slate-500 dark:text-slate-400\\">\\n                    <Target className=\\"h-12 w-12 mx-auto mb-3 opacity-30\\" />\\n                    <p>No goals yet. Set your first goal!</p>\\n                  </div>\\n                ) : (\\n                  goals.map((goal) => (\\n                    <div\\n                      key={goal.id}\\n                      className={cn(\\n                        \\"group flex items-center gap-3 p-4 rounded-lg border transition-all\\",\\n                        goal.completed\\n                          ? \\"bg-slate-50 dark:bg-slate-800/50 border-slate-200 dark:border-slate-800 opacity-60\\"\\n                          : \\"bg-white dark:bg-slate-900 border-slate-200 dark:border-slate-800 hover:border-emerald-300 dark:hover:border-emerald-700 hover:shadow-sm\\"\\n                      )}\\n                    >\\n                      <Checkbox\\n                        checked={goal.completed}\\n                        onCheckedChange={() => toggleGoalCompletion(goal.id)}\\n                        className=\\"mt-0\\"\\n                      />\\n                      <div className=\\"flex-1 min-w-0\\">\\n                        <p\\n                          className={cn(\\n                            \\"text-slate-900 dark:text-slate-100\\",\\n                            goal.completed && \\"line-through text-slate-500 dark:text-slate-500\\"\\n                          )}\\n                        >\\n                          {goal.description}\\n                        </p>\\n                        {goal.category && (\\n                          <span className=\\"inline-block mt-1 text-xs px-2 py-0.5 bg-slate-100 dark:bg-slate-800 text-slate-600 dark:text-slate-400 rounded-full\\">\\n                            {goal.category}\\n                          </span>\\n                        )}\\n                      </div>\\n                      <DropdownMenu>\\n                        <DropdownMenuTrigger asChild>\\n                          <Button variant=\\"ghost\\" size=\\"icon\\" className=\\"h-8 w-8 opacity-0 group-hover:opacity-100 transition-opacity\\">\\n                            <MoreHorizontal className=\\"h-4 w-4\\" />\\n                          </Button>\\n                        </DropdownMenuTrigger>\\n                        <DropdownMenuContent align=\\"end\\">\\n                          <DropdownMenuItem onClick={() => openEditGoal(goal)}>\\n                            <Pencil className=\\"h-4 w-4 mr-2\\" />\\n                            Edit\\n                          </DropdownMenuItem>\\n                          <AlertDialog>\\n                            <AlertDialogTrigger asChild>\\n                              <DropdownMenuItem onSelect={(e) => e.preventDefault()} className=\\"text-red-600\\">\\n                                <Trash2 className=\\"h-4 w-4 mr-2\\" />\\n                                Delete\\n                              </DropdownMenuItem>\\n                            </AlertDialogTrigger>\\n                            <AlertDialogContent>\\n                              <AlertDialogHeader>\\n                                <AlertDialogTitle>Delete Goal</AlertDialogTitle>\\n                                <AlertDialogDescription>\\n                                  Are you sure you want to delete this goal? This action cannot be undone.\\n                                </AlertDialogDescription>\\n                              </AlertDialogHeader>\\n                              <AlertDialogFooter>\\n                                <AlertDialogCancel>Cancel</AlertDialogCancel>\\n                                <AlertDialogAction\\n                                  onClick={() => deleteGoal(goal.id)}\\n                                  className=\\"bg-red-600 hover:bg-red-700\\"\\n                                >\\n                                  Delete\\n                                </AlertDialogAction>\\n                              </AlertDialogFooter>\\n                            </AlertDialogContent>\\n                          </AlertDialog>\\n                        </DropdownMenuContent>\\n                      </DropdownMenu>\\n                    </div>\\n                  ))\\n                )}\\n              </div>\\n            </section>\\n          </div>\\n\\n          {/* Sidebar - Focus Timer */}\\n          <div className=\\"space-y-6\\">\\n            <section className=\\"bg-white dark:bg-slate-900 rounded-xl border border-slate-200 dark:border-slate-800 shadow-sm p-6\\">\\n              <div className=\\"flex items-center gap-2 mb-6\\">\\n                <Timer className=\\"h-5 w-5 text-rose-500\\" />\\n                <h2 className=\\"font-semibold text-slate-900 dark:text-slate-100\\">Focus Timer</h2>\\n              </div>\\n\\n              <div className=\\"text-center\\">\\n                <div className=\\"relative w-48 h-48 mx-auto mb-6\\">\\n                  <svg className=\\"w-full h-full transform -rotate-90\\">\\n                    <circle\\n                      cx=\\"96\\"\\n                      cy=\\"96\\"\\n                      r=\\"88\\"\\n                      fill=\\"none\\"\\n                      stroke=\\"currentColor\\"\\n                      className=\\"text-slate-200 dark:text-slate-700\\"\\n                      strokeWidth=\\"8\\"\\n                    />\\n                    <circle\\n                      cx=\\"96\\"\\n                      cy=\\"96\\"\\n                      r=\\"88\\"\\n                      fill=\\"none\\"\\n                      stroke={timerActive ? \\"#f43f5e\\" : \\"#6366f1\\"}\\n                      strokeWidth=\\"8\\"\\n                      strokeLinecap=\\"round\\"\\n                      strokeDasharray={`${2 * Math.PI * 88}`}\\n                      strokeDashoffset={`${2 * Math.PI * 88 * (1 - timeLeft / (focusTime * 60))}`}\\n                      className=\\"transition-all duration-1000\\"\\n                    />\\n                  </svg>\\n                  <div className=\\"absolute inset-0 flex items-center justify-center\\">\\n                    <span className=\\"text-4xl font-bold text-slate-900 dark:text-slate-100\\">\\n                      {Math.floor(timeLeft / 60)}:{String(timeLeft % 60).padStart(2, \\"0\\")}\\n                    </span>\\n                  </div>\\n                </div>\\n\\n                <div className=\\"flex items-center justify-center gap-2 mb-4\\">\\n                  {!timerActive ? (\\n                    <Button onClick={startTimer} className=\\"gap-2 bg-rose-500 hover:bg-rose-600\\">\\n                      <Play className=\\"h-4 w-4\\" />\\n                      Start\\n                    </Button>\\n                  ) : (\\n                    <Button onClick={pauseTimer} variant=\\"outline\\" className=\\"gap-2\\">\\n                      <Pause className=\\"h-4 w-4\\" />\\n                      Pause\\n                    </Button>\\n                  )}\\n                  <Button onClick={resetTimer} variant=\\"outline\\" size=\\"icon\\">\\n                    <RotateCcw className=\\"h-4 w-4\\" />\\n                  </Button>\\n                </div>\\n\\n                <div className=\\"flex items-center justify-center gap-2\\">\\n                  <span className=\\"text-sm text-slate-500 dark:text-slate-400\\">Duration:</span>\\n                  <Input\\n                    type=\\"number\\"\\n                    value={focusTime}\\n                    onChange={(e) => {\\n                      const val = Math.max(1, Math.min(120, Number(e.target.value)));\\n                      setFocusTime(val);\\n                      if (!timerActive) setTimeLeft(val * 60);\\n                    }}\\n                    className=\\"w-20 text-center\\"\\n                    min={1}\\n                    max={120}\\n                  />\\n                  <span className=\\"text-sm text-slate-500 dark:text-slate-400\\">min</span>\\n                </div>\\n              </div>\\n            </section>\\n\\n            {/* Quick Stats */}\\n            <section className=\\"bg-gradient-to-br from-indigo-500 to-purple-600 rounded-xl shadow-sm p-6 text-white\\">\\n              <h3 className=\\"font-semibold mb-4\\">This Week&apos;s Progress</h3>\\n              <div className=\\"space-y-4\\">\\n                <div>\\n                  <div className=\\"flex justify-between text-sm mb-1\\">\\n                    <span>Assignments</span>\\n                    <span>{Math.round((assignments.filter(a => a.completed).length / Math.max(assignments.length, 1)) * 100)}%</span>\\n                  </div>\\n                  <div className=\\"h-2 bg-white/20 rounded-full overflow-hidden\\">\\n                    <div\\n                      className=\\"h-full bg-white rounded-full transition-all\\"\\n                      style={{ width: `${(assignments.filter(a => a.completed).length / Math.max(assignments.length, 1)) * 100}%` }}\\n                    />\\n                  </div>\\n                </div>\\n                <div>\\n                  <div className=\\"flex justify-between text-sm mb-1\\">\\n                    <span>Goals</span>\\n                    <span>{Math.round((goals.filter(g => g.completed).length / Math.max(goals.length, 1)) * 100)}%</span>\\n                  </div>\\n                  <div className=\\"h-2 bg-white/20 rounded-full overflow-hidden\\">\\n                    <div\\n                      className=\\"h-full bg-white rounded-full transition-all\\"\\n                      style={{ width: `${(goals.filter(g => g.completed).length / Math.max(goals.length, 1)) * 100}%` }}\\n                    />\\n                  </div>\\n                </div>\\n              </div>\\n            </section>\\n          </div>\\n        </div>\\n      </main>\\n\\n      {/* Assignment Dialog */}\\n      <Dialog open={isAssignmentDialogOpen} onOpenChange={setIsAssignmentDialogOpen}>\\n        <DialogContent className=\\"sm:max-w-md\\">\\n          <DialogHeader>\\n            <DialogTitle>\\n              {editingAssignment ? \\"Edit Assignment\\" : \\"Add New Assignment\\"}\\n            </DialogTitle>\\n            <DialogDescription>\\n              {editingAssignment\\n                ? \\"Update the details of your assignment.\\"\\n                : \\"Add a new assignment to track your progress.\\"}\\n            </DialogDescription>\\n          </DialogHeader>\\n          <div className=\\"space-y-4 py-4\\">\\n            <div className=\\"space-y-2\\">\\n              <Label htmlFor=\\"title\\">Assignment Title</Label>\\n              <Input\\n                id=\\"title\\"\\n                value={assignmentForm.title}\\n                onChange={(e) => setAssignmentForm({ ...assignmentForm, title: e.target.value })}\\n                placeholder=\\"e.g., Math Homework Chapter 5\\"\\n              />\\n            </div>\\n            <div className=\\"space-y-2\\">\\n              <Label htmlFor=\\"subject\\">Subject</Label>\\n              <Input\\n                id=\\"subject\\"\\n                value={assignmentForm.subject}\\n                onChange={(e) => setAssignmentForm({ ...assignmentForm, subject: e.target.value })}\\n                placeholder=\\"e.g., Mathematics\\"\\n              />\\n            </div>\\n            <div className=\\"space-y-2\\">\\n              <Label htmlFor=\\"dueDate\\">Due Date</Label>\\n              <Input\\n                id=\\"dueDate\\"\\n                type=\\"date\\"\\n                value={assignmentForm.dueDate}\\n                onChange={(e) => setAssignmentForm({ ...assignmentForm, dueDate: e.target.value })}\\n              />\\n            </div>\\n          </div>\\n          <DialogFooter>\\n            <DialogClose asChild>\\n              <Button variant=\\"outline\\">Cancel</Button>\\n            </DialogClose>\\n            <Button onClick={saveAssignment} disabled={!assignmentForm.title || !assignmentForm.dueDate}>\\n              {editingAssignment ? \\"Save Changes\\" : \\"Add Assignment\\"}\\n            </Button>\\n          </DialogFooter>\\n        </DialogContent>\\n      </Dialog>\\n\\n      {/* Goal Dialog */}\\n      <Dialog open={isGoalDialogOpen} onOpenChange={setIsGoalDialogOpen}>\\n        <DialogContent className=\\"sm:max-w-md\\">\\n          <DialogHeader>\\n            <DialogTitle>\\n              {editingGoal ? \\"Edit Goal\\" : \\"Add New Goal\\"}\\n            </DialogTitle>\\n            <DialogDescription>\\n              {editingGoal\\n                ? \\"Update your goal details.\\"\\n                : \\"Set a new goal to work toward this week.\\"}\\n            </DialogDescription>\\n          </DialogHeader>\\n          <div className=\\"space-y-4 py-4\\">\\n            <div className=\\"space-y-2\\">\\n              <Label htmlFor=\\"description\\">Goal Description</Label>\\n              <Input\\n                id=\\"description\\"\\n                value={goalForm.description}\\n                onChange={(e) => setGoalForm({ ...goalForm, description: e.target.value })}\\n                placeholder=\\"e.g., Study 5 hours this week\\"\\n              />\\n            </div>\\n            <div className=\\"space-y-2\\">\\n              <Label htmlFor=\\"category\\">Category (optional)</Label>\\n              <Input\\n                id=\\"category\\"\\n                value={goalForm.category}\\n                onChange={(e) => setGoalForm({ ...goalForm, category: e.target.value })}\\n                placeholder=\\"e.g., Study Time, Reading\\"\\n              />\\n            </div>\\n          </div>\\n          <DialogFooter>\\n            <DialogClose asChild>\\n              <Button variant=\\"outline\\">Cancel</Button>\\n            </DialogClose>\\n            <Button onClick={saveGoal} disabled={!goalForm.description}>\\n              {editingGoal ? \\"Save Changes\\" : \\"Add Goal\\"}\\n            </Button>\\n          </DialogFooter>\\n        </DialogContent>\\n      </Dialog>\\n    </div>\\n  );\\n};\\n\\nexport default Page;\\n", "app/layout.tsx": "import type { Metadata } from \\"next\\";\\nimport { Geist, Geist_Mono } from \\"next/font/google\\";\\nimport \\"./globals.css\\";\\nimport { ThemeProvider } from \\"@/components/theme-provider\\";\\n\\nconst geistSans = Geist({\\n  variable: \\"--font-geist-sans\\",\\n  subsets: [\\"latin\\"],\\n});\\n\\nconst geistMono = Geist_Mono({\\n  variable: \\"--font-geist-mono\\",\\n  subsets: [\\"latin\\"],\\n});\\n\\nexport const metadata: Metadata = {\\n  title: \\"Create Next App\\",\\n  description: \\"Generated by create next app\\",\\n};\\n\\nexport default function RootLayout({\\n  children,\\n}: Readonly<{\\n  children: React.ReactNode;\\n}>) {\\n  return (\\n    <html lang=\\"en\\" suppressHydrationWarning>\\n      <body\\n        className={`${geistSans.variable} ${geistMono.variable} antialiased`}\\n      >\\n        <ThemeProvider\\n          attribute=\\"class\\"\\n          defaultTheme=\\"system\\"\\n          enableSystem\\n          disableTransitionOnChange\\n        >\\n          {children}\\n        </ThemeProvider>\\n        <script src=\\"/__albert/element-picker.js\\" data-albert-element-picker></script>\\n</body>\\n    </html>\\n  );\\n}\\n", "components/theme-toggle.tsx": "\\"use client\\"\\n\\nimport * as React from \\"react\\"\\nimport { Moon, Sun } from \\"lucide-react\\"\\nimport { useTheme } from \\"next-themes\\"\\n\\nimport { Button } from \\"@/components/ui/button\\"\\nimport {\\n  DropdownMenu,\\n  DropdownMenuContent,\\n  DropdownMenuItem,\\n  DropdownMenuTrigger,\\n} from \\"@/components/ui/dropdown-menu\\"\\n\\nexport function ThemeToggle() {\\n  const { setTheme } = useTheme()\\n\\n  return (\\n    <DropdownMenu>\\n      <DropdownMenuTrigger asChild>\\n        <Button variant=\\"outline\\" size=\\"icon\\">\\n          <Sun className=\\"h-[1.2rem] w-[1.2rem] rotate-0 scale-100 transition-all dark:-rotate-90 dark:scale-0\\" />\\n          <Moon className=\\"absolute h-[1.2rem] w-[1.2rem] rotate-90 scale-0 transition-all dark:rotate-0 dark:scale-100\\" />\\n          <span className=\\"sr-only\\">Toggle theme</span>\\n        </Button>\\n      </DropdownMenuTrigger>\\n      <DropdownMenuContent align=\\"end\\">\\n        <DropdownMenuItem onClick={() => setTheme(\\"light\\")}>\\n          Light\\n        </DropdownMenuItem>\\n        <DropdownMenuItem onClick={() => setTheme(\\"dark\\")}>\\n          Dark\\n        </DropdownMenuItem>\\n        <DropdownMenuItem onClick={() => setTheme(\\"system\\")}>\\n          System\\n        </DropdownMenuItem>\\n      </DropdownMenuContent>\\n    </DropdownMenu>\\n  )\\n}\\n", "components/theme-provider.tsx": "\\"use client\\"\\n\\nimport * as React from \\"react\\"\\nimport { ThemeProvider as NextThemesProvider } from \\"next-themes\\"\\n\\nexport function ThemeProvider({\\n  children,\\n  ...props\\n}: React.ComponentProps<typeof NextThemesProvider>) {\\n  return <NextThemesProvider {...props}>{children}</NextThemesProvider>\\n}\\n"}	2026-03-15 05:11:05.535	2026-03-15 21:00:59.568	Added light/dark mode toggle to the Study Planner app using next-themes. Created a Theme