erwent a major refurbishment in 2007, updating its storyline and technology.\\",\\n  },\\n  {\\n    year: \\"2017\\",\\n    title: \\"Guardians of the Galaxy Announcement\\",\\n    description: \\"Disney announced a new Guardians of the Galaxy attraction for EPCOT, marking a shift towards more character-driven experiences.\\",\\n  },\\n  {\\n    year: \\"2021\\",\\n    title: \\"Remy's Ratatouille Adventure Opens\\",\\n    description: \\"Remy's Ratatouille Adventure, a new attraction in the France Pavilion, opened in 2021, bringing a beloved Pixar film to life.\\",\\n  },\\n];\\n\\nexport default function EpcotHistoryGuide() {\\n  return (\\n    <div className=\\"min-h-screen bg-gradient-to-br from-slate-50 to-slate-100 dark:from-black dark:to-black\\">\\n      {/* Header */}\\n      <header className=\\"border-b border-slate-200 dark:border-zinc-800 bg-white/80 dark:bg-black backdrop-blur-sm sticky top-0 z-10\\">\\n        <div className=\\"max-w-3xl mx-auto px-4 py-5 flex justify-between items-start\\">\\n          <div>\\n            <h1 className=\\"text-3xl font-bold text-slate-900 dark:text-white\\">\\n              EPCOT Center History\\n            </h1>\\n            <p className=\\"text-slate-600 dark:text-zinc-400 mt-1\\">\\n              Explore the milestones of EPCOT Center\\n            </p>\\n          </div>\\n          <ThemeToggle />\\n        </div>\\n      </header>\\n\\n      {/* Main Content */}\\n      <main className=\\"max-w-3xl mx-auto px-4 py-8\\">\\n        {historicalEvents.map((event) => (\\n          <motion.div\\n            key={event.year}\\n            initial={{ opacity: 0, y: 20 }}\\n            animate={{ opacity: 1, y: 0 }}\\n            transition={{ duration: 0.5 }}\\n          >\\n            <Card className=\\"mb-6 shadow-lg border border-slate-200 dark:border-zinc-800 bg-white dark:bg-zinc-900\\">\\n              <CardHeader>\\n                <CardTitle className=\\"text-lg text-slate-900 dark:text-white\\">\\n                  {event.year} - {event.title}\\n                </CardTitle>\\n              </CardHeader>\\n              <CardContent>\\n                <Dialog>\\n                  <DialogTrigger asChild>\\n                    <Button variant=\\"outline\\" size=\\"lg\\">Learn More</Button>\\n                  </DialogTrigger>\\n                  <DialogContent>\\n                    <h2 className=\\"text-xl font-bold mb-4\\">{event.title}</h2>\\n                    <p>{event.description}</p>\\n                  </DialogContent>\\n                </Dialog>\\n              </CardContent>\\n            </Card>\\n          </motion.div>\\n        ))}\\n      </main>\\n\\n      {/* Footer */}\\n      <footer className=\\"mt-12 text-center text-sm text-slate-500 dark:text-zinc-500\\">\\n        <p>Discover the evolution of EPCOT Center through the years.</p>\\n        <p className=\\"mt-1\\">Built with Next.js & Shadcn UI</p>\\n      </footer>\\n    </div>\\n  );\\n}\\n"}	2026-03-14 05:07:25.545	2026-03-14 05:07:25.545	Reduced the header height by changing the vertical padding from py-6 to py-5, making the header approximately 8-10px less tall.
