 w-16 rounded-full text-2xl border-white/30 bg-white/10 hover:bg-white/20 text-white backdrop-blur-sm\\"\\n            >\\n              <Plus className=\\"h-8 w-8\\" />\\n            </Button>\\n          </div>\\n\\n          {/* Reset Button */}\\n          <Button\\n            onClick={reset}\\n            variant=\\"secondary\\"\\n            size=\\"default\\"\\n            className=\\"mt-4 px-6 py-2 rounded-full bg-white/20 hover:bg-white/30 text-white border border-white/20 backdrop-blur-sm\\"\\n          >\\n            <RotateCcw className=\\"h-4 w-4 mr-2\\" />\\n            Reset\\n          </Button>\\n\\n          {/* Status Indicator */}\\n          <div className=\\"flex items-center gap-2 mt-4\\">\\n            <div\\n              className={`w-3 h-3 rounded-full transition-colors duration-300 ${\\n                count > 0\\n                  ? \\"bg-green-400\\"\\n                  : count < 0\\n                  ? \\"bg-red-400\\"\\n                  : \\"bg-gray-400\\"\\n              }`}\\n            ></div>\\n            <span className=\\"text-white/70 text-sm\\">\\n              {count > 0 ? \\"Positive\\" : count < 0 ? \\"Negative\\" : \\"Zero\\"}\\n            </span>\\n          </div>\\n        </div>\\n      </div>\\n\\n      {/* Footer */}\\n      <p className=\\"text-white/40 text-sm mt-8\\">\\n        Click the buttons to change the count\\n      </p>\\n    </div>\\n  );\\n"}	2026-03-15 01:55:56.709	2026-03-15 01:55:56.709	Created a simple counter application with increment, decrement, and reset functionality. The app features a beautiful gradient background with glassmorphism styling, large counter display, circular control buttons with icons, a status indicator showing positive/negative/zero state, and responsive design for all screen sizes.
